// 星の揺り籠 overlay override（screen map 外・open 中は screen の曲より優先）。overlay は routing-hub
// 内にしか無く、hub を離れると閉じる。
const BGM_STAR_CRADLE_TRACK = 'v6-cradle';

const BGM_CROSSFADE_SECONDS = 1;
// crossfade automation 完了後に旧 source/gain を切断・解放するための猶予（automation 端の取りこぼし回避）。
const BGM_TEARDOWN_DELAY_MS = BGM_CROSSFADE_SECONDS * 1000 + 80;

const bgmController = (() => {
  let audioContext = null;
  // 全曲別 GainNode と destination の間に挿す唯一の master GainNode。BGM on/off・音量はここだけを変え、
  // 再生中の source は再スタートしない。設定適用前の既定は音量1（＝audio 設定の first-run 契約値と同一）。
  let masterGain = null;
  let masterGainValue = 1;
  // 最後に要求された desired track id（context 未 resume でも記録し、unlock 後に最新を開始する）。
  let desiredTrackId = null;
  // current = 確立済みの声、incoming = fade-in 中の声。合計2声を上限に保ち、全曲 preload/cache はしない。
  let currentVoice = null;
  let incomingVoice = null;
  // 非同期 decode の逆転防止。reconcile のたびに増やし、resolve 時に一致する世代だけが再生を触る。
  let decodeGeneration = 0;

  function ensureAudioContext() {
    if (audioContext) return audioContext;
    const AudioContextCtor = window.AudioContext || window.webkitAudioContext;
    if (!AudioContextCtor) throw new Error('BGM: Web Audio API (AudioContext) is unavailable in this runtime');
    audioContext = new AudioContextCtor();
    // The single master gain sits between every per-track voice and the destination; applyAudioSettings changes
    // only its value, so on/off + volume never touch the crossfade / generation / track machinery.
    masterGain = audioContext.createGain();
    masterGain.gain.setValueAtTime(masterGainValue, audioContext.currentTime);
    masterGain.connect(audioContext.destination);
    return audioContext;
  }

  function isContextRunning() {
    return Boolean(audioContext) && audioContext.state === 'running';
  }

  function hardStopVoice(voice) {
    if (!voice) return;
    // Teardown is idempotent by construction (each voice is retired by exactly one generation-guarded path); the
    // stop() guard defends only against an AudioContext-level race, not a behavioural fallback.
    try { voice.sourceNode.stop(); } catch (error) { /* already stopped by the context */ }
    voice.sourceNode.disconnect();
    voice.gainNode.disconnect();
  }

  function rampVoiceGain(voice, targetGain) {
    const now = audioContext.currentTime;
    const gain = voice.gainNode.gain;
    gain.cancelScheduledValues(now);
    gain.setValueAtTime(gain.value, now);
    gain.linearRampToValueAtTime(targetGain, now + BGM_CROSSFADE_SECONDS);
  }

  function startVoice(buffer, trackId) {
    const now = audioContext.currentTime;
    const gainNode = audioContext.createGain();
    gainNode.gain.setValueAtTime(0, now);
    gainNode.gain.linearRampToValueAtTime(1, now + BGM_CROSSFADE_SECONDS);
    const sourceNode = audioContext.createBufferSource();
    sourceNode.buffer = buffer;
    sourceNode.loop = true;
    sourceNode.connect(gainNode);
    gainNode.connect(masterGain); // per-track gain → master gain → destination (on/off + volume live on master)
    sourceNode.start(now);
    return { sourceNode, gainNode, trackId };
  }

  function beginCrossfade(buffer, trackId, generation) {
    // Collapse a still-fading-in incoming from a prior crossfade first, so we never hold more than 2 voices.
    if (incomingVoice) {
      hardStopVoice(currentVoice);
      currentVoice = incomingVoice;
      incomingVoice = null;
    }
    incomingVoice = startVoice(buffer, trackId);
    if (currentVoice) rampVoiceGain(currentVoice, 0);
    setTimeout(() => {
      if (generation !== decodeGeneration) return; // a newer transition owns the voices now
      hardStopVoice(currentVoice);
      currentVoice = incomingVoice;
      incomingVoice = null;
    }, BGM_TEARDOWN_DELAY_MS);
  }

  function fadeToSilence(generation) {
    for (const voice of [currentVoice, incomingVoice]) {
      if (voice) rampVoiceGain(voice, 0);
    }
    setTimeout(() => {
      if (generation !== decodeGeneration) return;
      hardStopVoice(currentVoice);
      hardStopVoice(incomingVoice);
      currentVoice = null;
      incomingVoice = null;
    }, BGM_TEARDOWN_DELAY_MS);
  }

  async function fetchAndDecode(url) {
    const response = await fetch(url);
    if (!response.ok) throw new Error(`BGM: fetch ${url} -> HTTP ${response.status}`);
    const encoded = await response.arrayBuffer();
    return audioContext.decodeAudioData(encoded);
  }

  function reconcile() {
    if (!isContextRunning()) return; // suspended (pre-unlock): desired id is recorded; the unlock gesture retries
    const target = desiredTrackId;
    const playingTarget = incomingVoice ? incomingVoice.trackId : (currentVoice ? currentVoice.trackId : null);
    if (target === playingTarget) return; // already playing / heading there
    const generation = (decodeGeneration += 1);
    if (target === null) {
      fadeToSilence(generation);
      return;
    }
    const url = BGM_TRACK_CATALOG[target];
    fetchAndDecode(url)
      .then((buffer) => {
        if (generation !== decodeGeneration) return; // superseded by a later desired track
        beginCrossfade(buffer, target, generation);
      })
      .catch((error) => {
        if (generation !== decodeGeneration) return;
        // A decode/fetch failure must not drag the old track: drop to silence AND surface the error (no silent fallback).
        console.error(`BGM: failed to load track ${target} (${url})`, error);
        fadeToSilence(generation);
      });
  }

  function setDesiredTrack(trackId) {
    if (trackId !== null && !Object.hasOwn(BGM_TRACK_CATALOG, trackId)) {
      throw new Error(`BGM: unknown track id ${trackId}`);
    }
    if (trackId === desiredTrackId) return; // same desired track: no-op (never restarts the current track)
    desiredTrackId = trackId;
    if (trackId !== null) ensureAudioContext(); // create (possibly suspended) so the unlock gesture can resume it
    reconcile();
  }

  // Apply persisted audio settings (BGM on/off + master volume) to the master gain only. The settings API is the
  // strict source of the validated shape; a malformed shape here is a contract violation and fail-fasts rather
  // than being papered over. master gain = bgm_enabled ? bgm_volume : 0. The playing source is never restarted.
  function applyAudioSettings({ bgm_enabled, bgm_volume } = {}) {
    if (typeof bgm_enabled !== 'boolean') {
      throw new Error(`BGM: applyAudioSettings bgm_enabled must be a boolean, got ${bgm_enabled}`);
    }
    if (typeof bgm_volume !== 'number' || !Number.isFinite(bgm_volume) || bgm_volume < 0 || bgm_volume > 1) {
      throw new Error(`BGM: applyAudioSettings bgm_volume must be a number within 0..1, got ${bgm_volume}`);
    }
    masterGainValue = bgm_enabled ? bgm_volume : 0;
    if (masterGain) {
      const now = audioContext.currentTime;
      masterGain.gain.cancelScheduledValues(now);
      masterGain.gain.setValueAtTime(masterGainValue, now);
    }
  }

  // autoplay unlock: until the context is running, playback is deferred and only the desired id is recorded. The
  // first document user gesture resumes the context and starts the latest desired track. Electron's default
  // no-user-gesture-required policy makes the context 'running' from creation, so it plays from the first screen.
  function installAutoplayUnlock() {
    const unlock = () => {
      ensureAudioContext().resume()
        .then(reconcile)
        .catch((error) => console.error('BGM: autoplay unlock resume failed', error));
    };
    document.addEventListener('click', unlock, { once: true });
    document.addEventListener('pointerdown', unlock, { once: true });
  }

  installAutoplayUnlock();

  return { setDesiredTrack, applyAudioSettings };
})();

// The screen whose section currently carries the active class (the single source of truth showScreen just set).
function currentActiveScreenName() {
  for (const [screenName, element] of Object.entries(screens)) {
    if (element.classList.contains('active')) return screenName;
  }
  return null;
}

// Recompute the desired BGM track from the current UI state (active screen + 星の揺り籠 overlay open) and hand it
// to the controller. The overlay is a hub-only override that wins over the screen's own track. A known screen with
// no mapped track resolves to null → silence (distinct from an unknown screen, which showScreen rejects on entry).
function syncBgmForUiState() {
  let target = null;
  if (isRoutingHubStarCradleOpen()) {
    target = BGM_STAR_CRADLE_TRACK;
  } else {
    const screenName = currentActiveScreenName();
    if (screenName !== null && Object.hasOwn(BGM_SCREEN_TRACKS, screenName)) {
      target = BGM_SCREEN_TRACKS[screenName];
    }
  }
  bgmController.setDesiredTrack(target);
}

// Read the persisted audio settings once at boot and apply them to the controller, so the stored BGM on/off +
// volume take effect without opening the settings screen. A failed boot read drops the master gain to silence
// (bgm_enabled:false) and surfaces the error — the same posture as a decode failure — never keeping the BGM
// sounding at a fabricated default.
async function initAudioSettings() {
  try {
    bgmController.applyAudioSettings(await getJson('/api/settings/audio'));
  } catch (error) {
    bgmController.applyAudioSettings({ bgm_enabled: false, bgm_volume: 0 });
    console.error('BGM: failed to load audio settings at boot; dropping to silence', error);
    reportError(error);
  }
}

