// 舞台ピンのアセット画像。region（学院=①金の星水晶ジュエル / 山林=③魔法陣メダリオン）と
// 関係状態（通常 / バディー / エネミー）で別画像を出し、状態を見た目で判別できるようにする。
const mapPinImageUrls = {
  academy_neutral: '/canonical/map_pins/academy_neutral.png',
  academy_buddy: '/canonical/map_pins/academy_buddy.png',
  academy_enemy: '/canonical/map_pins/academy_enemy.png',
  sanrin_neutral: '/canonical/map_pins/sanrin_neutral.png'
};
// region + 状態 → ピン画像。学院はバディー優先（バディー+エネミー重複時はバディー画像）。
// 山林はバディー/エネミーが付かない neutral のみ。未知の region は fail-fast。
function academyMapPinImageUrl(region, hasBuddy, hasEnemy) {
  if (region === 'sanrin') return mapPinImageUrls.sanrin_neutral;
  if (region === 'academy') {
    if (hasBuddy) return mapPinImageUrls.academy_buddy;
    if (hasEnemy) return mapPinImageUrls.academy_enemy;
    return mapPinImageUrls.academy_neutral;
  }
  throw new Error(`unknown map region for pin image: ${region}`);
}
