// Maps a map-pin registry entry's declarative `coordinatesName` to its real truth-source object, so the pure
// registry stays DOM/JS-binding free while the dev calibration tool (?calibrate=academy-map) reads and exports
// against the actual constant. An entry naming a source that is absent here fail-fasts at build time.
const MAP_PIN_CALIBRATION_COORDINATE_SOURCES = { academyMapStagePinCoordinates, sanrinMapStagePinCoordinates };

const ACADEMY_MAP_REGIONS = [
  {
    id: 'academy',
    label: '学院',
    title: '星灯魔法学院マップ',
    lead: '舞台を選ぶと、そのターンの行き先が決まります。',
    canvasLabel: '星灯魔法学院の俯瞰地図'
  },
  {
    id: 'sanrin',
    label: '山林',
    title: '星灯の山林マップ',
    lead: '山林の舞台を選ぶと行き先が決まります。地域切り替えは無料です。',
    canvasLabel: '星灯の山林の俯瞰地図'
  }
];

function mapLocationRegion(location) {
  return location?.region === 'sanrin' ? 'sanrin' : 'academy';
}

function mapRegionDefinition(region = activeMapRegion) {
  return ACADEMY_MAP_REGIONS.find((entry) => entry.id === region) ?? ACADEMY_MAP_REGIONS[0];
}

function academyMapPointFor(locationIdOrIndex, indexOrTotal, maybeTotal) {
  const locationId = typeof locationIdOrIndex === 'string' ? locationIdOrIndex : null;
  const index = locationId ? indexOrTotal : locationIdOrIndex;
  const total = locationId ? maybeTotal : indexOrTotal;
  if (locationId && activeMapRegion === 'sanrin') {
    const sanrinPoint = sanrinMapStagePinCoordinates[locationId];
    if (sanrinPoint) return sanrinPoint;
  }
  const configuredPoint = locationId ? academyMapStagePinCoordinates[locationId] : null;
  if (configuredPoint) return configuredPoint;
  const columns = 5;
  const row = Math.floor(index / columns);
  const col = index % columns;
  const rows = Math.max(1, Math.ceil(total / columns));
  const x = 12 + col * (76 / Math.max(1, columns - 1));
  const y = 12 + row * (72 / Math.max(1, rows - 1));
  return { x, y };
}

function academyMapLocations() {
  return currentField?.locations ?? [];
}

function isAcademyEventMapLocation(locationOrId) {
  const locationId = typeof locationOrId === 'string' ? locationOrId : locationOrId?.id;
  return ACADEMY_MAP_EVENT_LOCATION_IDS.has(locationId);
}

function academyMapConversationLocations(locations = academyMapLocations()) {
  return locations.filter((location) => !isAcademyEventMapLocation(location));
}

function academyMapShopNode() {
  return {
    id: ACADEMY_MAP_SHOP_NODE_ID,
    display_name: '購買',
    description: '各種霊薬を取り揃えている学院購買部。必要な道具や品物を売買できる。',
    visible_situation: '各種霊薬を取り揃えている学院購買部。必要な道具や品物を売買できる。',
    background_url: ACADEMY_SHOP_BACKGROUND_URL,
    background_source_image_url: ACADEMY_SHOP_BACKGROUND_URL
  };
}

function isAcademyMapShopNode(nodeOrId) {
  const nodeId = typeof nodeOrId === 'string' ? nodeOrId : nodeOrId?.id;
  return nodeId === ACADEMY_MAP_SHOP_NODE_ID;
}

function sanrinMapGatheringNode() {
  return {
    id: SANRIN_MAP_GATHERING_NODE_ID,
    display_name: '採取',
    description: '山林の採取ポイントを巡り、在庫がある限り素材を無料で採取できる。集めた素材は購買で売れる。',
    visible_situation: '山林の採取ポイントを巡り、在庫がある限り素材を無料で採取できる。集めた素材は購買で売れる。',
    background_url: SANRIN_GATHERING_BACKGROUND_URL,
    background_source_image_url: SANRIN_GATHERING_BACKGROUND_URL
  };
}

function isSanrinMapGatheringNode(nodeOrId) {
  const nodeId = typeof nodeOrId === 'string' ? nodeOrId : nodeOrId?.id;
  return nodeId === SANRIN_MAP_GATHERING_NODE_ID;
}

function academyMapRenderableNodes(locations = academyMapLocations()) {
  return [...academyMapConversationLocations(locations), academyMapShopNode()];
}

function academyMapRegionLocations(region = activeMapRegion, locations = academyMapLocations()) {
  return locations.filter((location) => mapLocationRegion(location) === region);
}

function academyMapRegionRenderableNodes(region = activeMapRegion, locations = academyMapLocations()) {
  const regionLocations = academyMapRegionLocations(region, locations);
  // The 購買 special node is academy-only; the 採取 special node is sanrin-only; other regions show only their own 舞台.
  if (region === 'academy') return academyMapRenderableNodes(regionLocations);
  if (region === 'sanrin') return [...academyMapConversationLocations(regionLocations), sanrinMapGatheringNode()];
  return academyMapConversationLocations(regionLocations);
}

function academyMapCurrentAssignmentSignature() {
  return JSON.stringify({
    locations: academyMapLocations().map((location) => ({
      id: location.id,
      variants: [location.visible_situation, ...(location.visible_situation_variants ?? [])].filter(Boolean).length
    })),
    characters: selectableCharacters.map((character) => character.character_id),
    buddy: selectedAcademyBuddyCharacterId(),
    enemies: Array.from(selectedAcademyEnemyCharacterIds()).sort()
  });
}

function academyMapLocationById(locationId) {
  return academyMapLocations().find((location) => location.id === locationId) ?? currentField?.current_location ?? null;
}

function shuffledAcademyCharacters() {
  const pool = [...selectableCharacters];
  for (let index = pool.length - 1; index > 0; index -= 1) {
    const swapIndex = Math.floor(Math.random() * (index + 1));
    [pool[index], pool[swapIndex]] = [pool[swapIndex], pool[index]];
  }
  return pool;
}

function selectedAcademyStageSituation(locationOrId) {
  const location = typeof locationOrId === 'string' ? academyMapLocationById(locationOrId) : locationOrId;
  if (!location) return '';
  // Stage descriptions come straight from the server-evaluated field (academyMapLocations() ===
  // currentField.locations). The backend is the single truth source: evaluateLocationsForState resolves
  // each stage's visible_situation from the persisted truth — the current stage carries
  // current_location_visible_situation, every other academy stage carries its per-arrival
  // academy_stage_situations selection (rerolled server-side on each routing academy-map arrival), and an
  // unselected stage shows its authored default. The map reads that already-resolved value live at render
  // time — there is no client-side situation store, no client-side precedence, and no client-side default
  // fallback that could shadow the truth or freeze it at a session-start value.
  return location.visible_situation ?? '';
}

function withSelectedAcademyStageSituation(location) {
  if (!location) return location;
  return { ...location, visible_situation: selectedAcademyStageSituation(location) };
}

function academyMapNodeDescription(location) {
  if (!location) return '舞台の説明文はまだありません。';
  if (isAcademyMapShopNode(location)) {
    return location.description || location.visible_situation || '学院購買部です。必要な道具や品物を確認できます。';
  }
  if (isSanrinMapGatheringNode(location)) {
    return location.description || location.visible_situation || '山林の採取ポイントで素材を集められます。';
  }
  return selectedAcademyStageSituation(location) || location.description || '舞台の説明文はまだありません。';
}

function rerollAcademyMapCharacterAssignments() {
  const locations = academyMapLocations();
  academyMapAssignmentSignature = academyMapCurrentAssignmentSignature();
  if (!locations.length || !selectableCharacters.length) {
    academyMapCharacterAssignments = {};
    renderAcademyMap(currentField);
    return;
  }
  const shuffled = shuffledAcademyCharacters();
  const locationBuckets = Object.fromEntries(locations.map((location) => [location.id, []]));
  // Academy characters live in the academy; never scatter them onto山林 (or other) region stages.
  const shuffledLocations = academyMapConversationLocations(locations)
    .filter((location) => mapLocationRegion(location) === 'academy')
    .sort(() => Math.random() - 0.5);
  shuffled.forEach((character, index) => {
    const location = shuffledLocations[index % shuffledLocations.length];
    if (location) locationBuckets[location.id].push(character.character_id);
  });
  academyMapCharacterAssignments = locationBuckets;
  renderAcademyMap(currentField);
}

function ensureAcademyMapCharacterAssignments({ force = false } = {}) {
  if (force || !Object.keys(academyMapCharacterAssignments).length) {
    rerollAcademyMapCharacterAssignments();
  } else {
    renderAcademyMap(currentField);
  }
}

function assignedAcademyMapCharactersFor(locationId) {
  const assignedIds = academyMapCharacterAssignments[locationId] ?? [];
  return assignedIds
    .map((characterId) => selectableCharacters.find((character) => character.character_id === characterId))
    .filter(Boolean);
}

// その舞台に「いまいる会える相手」を返す唯一の機構。学院ステージは配置された学院キャラ、
// 山林ステージは出現中のクリーチャーで、どちらも display_name を持つ候補に正規化される。
// マップの hover ポップアップと会話相手選択画面が同じこの関数を共有する（マップ別実装を作らない）。
// location が無効なら location.id 参照で即座に throw する（空配列で握り潰さない）。
// region は mapLocationRegion による academy/sanrin の二値全域 partition（academy は sanrin の補集合）。
// canonical 37 ロケーションは全て有効 region を持ち、購買・採取の合成ノードが region を持たないのは
// 「academy 扱い」を意図した in-spec のノード形状なので、ここの academy 分岐は silent fallback ではない。
// （garbage region を生む到達経路は実在しない。throw 化は両特殊ピンの in-spec hover を壊す regression。）
function stageOccupantsFor(location) {
  return mapLocationRegion(location) === 'sanrin'
    ? sanrinCreatureCandidatesFor(location.id)
    : assignedAcademyMapCharactersFor(location.id);
}

function selectedAcademyBuddyCharacterId() {
  const explicit = String(currentRuntimeState?.current_buddy_character_id ?? '').trim();
  if (explicit) return explicit;
  return selectableCharacters.find((character) => character.is_buddy === true)?.character_id ?? null;
}

function selectedAcademyEnemyCharacterIds() {
  const explicit = Array.isArray(currentRuntimeState?.current_enemy_character_ids)
    ? currentRuntimeState.current_enemy_character_ids.map((id) => String(id ?? '').trim()).filter(Boolean)
    : [];
  if (explicit.length > 0) return new Set(explicit);
  return new Set(selectableCharacters.filter((character) => character.is_enemy === true)
    .map((character) => character.character_id));
}

// ── Buddy info-drawer truth source (GET /api/relationships/buddy) ──────────────
// The three 昼スタイル drawers' buddy category (routing hub / conversation-day / academy-map) resolve the current
// buddy from the backend endpoint, not the selectable-roster selector, so a homunculus buddy (an active 錬成室 child,
// absent from the selectable roster) shows instead of throwing as a dangling id. The endpoint is the single truth
// source: buddy null is the legitimate empty state; a present-but-unresolvable buddy id is a 500 there (corrupt
// state, never a silent null). Each buddy category is async (loading card immediately → fetch → stale-token guard),
// the same discipline as diary / inventory 装備欄 / 収蔵庫. A fetch failure / malformed payload surfaces through
// reportError (never a silent empty render).
async function fetchBuddyView() {
  const response = await fetch(BUDDY_VIEW_REQUEST_PATH);
  if (!response.ok) {
    throw new Error(`buddy fetch failed: HTTP ${response.status}`);
  }
  return parseBuddyView(await response.json());
}

// Monotonic guard against a stale buddy fetch overwriting the current drawer body: each (re-)render of a buddy
// category on any surface bumps this token, and a resolved fetch renders only when its captured token is still
// current AND the drawer is still on the buddy category (switching category / re-opening abandons the in-flight
// fetch rather than flashing stale content in).
let buddyViewFetchToken = 0;

// Resolve a validated buddy view to the panel subject: null (legitimate empty), a selectable roster character
// (kind 'character' — a character_id that does not resolve in the roster is corrupt state and throws, never
// collapsed to empty), or the homunculus buddy view (kind 'homunculus' — its display fields come straight from
// the endpoint since a homunculus is not in the selectable roster).
function resolveBuddyPanelSubject(view) {
  if (view.buddy === null) return null;
  const buddy = view.buddy;
  if (buddy.kind === 'character') {
    const roster = selectableCharacters.find((character) => character.character_id === buddy.character_id);
    if (!roster) {
      throw new Error(`buddy view character id ${JSON.stringify(buddy.character_id)} does not resolve in the selectable roster (corrupt relationship state)`);
    }
    return { kind: 'character', characterId: buddy.character_id, roster };
  }
  return { kind: 'homunculus', characterId: buddy.character_id, homunculus: buddy };
}

// The affinity meta chip (好感度 N) a homunculus buddy hero card shows in place of the selectable roster's 学年 /
// クラブ chips (the endpoint carries no school/club for a homunculus — the affinity is the one meta it exposes).
function buddyAffinityChip(affinity, chipClass) {
  const chip = document.createElement('span');
  chip.className = chipClass;
  chip.textContent = `好感度 ${affinity}`;
  return chip;
}

// Shared info-drawer resolution for the enemy category of the three 昼スタイル drawers. The legitimate-empty case (no
// enemy recorded) and a dangling case (a recorded id that does not resolve in the selectable roster) are kept
// distinct: legitimate-empty returns the empty array so the caller paints its scoped 空状態カード; a dangling id is
// broken relationship state and throws (絶対ルール: 空データへの畳み込み・部分表示・skip をしない). Enemy is
// selectable-only (a homunculus can never be an enemy), so this stays roster-resolved.
function resolveInfoDrawerEnemies() {
  const enemyIds = selectedAcademyEnemyCharacterIds();
  if (enemyIds.size === 0) return [];
  for (const enemyId of enemyIds) {
    if (!selectableCharacters.some((character) => character.character_id === enemyId)) {
      throw new Error(`info drawer enemy id ${JSON.stringify(enemyId)} does not resolve in the selectable roster (dangling relationship state)`);
    }
  }
  return selectableCharacters.filter((character) => enemyIds.has(character.character_id));
}

// The diary category (6th info-drawer category) reads a character's saved conversation-derived memories through
// GET /api/diary and renders them as a journal. Both surfaces (routing hub roster-pick, daytime partner-only)
// share this one async fetch: diaryRequestPath / parseDiaryEntries live in the headless-tested diaryViewClient
// module, so the missing-id and broken-response fail-fast paths are unit-tested without a browser. A non-OK
// response is surfaced (never a silent empty diary); parseDiaryEntries returns the entries in the received order
// (the backend owns chronology — the client never re-sorts). Callers route the rejection to reportError, the
// same error surfacing the other categories use.
async function fetchCharacterDiary(characterId) {
  const response = await fetch(diaryRequestPath(characterId));
  if (!response.ok) {
    throw new Error(`diary fetch failed for ${JSON.stringify(characterId)}: HTTP ${response.status}`);
  }
  return parseDiaryEntries(await response.json());
}

// Monotonic guard against a stale diary fetch overwriting the current drawer body: each (re-)render of a diary
// body — the routing hub roster pick, a routing hub character selection, and the daytime partner load — bumps
// this token, and a resolved fetch renders only when its captured token is still current and the drawer is still
// on the diary category. Switching category / re-opening / re-selecting therefore abandons an in-flight fetch
// rather than letting it flash old content in (a silent-wrong render is itself a fallback to avoid).
let diaryFetchToken = 0;

// The same monotonic stale-fetch guard for the routing hub 収蔵庫 (library collection) drawer category: opening or
// re-opening 収蔵庫 bumps this token, and a resolved GET /api/library/collection renders only when its captured
// token is still current AND the drawer is still on the library category (switching away / re-opening abandons the
// in-flight fetch instead of flashing stale entries in).
let libraryCollectionFetchToken = 0;

function stageHasAssignedBuddy(locationId) {
  const buddyCharacterId = selectedAcademyBuddyCharacterId();
  return Boolean(buddyCharacterId) && assignedAcademyMapCharactersFor(locationId).some((character) => character.character_id === buddyCharacterId);
}

function stageHasAssignedEnemy(locationId) {
  const enemyCharacterIds = selectedAcademyEnemyCharacterIds();
  return assignedAcademyMapCharactersFor(locationId).some((character) => enemyCharacterIds.has(character.character_id));
}

function renderAcademyMapHoverOccupants(location) {
  const occupants = document.querySelector('#academy-map-hover-occupants');
  const names = document.querySelector('#academy-map-hover-occupants-names');
  if (!occupants || !names) return;
  const present = stageOccupantsFor(location);
  // 在室 0 人は捏造せず欄ごと隠す（空配列を黙って既定値で埋めない）。
  if (!present.length) {
    occupants.hidden = true;
    names.replaceChildren();
    return;
  }
  const buddyCharacterId = selectedAcademyBuddyCharacterId();
  const enemyCharacterIds = selectedAcademyEnemyCharacterIds();
  occupants.hidden = false;
  names.replaceChildren(...present.map((character) => {
    const chip = document.createElement('span');
    chip.className = 'academy-map-hover-occupant-chip';
    if (character.is_creature) {
      chip.classList.add('is-creature');
    } else {
      // ピンの発光と同じ runtime 由来のバディー/エネミー判定に揃える。
      chip.classList.toggle('is-buddy', character.character_id === buddyCharacterId);
      chip.classList.toggle('is-enemy', enemyCharacterIds.has(character.character_id));
    }
    // 名前は著者データの display_name のみ。欠落を ID で握り潰さない（欠落はそのまま顕在化させる）。
    chip.textContent = character.display_name;
    return chip;
  }));
}

// hover tooltip をピン位置から離す間隔（px）。配置は固定の％閾値ではなく
// popup の実測サイズとキャンバスの実寸から決めるので、この値はピンと popup の
// 隙間だけを意味する。
const MAP_HOVER_TOOLTIP_GAP_PX = 12;

function updateAcademyMapHoverPreview(location, point = null) {
  const tooltip = document.querySelector('#academy-map-hover-tooltip');
  const stage = document.querySelector('#academy-map-hover-stage');
  const description = document.querySelector('#academy-map-hover-description');
  if (!tooltip || !stage || !description) return;
  const active = Boolean(location && point);
  tooltip.classList.toggle('is-visible', active);
  if (!active) return;
  stage.textContent = location.display_name ?? location.id;
  description.textContent = academyMapNodeDescription(location);
  renderAcademyMapHoverOccupants(location);
  // 内容を入れてからサイズ確定後に配置する（実測サイズに同期させるため）。
  positionAcademyMapHoverTooltip(tooltip, point);
}

// ピンの座標(percent)を起点に、popup の実測サイズ(offsetWidth/Height)とキャンバスの
// 実寸を測って、はみ出さない px 位置を計算して配置する。配置ロジック自体は純関数
// computeMapHoverTooltipPlacement に切り出してあり（headless 単体テスト対象）、ここは
// DOM 実測値を渡して結果を style に反映するだけ。旧実装の固定閾値(point.y<18 で下、
// point.x>68 で左)は popup が大きくなると上端・左右で枠外へあふれていた。
function positionAcademyMapHoverTooltip(tooltip, point) {
  const canvas = tooltip.offsetParent;
  if (!canvas) return;
  const { left, top } = computeMapHoverTooltipPlacement({
    canvasWidth: canvas.clientWidth,
    canvasHeight: canvas.clientHeight,
    tooltipWidth: tooltip.offsetWidth,
    tooltipHeight: tooltip.offsetHeight,
    pointXPercent: point.x,
    pointYPercent: point.y,
    gap: MAP_HOVER_TOOLTIP_GAP_PX
  });
  tooltip.style.left = `${left}px`;
  tooltip.style.top = `${top}px`;
}

function renderAcademyMapLocationPreview(location) {
  const title = document.querySelector('#academy-map-location-title');
  const text = document.querySelector('#academy-map-location-text');
  const image = document.querySelector('#academy-map-location-image');
  const goButton = document.querySelector('#academy-map-go-button');
  const displayName = location?.display_name ?? '舞台';
  title.textContent = displayName;
  text.textContent = academyMapNodeDescription(location);
  goButton.textContent = isAcademyMapShopNode(location)
    ? '購買に行く'
    : isSanrinMapGatheringNode(location)
      ? '採取に行く'
      : 'ここに行く';
  image.setAttribute('aria-label', `${displayName}の画像`);
  if (location?.background_url) {
    image.style.backgroundImage = `linear-gradient(180deg, rgba(8,9,10,0.02), rgba(8,9,10,0.72)), url('${location.background_url}')`;
  } else {
    image.style.backgroundImage = '';
  }
}

function openAcademyMapLocationDialog(location) {
  academyMapSelectedLocationId = location?.id ?? null;
  renderAcademyMapLocationPreview(location);
  openInteractionDetailDialog('#academy-map-location-dialog');
}

async function goToAcademyMapLocation() {
  if (!academyMapSelectedLocationId) return;
  if (isAcademyMapShopNode(academyMapSelectedLocationId)) {
    document.querySelector('#academy-map-location-dialog').close();
    showScreen('shop');
    return;
  }
  if (isSanrinMapGatheringNode(academyMapSelectedLocationId)) {
    document.querySelector('#academy-map-location-dialog').close();
    showScreen('gathering');
    return;
  }
  academyCompanionLocationId = academyMapSelectedLocationId;
  document.querySelector('#academy-map-location-dialog').close();
  // A confirmed move lands back on the map screen (no separate companion screen): refresh the
  // server-evaluated field, re-show the map, then open the conversation-partner popup over it. Closing
  // the popup leaves the player on the map with the move already committed (never rolled back).
  await moveToLocation(academyCompanionLocationId, {
    showDetail: false,
    nextScreen: 'academy-map',
    selectedVisibleSituation: selectedAcademyStageSituation(academyCompanionLocationId)
  });
  openAcademyMapCompanionPopup(academyCompanionLocationId);
}

// The academy-map character conversation lands on the daytime conversation screen. Routing is the official
// mode, so there is no legacy landing choice here; the entry takes the chosen id directly.
function startAcademyMapCompanionConversation(characterId) {
  // A missing id means broken popup wiring or malformed candidate data — fail fast rather than a silent
  // no-op (absolute rules: no silent fallback). Every rendered candidate card carries a real character_id.
  if (!characterId) {
    throw new Error(`academy map companion conversation requires a character id, got ${JSON.stringify(characterId)}`);
  }
  closeAcademyMapCompanionPopup();
  startConversationDay(characterId).catch(reportError);
}

// 会話相手選択ポップアップ: 移動確定後、マップ上に昼スタイルで開く。候補はマップ hover と同じ
// stageOccupantsFor（学院ステージ＝配置された学院キャラ、山林ステージ＝出現中クリーチャー）から取り、
// マップ別実装を作らない。顔＋名前のカードを押すと設定分岐どおりの会話が始まる。location が無効なら
// stageOccupantsFor が location.id 参照で即 throw する（空配列で握り潰さない）。
function renderAcademyMapCompanionPopup(locationId = academyCompanionLocationId) {
  const location = academyMapLocationById(locationId);
  const stageEl = document.querySelector('#academy-map-companion-popup-stage');
  const body = document.querySelector('#academy-map-companion-popup-body');
  if (!stageEl || !body) {
    throw new Error('academy map companion popup nodes are missing (broken markup wiring)');
  }
  stageEl.textContent = location?.display_name ?? '舞台';
  const isSanrin = mapLocationRegion(location) === 'sanrin';
  const candidates = stageOccupantsFor(location);
  if (!candidates.length) {
    const empty = document.createElement('p');
    empty.className = 'academy-map-companion-empty';
    empty.textContent = isSanrin
      ? '今この舞台に姿を見せている存在はいません。山林の舞台を巡ると、まれに話せる相手に出会えます。'
      : 'この舞台に会話できる相手はいません。ポップアップを閉じて、ほかの舞台を選べます。';
    body.replaceChildren(empty);
    return;
  }
  body.replaceChildren(...candidates.map((character) => {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'academy-map-companion-card';
    if (character.is_creature) {
      button.classList.add('is-creature');
    } else {
      button.classList.toggle('is-buddy', character.is_buddy === true);
      button.classList.toggle('is-enemy', character.is_enemy === true);
    }
    button.dataset.characterId = character.character_id;
    const image = document.createElement('img');
    image.src = character.selection_icon_url ?? character.face_url ?? sourceSheetImageUrl({ characterId: character.character_id, view: 'face' });
    image.alt = `${character.display_name ?? character.character_id}の顔`;
    if (character.is_creature) hideImageOnError(image);
    const label = document.createElement('span');
    const sublabel = character.is_creature
      ? `${character.kind_label ?? '山林の存在'}・山林で出会った珍しい話し相手`
      : 'この舞台にいる会話候補';
    label.innerHTML = `<strong>${character.display_name ?? character.character_id}</strong><small>${sublabel}</small>`;
    button.replaceChildren(image, label);
    button.addEventListener('click', () => startAcademyMapCompanionConversation(character.character_id));
    return button;
  }));
}

function openAcademyMapCompanionPopup(locationId = academyCompanionLocationId) {
  const popup = document.querySelector('#academy-map-companion-popup');
  if (!popup) {
    throw new Error('academy map companion popup #academy-map-companion-popup is missing (broken markup wiring)');
  }
  renderAcademyMapCompanionPopup(locationId);
  popup.hidden = false;
}

function closeAcademyMapCompanionPopup() {
  const popup = document.querySelector('#academy-map-companion-popup');
  if (popup) popup.hidden = true;
}

function applyAcademyMapRegionChrome(region = activeMapRegion) {
  const definition = mapRegionDefinition(region);
  const canvas = document.querySelector('.academy-map-canvas');
  if (canvas) {
    canvas.dataset.mapRegion = definition.id;
    canvas.setAttribute('aria-label', definition.canvasLabel);
  }
  const title = document.querySelector('#academy-map-title');
  if (title) title.textContent = definition.title;
  const lead = document.querySelector('#academy-map-lead');
  if (lead) lead.textContent = definition.lead;
  for (const button of document.querySelectorAll('.academy-map-region-button')) {
    const isActive = button.dataset.mapRegion === definition.id;
    button.classList.toggle('is-active', isActive);
    button.setAttribute('aria-pressed', isActive ? 'true' : 'false');
  }
}

function setActiveMapRegion(region) {
  const nextRegion = mapRegionDefinition(region).id;
  if (nextRegion === activeMapRegion) return;
  // Switching the viewed region is free — it is not a move and never costs a turn.
  activeMapRegion = nextRegion;
  academyMapSelectedLocationId = null;
  applyAcademyMapRegionChrome(nextRegion);
  const canvas = document.querySelector('.academy-map-canvas');
  if (canvas) {
    canvas.classList.add('is-region-switching');
    if (academyMapRegionSwitchTimer) clearTimeout(academyMapRegionSwitchTimer);
    academyMapRegionSwitchTimer = setTimeout(() => {
      canvas.classList.remove('is-region-switching');
      academyMapRegionSwitchTimer = null;
    }, ACADEMY_MAP_REGION_SWITCH_FLOURISH_MS);
  }
  renderAcademyMap(currentField);
}

function renderAcademyMap(field) {
  const layer = document.querySelector('#academy-map-stage-layer');
  if (!layer) return;
  const region = activeMapRegion;
  applyAcademyMapRegionChrome(region);
  const mapLocations = academyMapRegionRenderableNodes(region, field?.locations ?? []);
  updateAcademyMapHoverPreview(null);
  layer.replaceChildren(...mapLocations.map((candidate, index) => {
    const point = academyMapPointFor(candidate.id, index, mapLocations.length);
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'academy-map-node';
    const hasBuddy = stageHasAssignedBuddy(candidate.id);
    const hasEnemy = stageHasAssignedEnemy(candidate.id);
    button.classList.toggle('has-buddy', hasBuddy);
    button.classList.toggle('has-enemy', hasEnemy);
    button.style.backgroundImage = `url('${academyMapPinImageUrl(region, hasBuddy, hasEnemy)}')`;
    button.style.left = `${point.x}%`;
    button.style.top = `${point.y}%`;
    button.setAttribute('aria-label', `${candidate.display_name ?? candidate.id}を確認`);

    button.addEventListener('mouseenter', () => updateAcademyMapHoverPreview(candidate, point));
    button.addEventListener('focus', () => updateAcademyMapHoverPreview(candidate, point));
    button.addEventListener('mouseleave', () => updateAcademyMapHoverPreview(null));
    button.addEventListener('blur', () => updateAcademyMapHoverPreview(null));
    button.addEventListener('click', () => {
      openAcademyMapLocationDialog(candidate);
    });
    return button;
  }));
}

// ── 学院マップ「昼」層: 週グリフ・到着着地・左カテゴリ rail→情報ポップアップ ─────────────────────────
// マップ画面はハブ（形而上の月夜）と対の昼版として、上部に週グリフ、左に5カテゴリ rail→情報ドロワーを持つ。
// ドロワーの情報面はハブ/昼会話と同じ（self=共有 renderPlayerParametersInto、buddy/enemy/inventory/money は
// ハブ相当のデータ選択を共有）だが、表示はマップ専用の --am-* 昼トークン層に紐づく .academy-map-info-* で塗る
// （昼会話が --cd-night-* に紐づく別実装を持つのと同じ presentation 分離）。固定集合外カテゴリ・データ欠落の
// fail-fast はハブと同型（silent fallback / default 値 fallback をしない）。
const ACADEMY_MAP_TOTAL_WEEKS = 50;

const ACADEMY_MAP_INFO_CATEGORY_TITLES = Object.freeze({
  self: '自分',
  buddy: 'バディー',
  enemy: 'エネミー',
  inventory: '持ち物',
  money: 'お金'
});

// 週グリフ（☀ 第N週 / 50）。週の導出はハブ/昼会話と同じ共有ヘルパ conversationStageWeek に従う（非有限/負の
// elapsed_weeks は throw・週1捏造や silent clamp はしない）。マップに到達するのは game 開始後で、
// currentRuntimeState.elapsed_weeks はハブ/昼会話と同じ /api/state 経由で埋まっている。
function renderAcademyMapWeek() {
  // 週グリフ node は刷新後マップの常設要素。欠落は broken markup wiring で、静かな no-op にせず fail-fast する。
  const weekEl = document.querySelector('#academy-map-week');
  if (!weekEl) {
    throw new Error('academy map week glyph node #academy-map-week is missing (broken markup wiring)');
  }
  const week = conversationStageWeek(currentRuntimeState?.elapsed_weeks);
  weekEl.textContent = `第${week}週 / ${ACADEMY_MAP_TOTAL_WEEKS}`;
}

// 到着着地演出: マップ表示のたびに #academy-map-screen へ is-day-arriving を ~600ms 付与して「昼へ明ける」
// （暗→明の opacity/filter）。routing 到着経路（pre-arrival strict refresh→showScreen('academy-map')）も loop の
// 表示も同じ showScreen 経由なので、遷移機構は変えず演出だけ重ねる。prefers-reduced-motion は CSS 側で無効化。
let academyMapDayArrivalTimer = null;
function playAcademyMapDayArrival() {
  // 着地演出は表示中のマップ画面へ付与する。#academy-map-screen 欠落は broken markup で fail-fast する。
  const screen = document.querySelector('#academy-map-screen');
  if (!screen) {
    throw new Error('academy map screen node #academy-map-screen is missing (broken markup wiring)');
  }
  screen.classList.remove('is-day-arriving');
  void screen.offsetWidth; // reflow so re-adding the class restarts the animation
  screen.classList.add('is-day-arriving');
  if (academyMapDayArrivalTimer) clearTimeout(academyMapDayArrivalTimer);
  academyMapDayArrivalTimer = setTimeout(() => {
    screen.classList.remove('is-day-arriving');
    academyMapDayArrivalTimer = null;
  }, 600);
}

function academyMapInfoEmptyCard(title, note) {
  const card = document.createElement('div');
  card.className = 'academy-map-info-empty-card';
  const heading = document.createElement('strong');
  heading.className = 'academy-map-info-empty-title';
  heading.textContent = title;
  const body = document.createElement('p');
  body.className = 'academy-map-info-empty-note';
  body.textContent = note;
  card.append(heading, body);
  return card;
}

function academyMapInfoSummary(countText, labelText) {
  const summary = document.createElement('div');
  summary.className = 'academy-map-info-summary';
  const count = document.createElement('strong');
  count.className = 'academy-map-info-summary-count';
  count.textContent = countText;
  const label = document.createElement('span');
  label.className = 'academy-map-info-summary-label';
  label.textContent = labelText;
  summary.append(count, label);
  return summary;
}

function academyMapInfoMetaChips(character) {
  const row = document.createElement('div');
  row.className = 'academy-map-info-chip-row';
  for (const value of [character.school_year, character.club]) {
    if (!value) continue;
    const chip = document.createElement('span');
    chip.className = 'academy-map-info-chip';
    chip.textContent = value;
    row.append(chip);
  }
  return row;
}

// enemy / inventory / money は routing hub と同じデータ選択（selectedAcademyEnemyCharacterIds / currentInventory /
// moneyText）を共有し、顔 URL も共有の conversationDayRosterFaceUrl（純データ）を使う。buddy は下記のとおり
// GET /api/relationships/buddy 真実源へ非同期化した（selectedAcademyBuddyCharacterId は pin/hover/debug 専用に残る）。
// 表示クラスだけがマップ専用。
// The buddy category is async against the GET /api/relationships/buddy truth source (loading card immediately →
// fetch → stale-token + still-on-buddy guard), so a homunculus buddy renders instead of throwing as a dangling
// roster id. routing hub / 昼会話 (loadRoutingHubBuddyInto / loadConversationDayBuddyInto) は同型。
function renderAcademyMapBuddyInfo(bodyEl) {
  loadAcademyMapBuddyInfo(bodyEl).catch(reportError);
}

async function loadAcademyMapBuddyInfo(bodyEl) {
  const token = (buddyViewFetchToken += 1);
  bodyEl.replaceChildren(academyMapInfoLoadingCard('バディーを読み込んでいます…'));
  const view = await fetchBuddyView();
  if (token !== buddyViewFetchToken) return;
  const popup = document.querySelector('#academy-map-info-popup');
  if (!popup || popup.dataset.category !== 'buddy') return;
  // No buddy → the legitimate empty-state card; a corrupt buddy id throws upstream (resolveBuddyPanelSubject).
  const subject = resolveBuddyPanelSubject(view);
  if (!subject) {
    bodyEl.replaceChildren(academyMapInfoEmptyCard('バディー記録なし', 'バディーはいません。'));
    return;
  }
  bodyEl.replaceChildren(academyMapBuddyHeroCard(subject));
}

// The buddy hero card: a homunculus shows its endpoint face_url / display_name + a 好感度 affinity chip (no roster
// meta), a selectable character shows its roster face / name + 学年・クラブ chips (現行同等). Map-scoped classes only.
function academyMapBuddyHeroCard(subject) {
  const card = document.createElement('div');
  card.className = 'academy-map-info-buddy-card';
  const portrait = document.createElement('img');
  portrait.className = 'academy-map-info-portrait';
  const body = document.createElement('div');
  body.className = 'academy-map-info-buddy-body';
  const name = document.createElement('strong');
  name.className = 'academy-map-info-buddy-name';
  if (subject.kind === 'homunculus') {
    const buddy = subject.homunculus;
    portrait.src = buddy.face_url;
    portrait.alt = `${buddy.display_name}の顔`;
    name.textContent = buddy.display_name;
    const chips = document.createElement('div');
    chips.className = 'academy-map-info-chip-row';
    chips.append(buddyAffinityChip(buddy.affinity, 'academy-map-info-chip'));
    body.append(name, chips);
  } else {
    const buddy = subject.roster;
    portrait.src = conversationDayRosterFaceUrl(buddy);
    portrait.alt = `${buddy.display_name ?? buddy.character_id}の顔`;
    name.textContent = buddy.display_name ?? buddy.character_id;
    body.append(name);
    const chips = academyMapInfoMetaChips(buddy);
    if (chips.childElementCount > 0) body.append(chips);
  }
  card.append(portrait, body);
  return card;
}

// The buddy category's loading card (mirrors the diary loading card discipline — a placeholder shown immediately
// before the async fetch resolves).
function academyMapInfoLoadingCard(text) {
  const card = document.createElement('div');
  card.className = 'academy-map-info-loading';
  card.textContent = text;
  return card;
}

function academyMapInfoRosterCard(character) {
  const card = document.createElement('div');
  card.className = 'academy-map-info-roster-card';
  const image = document.createElement('img');
  image.className = 'academy-map-info-roster-face';
  image.src = conversationDayRosterFaceUrl(character);
  image.alt = `${character.display_name ?? character.character_id}の顔`;
  const body = document.createElement('div');
  body.className = 'academy-map-info-roster-body';
  const name = document.createElement('strong');
  name.className = 'academy-map-info-roster-name';
  name.textContent = character.display_name ?? character.character_id;
  const meta = document.createElement('small');
  meta.className = 'academy-map-info-roster-meta';
  meta.textContent = [character.school_year, character.club].filter(Boolean).join(' / ') || character.character_id;
  body.append(name, meta);
  card.append(image, body);
  return card;
}

function renderAcademyMapEnemiesInfo(bodyEl) {
  // エネミー解決は routing hub / 昼会話 (renderRoutingHubEnemiesInto / renderConversationDayEnemiesInto) と同型:
  // 記録0件は正当な空カード、記録済みだが解決できない dangling id は throw（resolveInfoDrawerEnemies が弁別）。
  const enemies = resolveInfoDrawerEnemies();
  if (!enemies.length) {
    bodyEl.append(academyMapInfoEmptyCard('エネミー記録なし', '対立関係のキャラクターはいません。'));
    return;
  }
  bodyEl.append(academyMapInfoSummary(`${enemies.length}件`, 'エネミー'));
  const list = document.createElement('div');
  list.className = 'academy-map-info-roster-list';
  list.append(...enemies.map((enemy) => academyMapInfoRosterCard(enemy)));
  bodyEl.append(list);
}

function renderAcademyMapInventoryInfo(bodyEl) {
  // 有効な inventory は items 配列を持つ。空配列は正当な「持ち物なし」だが、items 欠落/非配列は broken state で
  // 空扱いにせず surface する（silent fallback をしない）。
  const items = currentInventory?.items;
  if (!Array.isArray(items)) {
    throw new Error(`academy map inventory requires currentInventory.items array, got ${JSON.stringify(items)}`);
  }
  if (items.length === 0) {
    bodyEl.append(academyMapInfoEmptyCard('持ち物なし', '所持しているアイテムはありません。'));
    return;
  }
  bodyEl.append(academyMapInfoSummary(`${items.length}種類`, '持ち物'));
  const list = document.createElement('ul');
  list.className = 'academy-map-info-ledger';
  for (const item of items) {
    if (typeof item.name !== 'string' || item.name === '') {
      throw new Error(`academy map inventory item requires a non-empty name, got ${JSON.stringify(item)}`);
    }
    if (typeof item.quantity !== 'number' || !Number.isFinite(item.quantity)) {
      throw new Error(`academy map inventory item requires a numeric quantity, got ${JSON.stringify(item)}`);
    }
    if (typeof item.description !== 'string') {
      throw new Error(`academy map inventory item requires a description string, got ${JSON.stringify(item)}`);
    }
    const row = document.createElement('li');
    row.className = 'academy-map-info-ledger-row';
    const head = document.createElement('div');
    head.className = 'academy-map-info-ledger-head';
    const name = document.createElement('strong');
    name.textContent = item.name;
    const quantity = document.createElement('span');
    quantity.className = 'academy-map-info-ledger-quantity';
    quantity.textContent = `×${item.quantity.toLocaleString('ja-JP')}`;
    head.append(name, quantity);
    row.append(head);
    const materialMeta = buildInventoryMaterialMeta(item, 'academy-map-info-ledger-materia');
    if (materialMeta) row.append(materialMeta);
    if (item.description.trim() !== '') {
      const desc = document.createElement('p');
      desc.className = 'academy-map-info-ledger-desc';
      desc.textContent = item.description;
      row.append(desc);
    }
    list.append(row);
  }
  bodyEl.append(list);
}

function renderAcademyMapMoneyInfo(bodyEl, money) {
  const card = document.createElement('div');
  card.className = 'academy-map-info-money-card';
  const value = document.createElement('strong');
  value.className = 'academy-map-info-money-value';
  value.textContent = moneyText(money);
  const label = document.createElement('span');
  label.className = 'academy-map-info-money-label';
  label.textContent = '購買で使える資金';
  card.append(value, label);
  bodyEl.append(card);
}

const academyMapInfoCategoryRenderers = {
  // self はハブ/訓練/自室と同じ共有 renderPlayerParametersInto を検証済みパラメータ源で使う。マップ専用の昼
  // スキンはドロワー側 CSS が与える（第2 renderer を作らない）。player_parameters 欠落は broken state で fail fast。
  self: () => {
    const parameters = currentWorld?.player_parameters;
    if (!parameters || typeof parameters !== 'object') {
      throw new Error(`academy map self info requires currentWorld.player_parameters, got ${JSON.stringify(parameters)}`);
    }
    renderPlayerParametersInto(parameters, '#academy-map-info-popup-body');
  },
  buddy: (bodyEl) => renderAcademyMapBuddyInfo(bodyEl),
  enemy: (bodyEl) => renderAcademyMapEnemiesInfo(bodyEl),
  inventory: (bodyEl) => renderAcademyMapInventoryInfo(bodyEl),
  // money の唯一のデータ源は currentInventory.money（呼び出し側で検証・default 値 fallback をしない）。
  money: (bodyEl) => {
    if (!currentInventory || typeof currentInventory.money === 'undefined') {
      throw new Error(`academy map money info requires currentInventory.money, got ${JSON.stringify(currentInventory?.money)}`);
    }
    renderAcademyMapMoneyInfo(bodyEl, currentInventory.money);
  }
};

// ちょうど1つのカテゴリボタンがドロワー開中に selected を持ち、close 時（category=null）に全解除する。
function setActiveAcademyMapCategory(category) {
  for (const button of document.querySelectorAll('.academy-map-category-button')) {
    const isActive = button.dataset.amCategory === category;
    button.classList.toggle('is-active', isActive);
    button.setAttribute('aria-pressed', isActive ? 'true' : 'false');
  }
}

// 消費者のカテゴリ別 renderer に委譲。本体を空にしてから render。固定集合外カテゴリは contract 破れで throw
// （空ポップアップにしない・openInfo の title 検証と同型）。
function renderAcademyMapInfoCategory(category, bodyEl) {
  bodyEl.replaceChildren();
  const renderer = academyMapInfoCategoryRenderers[category];
  if (!renderer) {
    throw new Error(`unknown academy map info category: ${JSON.stringify(category)}`);
  }
  renderer(bodyEl);
}

// Open は無条件（既開でもカテゴリ切替として本体/ヘッダ/アイコン/選択状態を再セット）。固定集合外カテゴリ・
// popup/icon ノード欠落は throw（silent no-op / generic-title fallback をしない）。title 検証は共有ヘルパを使う。
function openAcademyMapInfo(category) {
  const categoryTitle = resolveConversationStageInfoCategoryTitle(category, ACADEMY_MAP_INFO_CATEGORY_TITLES);
  const popup = document.querySelector('#academy-map-info-popup');
  const title = document.querySelector('#academy-map-info-popup-title');
  const bodyEl = document.querySelector('#academy-map-info-popup-body');
  if (!popup || !title || !bodyEl) {
    throw new Error('academy map info popup nodes are missing (broken markup wiring)');
  }
  const icon = document.querySelector('#academy-map-info-popup-icon');
  if (!icon) {
    throw new Error('academy map info popup icon node is missing (broken markup wiring)');
  }
  title.textContent = categoryTitle;
  icon.src = `/canonical/academy_map/icons/${category}.png`;
  renderAcademyMapInfoCategory(category, bodyEl);
  popup.hidden = false;
  popup.dataset.category = category;
  setActiveAcademyMapCategory(category);
}

function closeAcademyMapInfo() {
  const popup = document.querySelector('#academy-map-info-popup');
  if (popup) popup.hidden = true;
  setActiveAcademyMapCategory(null);
}

// Field INTERACTION ENTRY second box. The field screen is a debug surface (production
// play uses the academy/sanrin maps and the companion screen), so this box lists the
// FULL creature roster (allCreatureCandidates, loaded from /api/creatures) regardless of
// encounter or current location — a debug convenience. Each entry renders only from its
// validated, backend-driven candidate shape (no client-side default values) and starts a
// conversation through the same field pipeline the academy roster uses
// (startAcademyConversationSessionFromCompanion -> /api/interaction/start -> conversation session
// screen); creatures carry no authoring/continuity surfaces, so there is no intermediate edit dialog.
// Production surfaces (academy/sanrin maps, companion screen) are unaffected: they keep
// using the encounter-scoped sanrinCreatureCandidatesFor source, which this does not touch.
function renderFieldCreatureSelector() {
  const panel = document.querySelector('#field-creature-select-panel');
  const list = document.querySelector('#creature-selection-list');
  if (!panel || !list) return;
  panel.hidden = allCreatureCandidates.length === 0;
  list.replaceChildren(...allCreatureCandidates.map((creature) => {
    const cell = document.createElement('div');
    cell.className = 'character-option-cell';
    cell.dataset.characterId = creature.character_id;

    const button = document.createElement('button');
    button.type = 'button';
    button.className = creature.character_id === activeCharacterId ? 'selected character-option is-creature' : 'character-option is-creature';
    button.dataset.characterId = creature.character_id;
    // Render only from the validated creature candidate shape — no client-side
    // alternate/default display values. creatureCandidateFromSummary already fails
    // fast on a malformed summary (and sets selection_icon_url to the validated
    // face_url), so missing data surfaces upstream rather than being masked here.
    const thumb = document.createElement('img');
    thumb.src = creature.selection_icon_url;
    thumb.alt = `${creature.display_name}の顔`;
    hideImageOnError(thumb);
    const label = document.createElement('span');
    label.innerHTML = `<strong>${creature.display_name}</strong><small>${creature.kind_label}</small>`;
    button.append(thumb, label);
    button.addEventListener('click', () => startAcademyConversationSessionFromCompanion(creature.character_id).catch(reportError));

    cell.append(button);
    return cell;
  }));
}

function renderField(field) {
  currentField = field;
  const location = field.current_location ?? field.locations.find((item) => item.id === field.state.current_location_id);
  renderInteractionLocation(location);
  renderFieldLocationDetail(location);
  renderFieldCreatureSelector();
  renderAcademyMap(field);
  const routeList = document.querySelector('#field-route-list');
  routeList.replaceChildren(...field.locations.map((candidate) => {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'location-card';
    button.classList.toggle('current', candidate.id === field.state.current_location_id);
    button.title = candidate.id;

    const label = document.createElement('strong');
    label.textContent = candidate.display_name ?? candidate.id;
    const route = document.createElement('span');
    route.className = 'route_label';
    route.textContent = candidate.id === field.state.current_location_id ? '現在地' : '舞台を切り替える';
    button.replaceChildren(label, route);

    button.addEventListener('click', () => moveToLocation(candidate.id, { showDetail: true }).catch(reportError));
    return button;
  }));
}

function canResumeFromSlotLoad() {
  return slotLoadCanResumePlay && Boolean(currentActiveSlotId) && !activeSlotIncompatible;
}

function updateSlotLoadResumeButton() {
  const resumeButton = document.querySelector('#slot-load-resume-play');
  if (resumeButton) resumeButton.disabled = !canResumeFromSlotLoad();
}

function openDeleteSlotDialog(slotId) {
  const dialog = document.querySelector('#slot-load-delete-confirm-dialog');
  if (!dialog) return;
  pendingDeleteSlotId = slotId;
  document.body.classList.add('interaction-detail-backdrop');
  if (typeof dialog.showModal === 'function') {
    dialog.showModal();
    return;
  }
  dialog.setAttribute('open', '');
  dialog.classList.add('fallback-open');
}

function closeDeleteSlotDialog() {
  const dialog = document.querySelector('#slot-load-delete-confirm-dialog');
  pendingDeleteSlotId = null;
  if (!dialog) return;
  if (typeof dialog.close === 'function' && dialog.open) {
    dialog.close();
    return;
  }
  dialog.removeAttribute('open');
  dialog.classList.remove('fallback-open');
  document.body.classList.remove('interaction-detail-backdrop');
}

async function confirmDeleteSlot() {
  if (!pendingDeleteSlotId) return;
  const slotId = pendingDeleteSlotId;
  closeDeleteSlotDialog();
  await deleteSpecificSlot(slotId);
}

// A normal (compatible) save slot card: a start ("このデータで始める") button, a 削除 button routed through the
// shared delete-confirm dialog, the 卒業済み status line, and the per-slot memo editor.
function renderSlotCard(slot) {
  const article = document.createElement('article');
  article.className = 'continuity-record-item slot-load-item';

  const body = document.createElement('div');
  body.className = 'slot-load-item-body';

  const summary = document.createElement('div');
  summary.className = 'slot-load-item-summary';

  const title = document.createElement('strong');
  title.textContent = slot.label || slot.slot_id;
  const meta = document.createElement('p');
  meta.textContent = [slot.slot_id, slot.updated_at, slot.current_location_id].filter(Boolean).join(' / ');
  const graduationStatus = document.createElement('p');
  graduationStatus.className = 'slot-load-item-status';
  graduationStatus.textContent = '卒業済み';
  graduationStatus.hidden = slot.graduation_completed !== true;
  const actions = document.createElement('div');
  actions.className = 'dialog-action-row';
  const load = document.createElement('button');
  load.type = 'button';
  load.className = 'academy-map-action-button primary';
  load.textContent = 'このデータで始める';
  load.disabled = slot.graduation_completed === true;
  load.setAttribute('aria-disabled', String(slot.graduation_completed === true));
  load.addEventListener('click', () => loadSpecificSlot(slot.slot_id).catch(reportError));
  const remove = document.createElement('button');
  remove.type = 'button';
  remove.className = 'academy-map-action-button secondary';
  remove.textContent = '削除';
  remove.addEventListener('click', () => openDeleteSlotDialog(slot.slot_id));
  actions.append(load, remove);
  summary.append(title, meta, graduationStatus, actions);

  body.append(summary, renderSlotNoteEditor(slot));
  article.append(body);
  return article;
}

// A degraded (incompatible) save slot card: rendered from an entry in response.incompatible_slots
// ({ slot_id, compatibility: { error_code, message }, note, updated_at }). It shows only the safely
// readable metadata plus a fixed player-facing reason (never the server's migration CLI message), and
// offers ONLY the shared delete-confirm dialog — no start button and no note editor, because a degraded
// slot cannot be loaded or its note re-saved (the backend re-throws the same compatibility error on both).
function renderDegradedSlotCard(entry) {
  const article = document.createElement('article');
  article.className = 'continuity-record-item slot-load-item slot-load-item-degraded';

  const body = document.createElement('div');
  body.className = 'slot-load-item-body';

  const summary = document.createElement('div');
  summary.className = 'slot-load-item-summary';

  const title = document.createElement('strong');
  title.textContent = entry.slot_id;
  const meta = document.createElement('p');
  meta.textContent = [entry.slot_id, entry.updated_at, entry.note].filter(Boolean).join(' / ');
  const reason = document.createElement('p');
  reason.className = 'slot-load-item-status slot-load-item-degraded-reason';
  reason.textContent = SLOT_LOAD_DEGRADED_REASON;
  const actions = document.createElement('div');
  actions.className = 'dialog-action-row';
  const remove = document.createElement('button');
  remove.type = 'button';
  remove.className = 'academy-map-action-button secondary';
  remove.textContent = '削除';
  remove.addEventListener('click', () => openDeleteSlotDialog(entry.slot_id));
  actions.append(remove);
  summary.append(title, meta, reason, actions);

  body.append(summary);
  article.append(body);
  return article;
}

async function refreshSaveSlots() {
  const response = await getJson('/api/slots');
  const slots = response.slots ?? [];
  const incompatibleSlots = response.incompatible_slots ?? [];
  currentActiveSlotId = response.active_slot_id ?? null;
  // A degraded active slot reports active_slot_incompatible with the play-mode / phase-2 fields explicitly
  // null. Resolving the route in that state would fail-fast in resolvePlayModeEntryRoute, so branch on the
  // flag: keep the load screen open (the API is 200), null the route/phase-2 contract, and leave resume
  // disabled. A non-degraded active slot keeps resolving the route exactly as before.
  activeSlotIncompatible = response.active_slot_incompatible === true;
  if (activeSlotIncompatible) {
    slotLoadEntryRoute = null;
    slotLoadGraduationPhase2Reentry = null;
    currentPlayMode = null;
  } else {
    slotLoadEntryRoute = resolvePlayModeEntryRoute(response, '/api/slots');
    slotLoadGraduationPhase2Reentry = parseGraduationPhase2Reentry(response, '/api/slots');
    currentPlayMode = slotLoadEntryRoute.mode;
  }
  updateSlotLoadResumeButton();

  const loadButton = document.querySelector('#open-load-screen');
  // The title load button stays enabled while any degraded card remains, so the player can open the load
  // screen to delete an incompatible slot even when no compatible slot is left.
  if (loadButton) loadButton.disabled = slots.length === 0 && incompatibleSlots.length === 0;

  const list = document.querySelector('#slot-load-list');
  if (list) {
    if (!slots.length && !incompatibleSlots.length) {
      const empty = document.createElement('p');
      empty.className = 'continuity-empty';
      empty.textContent = 'まだロードできるセーブデータがありません。';
      list.replaceChildren(empty);
    } else {
      list.replaceChildren(
        ...slots.map((slot) => renderSlotCard(slot)),
        ...incompatibleSlots.map((entry) => renderDegradedSlotCard(entry))
      );
    }
  }

  return { slots, incompatibleSlots };
}

function renderRecordItems(elementId, record) {
  const container = document.querySelector(elementId);
  const items = record.items ?? [];
  if (!items.length) {
    const empty = document.createElement('p');
    empty.className = 'continuity-empty';
    empty.textContent = 'なし';
    container.replaceChildren(empty);
    return;
  }
  container.replaceChildren(...items.map((item) => {
    const article = document.createElement('article');
    article.className = 'continuity-record-item';
    const title = document.createElement('strong');
    title.textContent = item.name ?? item.title ?? item.id ?? 'record';
    const body = document.createElement('p');
    body.textContent = item.text ?? item.description ?? item.body ?? '';
    const meta = document.createElement('small');
    meta.textContent = [item.id, item.work_record_id, item.source_conversation_id].filter(Boolean).join(' / ');
    article.append(title, body, meta);
    return article;
  }));
}

function renderContinuityRecords(status) {
  const records = status.records ?? {};
  renderRecordItems('#character-memory-records', records.memory ?? { items: [] });
  renderRecordItems('#character-skill-records', records.skills ?? { items: [] });
  renderRecordItems('#character-work-records', records.work_records ?? { items: [] });
}

async function refreshRecordStatus() {
  const status = await getJson(`/api/records/status?character_id=${encodeURIComponent(activeCharacterId)}`);
  renderContinuityRecords(status);
}

let currentFlagStatus = { groups: [] };
let currentFlagDetail = null;
let currentEventFlagStatus = { flags: [], pending_events: [] };
let currentEventFlagDetail = null;

function findFlagStatus(flagId) {
  for (const group of currentFlagStatus.groups ?? []) {
    const flag = (group.flags ?? []).find((entry) => entry.id === flagId);
    if (flag) return { flag, group };
  }
  return null;
}

function updateFlagDetailToggle(flag) {
  const button = document.querySelector('#toggle-flag-active');
  button.dataset.flagId = flag.id;
  button.dataset.nextActive = flag.active ? 'false' : 'true';
  button.textContent = flag.active ? 'フラグをオフにする' : 'フラグをオンにする';
}

function updateFlagJudgmentFlowToggle(flag) {
  const button = document.querySelector('#toggle-flag-judgment-flow');
  button.dataset.flagId = flag.id;
  button.dataset.nextEnabled = flag.judgment_flow_enabled === false ? 'true' : 'false';
  button.textContent = flag.judgment_flow_enabled === false ? '判定フローを有効化する' : '判定フローを無効化する';
}

function updateFlagDetailControls(flag) {
  updateFlagDetailToggle(flag);
  updateFlagJudgmentFlowToggle(flag);
}

