  // this event session from inside a still-in-flight originating turn (the routing in-turn academy-map dispatch,
  // arriveAtRoutingAcademyMap); every other caller leaves it false and keeps the single-flight guard.
  await startConversationDayFromPendingEvent(flagId, { loadingAlreadyVisible, allowDuringInFlight });
