// Enter submits, but never while an IME composition is in progress (event.isComposing, the
// tracked composing flag, or the legacy keyCode 229 some IMEs emit) and never with Shift held.
function enterShouldSubmit(event, composing) {
  if (event.key !== 'Enter') return false;
  if (event.shiftKey) return false;
  if (event.isComposing || composing || event.keyCode === 229) return false;
  return true;
}

function shouldSubmitPlayerInput(event) {
  return enterShouldSubmit(event, playerInputIsComposing);
}

const academyConversationSessionInputElement = document.querySelector('#academy-conversation-session-player-input');
for (const inputElement of [academyConversationSessionInputElement]) {
  inputElement.addEventListener('compositionstart', () => {
    playerInputIsComposing = true;
  });
  inputElement.addEventListener('compositionend', () => {
    playerInputIsComposing = false;
  });
  inputElement.addEventListener('keydown', (event) => {
    if (shouldSubmitPlayerInput(event)) {
      event.preventDefault();
      if (conversationRequestInFlight) {
        showProcessingToast();
        return;
      }
      runConversation().catch(reportError);
    }
  });
}
