document.querySelector('#audio-bgm-volume').addEventListener('change', (event) => saveAudioSettings({ bgm_volume: Number(event.target.value) }).catch(reportError));
document.querySelector('#settings-back-to-title').addEventListener('click', () => showScreen('title'));
for (const tab of document.querySelectorAll('.settings-category-tab')) {
  tab.addEventListener('click', () => selectSettingsCategory(tab.dataset.settingsCategory));
}
for (const input of [document.querySelector('#lmstudio-host'), document.querySelector('#lmstudio-port')]) {
  input.addEventListener('input', () => syncLmStudioConnectionModeUi());
  // No save button: a committed host/port edit applies on change (blur, or Enter which blurs).
  input.addEventListener('change', () => saveLmStudioSettings().catch(reportError));
  input.addEventListener('keydown', (event) => {
    if (event.key === 'Enter') {
      event.preventDefault();
      input.blur();
    }
  });
}
for (const radio of [document.querySelector('#lmstudio-connection-mode-localhost'), document.querySelector('#lmstudio-connection-mode-lan')]) {
  radio.addEventListener('change', () => {
    syncLmStudioConnectionModeUi();
    saveLmStudioSettings().catch(reportError);
  });
}
document.querySelector('#lmstudio-model').addEventListener('change', () => saveLmStudioSettings().catch(reportError));
document.querySelector('#lmstudio-thinking-effort').addEventListener('change', () => saveLmStudioSettings().catch(reportError));
document.querySelector('#fetch-lmstudio-models').addEventListener('click', () => fetchLmStudioModels().catch(reportError));
document.querySelector('#slot-load-resume-play').addEventListener('click', () => resumePlayFromSlotLoad().catch(reportError));
document.querySelector('#back-to-title-screen').addEventListener('click', () => showScreen('title'));
document.querySelector('#slot-load-delete-confirm-submit').addEventListener('click', () => confirmDeleteSlot().catch(reportError));
document.querySelector('#slot-load-delete-confirm-cancel').addEventListener('click', () => closeDeleteSlotDialog());
document.querySelector('#delete-character-memory').addEventListener('click', () => deleteCharacterRecords('memory').catch(reportError));
document.querySelector('#delete-character-skills').addEventListener('click', () => deleteCharacterRecords('skills').catch(reportError));
document.querySelector('#delete-character-work-records').addEventListener('click', () => deleteCharacterRecords('work_records').catch(reportError));

// ===== Practical dungeon (実践) =====
let currentDungeonView = null;
let dungeonActionInFlight = false;
// A companion run end defers its finalize -> bank -> clear so the exit returns to the room
// at once; the finalize runs in the background while this flag holds (mirrors the
// conversation post-flow's conversationFinalizationInFlight).
let dungeonFinalizationInFlight = false;
let activeDungeonFinalizationPromise = null;
// Run-scoped companion chat history, stored as display messages (carrying per-message
// expression) so the dungeon sidebar mounts the same streaming chat controller as the
// academy. The enter-time companion opening streams straight into this history during enter.
let dungeonChatMessages = [];
// Persistent map-entity nodes (player / companion / enemy:<uid>) kept across renders so a
// position change animates as a slide. `dungeonBoardSignature` snaps the overlay (no slide)
// when the board itself changes (new run / new floor), since entities did not "move" there.
const dungeonEntityNodes = new Map();
// Each live entity's current logical tile (key -> {x, y}), so a combat effect can find the node at
// an event's from/to tile and originate from where that token is ACTUALLY drawn (mid-slide), not
// its final logical tile.
const dungeonEntityTiles = new Map();
let dungeonBoardSignature = null;
// Consumable-use targeting state: null when idle, else the armed dungeon_consumable plus the input it is
// still collecting — mode 'aim' waits for a board tile (attack_area), mode 'ally' waits for a self/companion
// pick (heal/MP). The auto (attack_single) and revive kinds need no extra input and fire immediately without
// ever entering this state.
let dungeonConsumableTargeting = null;

// Deadzone camera state, in board pixels: the scroll offset whose negation translates
// the board inside the clipping viewport. Persists across renders so the deadzone follow
// has the previous position to scroll from; a new floor centers it and a viewport resize
// reframes it (see layoutDungeonBoard). Cell sizing and camera are recomputed together
// because the visible tile count, the vision-range fit, and the follow margin are one
// coupled layout.
let dungeonCamera = { x: 0, y: 0 };
// The viewport size (px) the camera was last laid out for. A reframe responds to an actual viewport
// resize; when the grid ResizeObserver fires with no net size change (e.g. the settle that fires
// right after a fresh board already centered at its final width), there is nothing to reframe, so
// the camera is left as placed and the entry center is not content-clamped off-centre.
let dungeonViewportSize = { w: 0, h: 0 };
// Tile size is bounded so the map neither shrinks to specks nor blows up past readability; inside the band
// the cell is sized from the viewport alone against a FIXED target cell count (DN_TARGET_CELLS), so the scale
// is content- and vision-independent — constant at one window size. The floor is raised from the old 24px so
// small windows keep icons legible (the player's "小さくて見えない"), and the ceiling lifted from 60px so the
// tiles read as large as the window allows.
const DN_CELL_MIN = 44;
const DN_CELL_MAX = 72;
// The map targets this many cells across its smaller axis, regardless of vision radius (which only drives the
// follow margin now). 8 lands ~62px cells on a representative desktop map column and never rezooms per-run.
const DN_TARGET_CELLS = 8;

const DUNGEON_GLYPHS = { player: '＠', companion: '◇', stairs: '＞', entrance: '＜', wall: '█', floor: '・', item: '＊' };
const DUNGEON_MAGIC_LABELS = { light: '光', dark: '闇', fire: '火', water: '水', earth: '土', wind: '風' };
const DUNGEON_ABILITY_LABELS = { strength: '筋力', agility: '瞬発力', academics: '学力', magical_power: '魔力', charisma: 'カリスマ' };
const DUNGEON_ASSET_BASE = '/canonical/dungeon';
// Faceless protagonist crest (案3): a star/starlight emblem, no portrait. Pure SVG = no asset dependency.
const DUNGEON_CREST_SVG = '<svg viewBox="0 0 24 24" class="dn-crest" aria-hidden="true"><path d="M12 2.2l2.7 6.4 6.9.5-5.3 4.5 1.7 6.7L12 17.1 6 20.8l1.7-6.7L2.4 9.1l6.9-.5z"/></svg>';

function dungeonEnemyIconUrl(archetypeId) {
  return archetypeId ? `${DUNGEON_ASSET_BASE}/enemies/${archetypeId}.png` : null;
}
function dungeonItemIconUrl(kind) {
  return kind ? `${DUNGEON_ASSET_BASE}/items/${kind}.png` : null;
}
function dungeonStairsIconUrl() {
  return `${DUNGEON_ASSET_BASE}/ui/stairs.png`;
}
// Companion face reuses the existing visual_set face image; visual_set_id is resolved
// from the loaded selectable roster by character_id (no engine field needed).
function dungeonCompanionFaceUrl(characterId) {
  const character = (selectableCharacters ?? []).find((entry) => entry.character_id === characterId);
  const visualSetId = character?.visual_set_id;
  return visualSetId ? `/canonical/character_visual_sets/${visualSetId}/face_emotions/neutral.jpg` : null;
}

// The face image for a dungeon companion token — the shared resolution used by both the map ally token and the
// chat header, so both render the SAME face. A homunculus companion (the face_url schema marker) is absent from
// the selectable roster, so the visual_set path cannot resolve it; its face comes from the run view entry-snapshot
// face_url. A selectable companion carries no face_url and resolves its visual_set face from the roster (unchanged).
// Fail-fast: a homunculus companion whose face_url is missing/blank throws rather than degrading to a glyph token —
// the same no-silent-blank discipline as the selectable roster miss (openDungeonCompanionDetail).
function dungeonCompanionTokenFaceUrl(companion) {
  if (!dungeonCompanionIsHomunculus(companion)) return dungeonCompanionFaceUrl(companion.character_id);
  const faceUrl = companion.face_url;
  if (typeof faceUrl !== 'string' || faceUrl === '') {
    throw new Error(`homunculus dungeon companion is missing face_url: ${companion?.name ?? companion?.character_id ?? '(unknown companion)'}`);
  }
  return faceUrl;
}

function dungeonReasonText(reason) {
  if (reason === 'lmstudio_not_configured') return 'LM Studio が未設定のため、単独（機械のみ）で潜ります。';
  if (reason === 'llm_busy') return '直前の会話の後処理が実行中のため、今は単独（機械のみ）で潜ります。';
  return '同行キャラが現れる可能性があります。';
}

async function refreshDungeonScreen() {
  // The companion header renders the companion's parameter bars from the loaded character roster
  // (the same source as the name-click detail). Boot loads the roster before the dungeon is reachable,
  // so this is a no-op in the normal flow; ensuring it here makes the screen self-sufficient so the
  // companion render never depends on call order. A fetch failure throws (fail-fast) — this is an
  // explicit precondition load, not a silent fallback, so renderDungeonChat's miss is a true desync.
  if (!selectableCharacters.length) await refreshCharacters();
  const view = await getJson('/api/dungeon/state');
  if (view && view.pending_finalize) {
    // A run is held awaiting its deferred finalize (reloaded mid-exit, or a prior background
    // finalize failed). Resume it: show the held result, then run the finalize and return to the room.
    const held = dungeonResultFromHeldView(view);
    renderDungeonResult(held);
    await dungeonExitToRoom(held);
    return;
  }
  if (view && view.active) {
    renderDungeonPlay(view);
    return;
  }
  await renderDungeonEntry();
}

async function renderDungeonEntry() {
  currentDungeonView = null;
  dungeonChatMessages = [];
  teardownDungeonConsumableTargeting();
  document.querySelector('#dungeon-play').hidden = true;
  document.querySelector('#dungeon-result-popup').hidden = true;
  document.querySelector('#dungeon-entry').hidden = false;
  closeDungeonPopup();
  closeDungeonRetreatConfirm();
  closeDungeonActorDetail();
  document.querySelector('#dungeon-chat').hidden = true;
  const availabilityNode = document.querySelector('#dungeon-availability');
  try {
    const availability = await getJson('/api/dungeon/availability');
    availabilityNode.textContent = availability.available
      ? '同行キャラが現れることがあります（LLM 利用可）。'
      : dungeonReasonText(availability.reason);
  } catch (error) {
    availabilityNode.textContent = dungeonReasonText(null);
    writeDebugLog({ dungeon_availability_error: error.message });
  }
  // The equipment section fetches its own authoritative snapshot; its failure surfaces on the equipment
  // status line (never a placeholder card) without failing the whole entry render (availability already showed).
  await refreshDungeonEquipment().catch(reportDungeonEquipmentError);
}

// ── Practical-dungeon entry equipment section (#dungeon-entry → #dungeon-equipment) ─────────────────────────
// The dungeon prep screen carries the hero's two equip slots (weapon / amulet) and the run-correction breakdown.
// GET /api/equipment, POST /api/equipment/equip { slot, instance_id }, and POST /api/equipment/unequip { slot }
// ALL return the SAME authoritative snapshot { slots:{weapon,amulet}, instances:[...], run_equipment }, so the
// response is the single source of truth: the client re-renders from the returned snapshot and never optimistically
// mutates a slot before the server confirms. The equipment vocabulary (kinds / weapon types / qualities / elements
// / effect keys and their closed-set labels) is imported from workshopArrivalClient.js (which mirrors
// app/src/equipment.mjs) — there is NO second label map or private translation here. Equipment changed at entry is
// folded into the run at enter time (C-23 entry snapshot); a change mid-run does not affect the in-progress run, so
// this surface adds no run-time gate — it is simply not shown while a run is active (the entry surface is hidden).
// The snapshot is validated fail-fast (malformed slots / instances / run_equipment throw — no silent skip); an API
// failure (400/409 etc.) surfaces on the equipment status line.

// Single-flight guard so a double click never fires two equip/unequip POSTs (each would rewrite the slot).
let dungeonEquipmentInFlight = false;

// The equip owner the entry surface currently shows/edits: 'player' (hero) or the buddy's character_id. The GET
// /api/equipment snapshot carries BOTH the player fields and the buddy sub-view, so a tab switch re-renders the
// cached snapshot without a refetch; equip/unequip re-render from the POST response and keep the selected owner.
// A fresh entry render resets to 'player'; a snapshot whose buddy is gone/changed falls the selection back to the
// hero (the buddy is a real run companion — a stale target is never silently equipped).
let dungeonEquipmentTarget = 'player';
let dungeonLastEquipmentSnapshot = null;

// The equipment status line is the error surface: a failed snapshot fetch / equip / unequip shows here instead of
// leaving placeholder cards (no silent fallback). The line ships in the entry markup, so a missing node is broken
// wiring — throw rather than silently suppressing the surface equipment failures must appear on.
function setDungeonEquipmentStatus(message, { tone = null } = {}) {
  const status = document.querySelector('#dungeon-equipment-status');
  if (!status) {
    throw new Error('dungeon equipment status line (#dungeon-equipment-status) is missing (broken markup wiring)');
  }
  const text = String(message ?? '').trim();
  if (!text) {
    status.hidden = true;
    status.textContent = '';
    delete status.dataset.tone;
    return;
  }
  status.hidden = false;
  status.textContent = text;
  if (tone) status.dataset.tone = tone;
  else delete status.dataset.tone;
}

function reportDungeonEquipmentError(error) {
  if (handleRuntimeApiError(error, { allowSettingsRedirect: true })) return;
  setDungeonEquipmentStatus(errorDisplayMessage(error), { tone: 'error' });
  console.error(error);
}

function clearDungeonEquipment() {
  document.querySelector('#dungeon-equipment-targets').replaceChildren();
  document.querySelector('#dungeon-equipment-slots').replaceChildren();
  document.querySelector('#dungeon-equipment-run').replaceChildren();
}

// Fetch this save's equipment snapshot and render the target tabs + the two slots + the run-correction breakdown.
// A fresh entry render starts on the hero tab. Fail closed: the prior cards are cleared BEFORE the fetch so a
// failed / malformed refetch leaves NO stale, still-clickable cards.
async function refreshDungeonEquipment() {
  setDungeonEquipmentStatus('');
  clearDungeonEquipment();
  dungeonEquipmentTarget = 'player';
  const snapshot = await getJson('/api/equipment');
  renderDungeonEquipment(snapshot);
}

// Validate one equipment instance against the shared closed-set vocabulary, returning the instance plus its
// ordered base / bonus effect entries (workshopEffectEntries throws on an unknown effect key or a non-positive
// value — the same headless-tested guard the workshop uses). base / bonus are validated with allowEmpty because the
// equipment instance-shape contract structurally permits an empty effect object (rendered as 「なし」, never a
// silent skip). Every identity field is checked fail-fast against the imported frozen sets — no independent map.
function validateDungeonEquipmentInstance(instance, label) {
  if (!instance || typeof instance !== 'object' || Array.isArray(instance)) {
    throw new Error(`equipment: ${label} must be an object (got ${JSON.stringify(instance)})`);
  }
  if (!WORKSHOP_EQUIPMENT_KINDS.includes(instance.kind)) {
    throw new Error(`equipment: ${label} kind must be one of ${WORKSHOP_EQUIPMENT_KINDS.join('/')} (got ${JSON.stringify(instance.kind)})`);
  }
  assertWorkshopString(instance.instance_id, `${label}.instance_id`);
  if (instance.kind === 'weapon') {
    if (!WORKSHOP_WEAPON_TYPES.includes(instance.weapon_type)) {
      throw new Error(`equipment: ${label} weapon_type must be one of ${WORKSHOP_WEAPON_TYPES.join('/')} (got ${JSON.stringify(instance.weapon_type)})`);
    }
  } else if (Object.prototype.hasOwnProperty.call(instance, 'weapon_type')) {
    throw new Error(`equipment: a ${instance.kind} ${label} must not carry weapon_type (got ${JSON.stringify(instance.weapon_type)})`);
  }
  if (!WORKSHOP_ELEMENTS.includes(instance.element)) {
    throw new Error(`equipment: ${label} element must be one of ${WORKSHOP_ELEMENTS.join('/')} (got ${JSON.stringify(instance.element)})`);
  }
  assertWorkshopInteger(instance.tier, `${label}.tier`, { min: 1, max: 4 });
  if (!WORKSHOP_EQUIPMENT_QUALITIES.includes(instance.quality)) {
    throw new Error(`equipment: ${label} quality must be one of ${WORKSHOP_EQUIPMENT_QUALITIES.join('/')} (got ${JSON.stringify(instance.quality)})`);
  }
  assertWorkshopString(instance.name, `${label}.name`);
  assertWorkshopString(instance.flavor, `${label}.flavor`);
  const baseEffects = workshopEffectEntries(instance.base_effects, `${label}.base_effects`, { allowEmpty: true });
  const bonusEffects = workshopEffectEntries(instance.bonus_effects, `${label}.bonus_effects`, { allowEmpty: true });
  return { instance, baseEffects, bonusEffects };
}

// Validate the run-equipment aggregate. null (nothing equipped) is a valid reading; a present value must carry an
// `effects` object with every scalar effect key a non-negative integer and element_spell_power an object of magic
// element → positive integer (unknown element / bad value throws). Returns the validated effects (or null).
function validateDungeonRunEquipment(runEquipment) {
  if (runEquipment === null || runEquipment === undefined) return null;
  if (typeof runEquipment !== 'object' || Array.isArray(runEquipment)) {
    throw new Error(`equipment: run_equipment must be an object or null (got ${JSON.stringify(runEquipment)})`);
  }
  const effects = runEquipment.effects;
  if (!effects || typeof effects !== 'object' || Array.isArray(effects)) {
    throw new Error(`equipment: run_equipment.effects must be an object (got ${JSON.stringify(effects)})`);
  }
  for (const key of WORKSHOP_EFFECT_KEYS) {
    if (key === 'element_spell_power') {
      const perElement = effects.element_spell_power;
      if (!perElement || typeof perElement !== 'object' || Array.isArray(perElement)) {
        throw new Error(`equipment: run_equipment.effects.element_spell_power must be an object (got ${JSON.stringify(perElement)})`);
      }
      for (const [element, value] of Object.entries(perElement)) {
        if (!WORKSHOP_ELEMENTS.includes(element)) throw new Error(`equipment: run_equipment element_spell_power has an unknown element ${JSON.stringify(element)}`);
        if (!Number.isInteger(value) || value <= 0) throw new Error(`equipment: run_equipment element_spell_power ${element} must be a positive integer (got ${JSON.stringify(value)})`);
      }
      continue;
    }
    const value = effects[key];
    if (!Number.isInteger(value) || value < 0) {
      throw new Error(`equipment: run_equipment.effects.${key} must be a non-negative integer (got ${JSON.stringify(value)})`);
    }
  }
  return effects;
}

// Validate one owner's two equip slots fail-fast: an object carrying BOTH weapon / amulet keys (present, each an
// instance whose kind matches the slot, or null = unequipped — an absent key is malformed, not a silent null).
// Returns the resolved slot map ({ weapon, amulet } of validated instance views or null). Shared by the player
// slots and the buddy sub-view so both owners resolve by the identical rule.
function validateDungeonEquipmentSlots(rawSlots, label) {
  if (!rawSlots || typeof rawSlots !== 'object' || Array.isArray(rawSlots)) {
    throw new Error(`equipment snapshot: ${label} must be an object (got ${JSON.stringify(rawSlots)})`);
  }
  const resolvedSlots = {};
  for (const slot of WORKSHOP_EQUIPMENT_KINDS) {
    if (!Object.prototype.hasOwnProperty.call(rawSlots, slot)) {
      throw new Error(`equipment snapshot: ${label} is missing the ${slot} slot (got ${JSON.stringify(rawSlots)})`);
    }
    const value = rawSlots[slot];
    if (value === null) {
      resolvedSlots[slot] = null;
      continue;
    }
    const view = validateDungeonEquipmentInstance(value, `${label}.${slot}`);
    if (view.instance.kind !== slot) {
      throw new Error(`equipment snapshot: ${label}.${slot} holds a ${view.instance.kind}, not a ${slot}`);
    }
    resolvedSlots[slot] = view;
  }
  return resolvedSlots;
}

// Validate the required `buddy` sub-view: null when no run companion is set, else an object mirroring the player
// fields — a non-empty character_id, the same two-slot shape, and the same run_equipment shape. A missing (undefined)
// buddy key is a broken server contract, not a silent "no buddy". A homunculus buddy additionally carries a
// display_name (the schema marker: field present ⇒ homunculus, absent ⇒ selectable — B1 contract); when present it
// must be a non-empty string. Returns null or { characterId, displayName: string | null, slots, runEffects }.
function validateDungeonBuddyEquipment(buddy) {
  if (buddy === undefined) {
    throw new Error('equipment snapshot: buddy is required (null when unset, an object when set)');
  }
  if (buddy === null) return null;
  if (typeof buddy !== 'object' || Array.isArray(buddy)) {
    throw new Error(`equipment snapshot: buddy must be an object or null (got ${JSON.stringify(buddy)})`);
  }
  assertWorkshopString(buddy.character_id, 'buddy.character_id');
  const hasDisplayName = Object.prototype.hasOwnProperty.call(buddy, 'display_name');
  const displayName = hasDisplayName ? assertWorkshopString(buddy.display_name, 'buddy.display_name') : null;
  const slots = validateDungeonEquipmentSlots(buddy.slots, 'buddy.slots');
  const runEffects = validateDungeonRunEquipment(buddy.run_equipment);
  return { characterId: buddy.character_id, displayName, slots, runEffects };
}

// Validate the whole GET /api/equipment (and equip/unequip) snapshot fail-fast BEFORE any DOM mutation: `slots`
// resolves as above; `instances` is an array of owned instances; run_equipment validates as above; and `buddy` is
// the required run-companion sub-view (null when unset). Returns the normalized snapshot the renderer consumes.
function validateDungeonEquipmentSnapshot(snapshot) {
  if (!snapshot || typeof snapshot !== 'object' || Array.isArray(snapshot)) {
    throw new Error(`equipment snapshot: malformed response ${JSON.stringify(snapshot)}`);
  }
  const slots = validateDungeonEquipmentSlots(snapshot.slots, 'slots');
  if (!Array.isArray(snapshot.instances)) {
    throw new Error(`equipment snapshot: instances must be an array (got ${JSON.stringify(snapshot.instances)})`);
  }
  const instances = snapshot.instances.map((instance, index) => validateDungeonEquipmentInstance(instance, `instances[${index}]`));
  const runEffects = validateDungeonRunEquipment(snapshot.run_equipment);
  const buddy = validateDungeonBuddyEquipment(snapshot.buddy);
  return { slots, instances, runEffects, buddy };
}

function renderDungeonEquipment(snapshot) {
  dungeonLastEquipmentSnapshot = snapshot;
  const view = validateDungeonEquipmentSnapshot(snapshot);
  const owner = activeDungeonEquipmentOwner(view);
  renderDungeonEquipmentTargetTabs(view, owner.target);
  renderDungeonEquipmentSlots(owner.target, owner.slots, view.instances);
  renderDungeonEquipmentRun(owner.runEffects);
}

// Settle which owner the entry surface renders from the freshly-validated snapshot: the hero by default, or the
// buddy while the snapshot still carries that same buddy. A snapshot whose buddy is gone or changed falls the
// selection back to the hero (a stale companion is never rendered or edited). Returns the equip target id plus that
// owner's resolved slots + run effects.
function activeDungeonEquipmentOwner(view) {
  if (dungeonEquipmentTarget !== 'player') {
    if (view.buddy && view.buddy.characterId === dungeonEquipmentTarget) {
      return { target: view.buddy.characterId, slots: view.buddy.slots, runEffects: view.buddy.runEffects };
    }
    dungeonEquipmentTarget = 'player';
  }
  return { target: 'player', slots: view.slots, runEffects: view.runEffects };
}

// The 主人公 / バディー target tabs. No buddy → the switch UI stays empty (the quiet no-companion state; the hero
// equipment simply shows below). With a buddy, two tabs: the hero and the buddy's roster display name (resolved
// fail-fast — a buddy id absent from the selectable roster throws rather than borrowing another character's name).
function renderDungeonEquipmentTargetTabs(view, activeTarget) {
  const container = document.querySelector('#dungeon-equipment-targets');
  if (!view.buddy) {
    container.replaceChildren();
    return;
  }
  container.replaceChildren(
    buildDungeonEquipmentTargetTab('player', '主人公', activeTarget),
    buildDungeonEquipmentTargetTab(view.buddy.characterId, dungeonEquipmentBuddyName(view.buddy), activeTarget)
  );
}

// The buddy tab's display name. A homunculus buddy carries its display_name in the snapshot sub-view (the schema
// marker); use it directly. A selectable buddy has no display_name field, so it resolves from the already-loaded
// selectable roster (the dungeon flow loads it before the entry render) — an id that does not resolve throws (the
// buddy name is never substituted with another character's, and never falls back to the raw id).
function dungeonEquipmentBuddyName(buddy) {
  if (buddy.displayName !== null) return buddy.displayName;
  const character = selectableCharacters.find((entry) => entry.character_id === buddy.characterId);
  if (!character) {
    throw new Error(`dungeon equipment: buddy ${buddy.characterId} does not resolve in the selectable roster`);
  }
  return character.display_name;
}

function buildDungeonEquipmentTargetTab(target, label, activeTarget) {
  const button = document.createElement('button');
  button.type = 'button';
  button.className = 'dungeon-equipment-target';
  button.dataset.target = target;
  button.setAttribute('role', 'tab');
  const active = target === activeTarget;
  button.setAttribute('aria-selected', active ? 'true' : 'false');
  if (active) button.dataset.active = 'true';
  button.textContent = label;
  button.addEventListener('click', () => selectDungeonEquipmentTarget(target));
  return button;
}

// Switch the shown/edited owner and re-render from the cached snapshot — both owners already live in it, so a tab
// switch needs no refetch.
function selectDungeonEquipmentTarget(target) {
  if (target === dungeonEquipmentTarget) return;
  dungeonEquipmentTarget = target;
  if (dungeonLastEquipmentSnapshot) renderDungeonEquipment(dungeonLastEquipmentSnapshot);
}

function renderDungeonEquipmentSlots(target, slots, instances) {
  const container = document.querySelector('#dungeon-equipment-slots');
  const cards = WORKSHOP_EQUIPMENT_KINDS.map((slot) => buildDungeonEquipmentSlotCard(target, slot, slots[slot], instances));
  container.replaceChildren(...cards);
}

// One slot card: an occupied slot shows the equipped instance + a 解除 (unequip) button; an empty slot shows a
// quiet 未装備 note and — from the owned instances of this kind — the 装備 candidates (a click equips it). A slot
// with no owned candidate of its kind shows only the quiet empty state (an optional workshop nudge, no new導線).
function buildDungeonEquipmentSlotCard(target, slot, equippedView, instances) {
  const card = document.createElement('div');
  card.className = 'dungeon-equipment-slot';
  card.dataset.slot = slot;
  const head = document.createElement('p');
  head.className = 'dungeon-equipment-slot-head';
  head.textContent = `${workshopKindLabel(slot)}スロット`;
  card.append(head);
  if (equippedView) {
    card.append(buildDungeonEquipmentEquipped(target, slot, equippedView));
  } else {
    card.append(buildDungeonEquipmentEmpty(target, slot, instances.filter((view) => view.instance.kind === slot)));
  }
  return card;
}

function buildDungeonEquipmentEquipped(target, slot, view) {
  const wrap = document.createElement('div');
  wrap.className = 'dungeon-equipment-equipped';
  wrap.append(buildDungeonEquipmentInstanceDetail(view));
  const unequip = document.createElement('button');
  unequip.type = 'button';
  unequip.className = 'dungeon-equipment-action';
  unequip.dataset.action = 'unequip';
  unequip.dataset.slot = slot;
  unequip.textContent = '解除';
  unequip.addEventListener('click', () => dungeonUnequip(target, slot).catch(reportDungeonEquipmentError));
  wrap.append(unequip);
  return wrap;
}

// The full display of an equipped instance: its LLM-authored name, the confirmed identity (種別・属性・階級・出来栄え
// using the shared closed-set labels), and the base + roll-derived bonus effects (both from the shared effect-entry
// helper; an empty set reads an honest 「なし」).
function buildDungeonEquipmentInstanceDetail(view) {
  const { instance, baseEffects, bonusEffects } = view;
  const detail = document.createElement('div');
  detail.className = 'dungeon-equipment-instance';
  detail.dataset.element = instance.element;
  const name = document.createElement('p');
  name.className = 'dungeon-equipment-instance-name';
  name.textContent = instance.name;
  const meta = document.createElement('p');
  meta.className = 'dungeon-equipment-instance-meta';
  meta.textContent = dungeonEquipmentInstanceMetaText(instance);
  const effects = document.createElement('div');
  effects.className = 'dungeon-equipment-instance-effects';
  effects.append(
    buildDungeonEquipmentEffectRow('基礎性能', baseEffects),
    buildDungeonEquipmentEffectRow('付加性能', bonusEffects)
  );
  detail.append(name, meta, effects);
  return detail;
}

// The identity line shared by the equipped detail and the candidate row: 種別（武器は weapon_type 併記）・属性・
// 階級T・出来栄え, every token from the shared closed-set label functions (fail-fast on an out-of-set value).
function dungeonEquipmentInstanceMetaText(instance) {
  return `${workshopKindLabelFull(instance)}・属性${workshopElementLabel(instance.element)}・階級T${instance.tier}・出来栄え${workshopQualityLabel(instance.quality)}`;
}

function buildDungeonEquipmentEffectRow(label, entries) {
  const row = document.createElement('div');
  row.className = 'dungeon-equipment-effect-row';
  const rowLabel = document.createElement('span');
  rowLabel.className = 'dungeon-equipment-effect-label';
  rowLabel.textContent = label;
  const chips = document.createElement('span');
  chips.className = 'dungeon-equipment-effect-chips';
  if (entries.length === 0) {
    const none = document.createElement('span');
    none.className = 'dungeon-equipment-effect-none';
    none.textContent = 'なし';
    chips.append(none);
  } else {
    for (const entry of entries) chips.append(dungeonEquipmentEffectChip(entry));
  }
  row.append(rowLabel, chips);
  return row;
}

function dungeonEquipmentEffectChip(effect) {
  const chip = document.createElement('span');
  chip.className = 'dungeon-equipment-effect';
  chip.textContent = `${effect.label}+${effect.value}`;
  return chip;
}

function buildDungeonEquipmentEmpty(target, slot, candidates) {
  const wrap = document.createElement('div');
  wrap.className = 'dungeon-equipment-empty';
  const note = document.createElement('p');
  note.className = 'dungeon-equipment-empty-note';
  note.textContent = '未装備';
  wrap.append(note);
  if (candidates.length === 0) {
    const hint = document.createElement('p');
    hint.className = 'dungeon-equipment-empty-hint';
    hint.textContent = 'この種別の装備はまだありません。工房で仕立てられます。';
    wrap.append(hint);
    return wrap;
  }
  const list = document.createElement('div');
  list.className = 'dungeon-equipment-candidates';
  for (const candidate of candidates) list.append(buildDungeonEquipmentCandidate(target, slot, candidate));
  wrap.append(list);
  return wrap;
}

function buildDungeonEquipmentCandidate(target, slot, view) {
  const { instance } = view;
  const button = document.createElement('button');
  button.type = 'button';
  button.className = 'dungeon-equipment-candidate';
  button.dataset.instanceId = instance.instance_id;
  button.dataset.element = instance.element;
  const name = document.createElement('span');
  name.className = 'dungeon-equipment-candidate-name';
  name.textContent = instance.name;
  const meta = document.createElement('span');
  meta.className = 'dungeon-equipment-candidate-meta';
  meta.textContent = dungeonEquipmentInstanceMetaText(instance);
  button.append(name, meta);
  button.addEventListener('click', () => dungeonEquip(target, slot, instance.instance_id).catch(reportDungeonEquipmentError));
  return button;
}

// The run-correction breakdown: the aggregated effects that WILL fold into the run at enter. Scalar effects are
// listed (in the shared effect-key order) only when non-zero; element_spell_power expands to one row per element
// (属性別). A null run_equipment — nothing equipped — reads 補正なし (not an empty panel).
function renderDungeonEquipmentRun(runEffects) {
  const container = document.querySelector('#dungeon-equipment-run');
  const title = document.createElement('p');
  title.className = 'dungeon-equipment-run-title';
  title.textContent = 'この run に効く補正';
  const body = document.createElement('div');
  body.className = 'dungeon-equipment-run-body';
  const rows = runEffects ? dungeonRunEquipmentRows(runEffects) : [];
  if (rows.length === 0) {
    const none = document.createElement('p');
    none.className = 'dungeon-equipment-run-none';
    none.textContent = '補正なし';
    body.append(none);
  } else {
    for (const row of rows) body.append(buildDungeonEquipmentRunRow(row));
  }
  container.replaceChildren(title, body);
}

// Ordered { label, value } rows over the shared effect-key order: each non-zero scalar once, then one row per
// contributing element for element_spell_power (label 同属性スペル威力（<属性>）). Effects are pre-validated.
function dungeonRunEquipmentRows(effects) {
  const rows = [];
  for (const key of WORKSHOP_EFFECT_KEYS) {
    if (key === 'element_spell_power') {
      for (const element of WORKSHOP_ELEMENTS) {
        const value = effects.element_spell_power[element];
        if (value === undefined) continue;
        rows.push({ label: `${WORKSHOP_EFFECT_LABELS[key]}（${workshopElementLabel(element)}）`, value });
      }
      continue;
    }
    const value = effects[key];
    if (value > 0) rows.push({ label: WORKSHOP_EFFECT_LABELS[key], value });
  }
  return rows;
}

function buildDungeonEquipmentRunRow(row) {
  const el = document.createElement('div');
  el.className = 'dungeon-equipment-run-row';
  const label = document.createElement('span');
  label.className = 'dungeon-equipment-run-label';
  label.textContent = row.label;
  const value = document.createElement('span');
  value.className = 'dungeon-equipment-run-value';
  value.textContent = `+${row.value}`;
  el.append(label, value);
  return el;
}

// Equip an owned instance into its slot / clear a slot. Both adopt the returned authoritative snapshot as the sole
// source of truth (no optimistic slot mutation); an in-flight guard blocks a double POST. A failure REJECTS to the
// click handler's reporter (the equip/unequip is fail-fast — nothing is guessed on error). Only the in-flight reset
// runs in finally.
async function dungeonEquip(target, slot, instanceId) {
  if (dungeonEquipmentInFlight) {
    showProcessingToast();
    return;
  }
  dungeonEquipmentInFlight = true;
  try {
    setDungeonEquipmentStatus('');
    const snapshot = await postJson('/api/equipment/equip', { target, slot, instance_id: instanceId });
    renderDungeonEquipment(snapshot);
  } finally {
    dungeonEquipmentInFlight = false;
  }
}

async function dungeonUnequip(target, slot) {
  if (dungeonEquipmentInFlight) {
    showProcessingToast();
    return;
  }
  dungeonEquipmentInFlight = true;
  try {
    setDungeonEquipmentStatus('');
    const snapshot = await postJson('/api/equipment/unequip', { target, slot });
    renderDungeonEquipment(snapshot);
  } finally {
    dungeonEquipmentInFlight = false;
  }
}

async function enterDungeon() {
  if (dungeonActionInFlight) return;
  if (dungeonFinalizationInFlight) {
    // A prior run's finalize is still landing; the run is held server-side, so block re-entry.
    showProcessingToast();
    return;
  }
  dungeonActionInFlight = true;
  dungeonChatMessages = [];
  let bufferedView = null;
  let leftLoading = false;
  const showPlay = () => {
    if (leftLoading || !bufferedView) return;
    leftLoading = true;
    // Leave the loading screen: activate the dungeon screen (without its auto state-refetch, since
    // we already hold the board) and reveal the buffered board. renderDungeonPlay only unhides
    // #dungeon-play WITHIN the dungeon screen, so without this switch the board stays hidden behind
    // the still-active loading screen and the loader never appears to exit.
    showScreen('academy-dungeon', { skipDungeonRefresh: true });
    renderDungeonPlay(bufferedView);
  };
  try {
    setAcademyLoadingDestinationCopy(null, { loadingCopy: DUNGEON_ENTER_LOADING_COPY });
    showScreen('academy-loading');
    const minimumDisplay = sleep(ACADEMY_LOADING_MINIMUM_MS);
    // Enter streams: the board arrives on a dungeon_enter event, then the companion opening
    // streams token by token into the chat. The first token leaves the loading screen and
    // reveals the board; the opening keeps streaming into the now-visible panel.
    await runAssistantSseStream({
      surface: dungeonChatSurface,
      endpoint: '/api/dungeon/enter',
      body: {},
      statusPrefix: 'dungeon-enter',
      finalAssistantMode: 'first',
      refreshAfter: false,
      onEvent: (event, data) => { if (event === 'dungeon_enter') { bufferedView = data.view; notifyAcademyLoadingProgress(); } },
      onAssistantStreamStart: () => showPlay()
    });
    // Solo / no-companion enter has no opening token: hold the loading its usual minimum, then
    // reveal the board.
    await minimumDisplay;
    showPlay();
  } catch (error) {
    // Enter / opening failure returns to the room and surfaces the error — never a silent
    // drop into a solo run on the loading screen.
    showScreen('academy-room');
    reportError(error);
  } finally {
    dungeonActionInFlight = false;
  }
}

async function dungeonDo(action) {
  if (dungeonActionInFlight || !currentDungeonView) return;
  dungeonActionInFlight = true;
  try {
    const result = await postJson('/api/dungeon/action', { action });
    if (result.ended) {
      // A run-ending turn (e.g. the fatal blow) still gets its combat animation: play it on the
      // still-visible board, then show the result. Awaited so input stays gated meanwhile.
      if (result.events?.length) {
        animateDungeonCombat(result.events);
        await new Promise((resolve) => window.setTimeout(resolve, DUNGEON_ENDED_ANIM_MS));
      }
      renderDungeonResult(result);
      await dungeonExitToRoom(result);
    } else {
      renderDungeonPlay(result);
      animateDungeonCombat(result.events);
    }
  } finally {
    dungeonActionInFlight = false;
  }
}

// Builds the result-surface payload for a run held server-side awaiting its finalize (used when
// resuming an interrupted exit). applied_gains_preview is the clamped deltas the finalize will bank
// (empty for death), so a resumed exit shows the same gains the action's preview did.
function dungeonResultFromHeldView(view) {
  return {
    ended: true,
    pending_finalize: true,
    status: view.pending_finalize.outcome,
    floor_reached: view.floor,
    max_floors: view.max_floors,
    applied_gains: view.applied_gains_preview ?? { magic: {}, abilities: {} }
  };
}

// Exit hand-off mirroring the conversation post-flow: show the result a beat, slip through the
// loading screen, and land in the room. A companion run's finalize -> bank -> clear runs in the
// background (busy-gated server-side) so the room is reached without waiting on the LLM; a solo
// run end has already banked synchronously, so there is nothing to background.
async function dungeonExitToRoom(result) {
  if (result.pending_finalize) startDungeonBackgroundFinalize();
  await sleep(DUNGEON_RESULT_HOLD_MS);
  // The action-ended result carries the mode-resolved next screen (loop -> academy-room, routing ->
  // interaction). A run resumed from a held-finalize state (dungeonResultFromHeldView) has no
  // transition — the dungeon state view does not expose it — so the global play mode resolves the
  // return screen for that recovery case, mirroring the backend's post-dungeon screen.
  let nextScreen = result.transition?.next_screen ?? null;
  if (nextScreen == null) {
    if (currentPlayMode !== 'loop' && currentPlayMode !== 'routing') {
      throw new Error(`dungeon resume: unknown play mode ${JSON.stringify(currentPlayMode)}`);
    }
    nextScreen = currentPlayMode === 'routing' ? 'interaction' : 'academy-room';
  }
  // Drain-on-exit for the routing dungeon return: the companion dungeon finalize (POST
  // /api/dungeon/finalize) is the dungeon's post-processing. The hub it returns to opens on an empty
  // pending-finalization queue — the hub->dungeon dispatch already drained ルミ's finalization on exit,
  // and the hub start no longer pre-drains — so the only post-processing left at exit is the companion
  // finalize. Drain it to completion under the exit loading screen BEFORE opening the hub, so the
  // companion finalize and the hub opening never race on the LM pipeline (hub return happens only after
  // the drain completes). Loop returns to academy-room and never enters the hub, so it keeps the
  // un-awaited background finalize (its room is reached without waiting on the LLM).
  if (nextScreen === 'interaction' && activeDungeonFinalizationPromise) {
    await showAcademyLoadingScreenUntilReady({
      // The companion finalize drain is the observed boundary held under the exit loading screen; advance the
      // constellation when it completes. The following hub return (navigateToPostContentScreen → enterRoutingHub)
      // keeps the same loader up and advances again on its own POST/refresh boundaries.
      readiness: (async () => { await activeDungeonFinalizationPromise; notifyAcademyLoadingProgress(); })(),
      loadingCopy: DUNGEON_HUB_RETURN_LOADING_COPY
    });
  }
  await navigateToPostContentScreen(nextScreen, { loadingCopy: DUNGEON_EXIT_LOADING_COPY });
}

// Runs the deferred companion finalize -> bank -> clear in the background. The server holds the
// LLM busy gate for the request's duration, so re-entering the dungeon meanwhile sees llm_busy.
// A failure surfaces (reportError) and leaves the run held server-side for a later retry.
function startDungeonBackgroundFinalize() {
  if (dungeonFinalizationInFlight) return;
  dungeonFinalizationInFlight = true;
  const finalization = (async () => {
    try {
      const result = await postJson('/api/dungeon/finalize', {});
      if (result.world?.player_parameters) {
        currentWorld = { ...(currentWorld ?? {}), player_parameters: result.world.player_parameters };
      }
      currentRuntimeState = result.state ?? currentRuntimeState;
      await refresh();
      if (screens['academy-room']?.classList.contains('active')) renderAcademyRoomScreen();
    } catch (error) {
      reportError(error);
    } finally {
      dungeonFinalizationInFlight = false;
      if (activeDungeonFinalizationPromise === finalization) activeDungeonFinalizationPromise = null;
    }
  })();
  activeDungeonFinalizationPromise = finalization;
}

async function dungeonRetreat() {
  if (!currentDungeonView || !currentDungeonView.can_retreat) return;
  closeDungeonRetreatConfirm();
  await dungeonDo({ type: 'retreat' });
}

function dungeonCompanionIdentity() {
  const companion = currentDungeonView?.companion;
  return { character_id: companion?.character_id ?? null, character_name: companion?.name ?? '' };
}

// A run view companion is a homunculus when it carries a face_url (the B3 schema marker — a selectable companion
// carries no face_url / parameters). Its face + 11 parameters come from the run view entry snapshot, not the roster.
function dungeonCompanionIsHomunculus(companion) {
  return typeof companion?.face_url === 'string' && companion.face_url !== '';
}

// Maps the run-scoped companion conversation into display messages, carrying each
// assistant turn's expression so the sidebar shows per-message faces (the conversation
// pipeline is the source of truth for the full message list).
function dungeonMessagesFromConversation(conversation) {
  const identity = dungeonCompanionIdentity();
  return (conversation?.messages ?? [])
    .filter((message) => message.role === 'user' || message.role === 'assistant')
    .map((message) => {
      if (message.role === 'assistant') {
        return {
          role: 'assistant',
          character_id: identity.character_id,
          character_name: identity.character_name,
          content: message.content ?? '',
          face_emotion_variant_id: message.face_emotion_variant_id ?? 'face_neutral',
          expression: message.expression ?? 'neutral'
        };
      }
      return { role: 'user', content: message.content ?? '' };
    });
}

// Renders the companion chat log using the shared message rows (faces + bubbles) into
// the dungeon sidebar target. Edits are off here (companion message editing is out of
// scope), and the sidebar layout/CSS is scoped separately under .dungeon-chat-log.
function renderDungeonChatLog(messages, { popFromDisplayIndex = -1 } = {}) {
  dungeonChatMessages = messages;
  const log = document.querySelector('#dungeon-chat-log');
  if (!log) return;
  log.replaceChildren(...createMessageRows(displayMessages(messages), popFromDisplayIndex, false));
  applyDungeonCompanionMessageFace(log);
  log.scrollTop = log.scrollHeight;
}

// A homunculus companion is absent from the selectable roster, so the shared message rows (createMessageRows →
// sourceSheetImageUrl) cannot resolve its face. When the run view companion carries a face_url (the homunculus
// marker), override each assistant bubble's message face with it — a dungeon-scoped override that leaves the shared
// createMessageRows / sourceSheetImageUrl untouched. A selectable companion has no face_url and keeps its roster face.
function applyDungeonCompanionMessageFace(log) {
  const companion = currentDungeonView?.companion;
  if (!companion || !dungeonCompanionIsHomunculus(companion)) return;
  for (const image of log.querySelectorAll('.message-face img')) {
    setActorImageSource(image, companion.face_url);
  }
}

// The dungeon companion mounts the shared streaming chat controller with its own
// history store, render target, identity, and conversation mapping.
const dungeonChatSurface = {
  getHistory: () => dungeonChatMessages,
  setHistory: (messages) => { dungeonChatMessages = messages; },
  render: (messages, options) => renderDungeonChatLog(messages, options),
  mapMessages: (conversation) => dungeonMessagesFromConversation(conversation),
  assistantIdentity: () => dungeonCompanionIdentity(),
  commitState: (result) => { dungeonChatMessages = dungeonMessagesFromConversation(result.conversation); },
  refresh: async () => {}
};

function setDungeonChatInputDisabled(disabled) {
  document.querySelector('#dungeon-talk-send').disabled = disabled;
  document.querySelector('#dungeon-talk-input').disabled = disabled;
}

async function dungeonTalk() {
  const input = document.querySelector('#dungeon-talk-input');
  const text = input.value.trim();
  if (!text || dungeonActionInFlight || !currentDungeonView?.companion || currentDungeonView.companion.down) return;
  dungeonActionInFlight = true;
  setDungeonChatInputDisabled(true);
  // Snapshot the committed history so a failed send can roll the optimistic line back out.
  const previousMessages = dungeonChatMessages;
  try {
    input.value = '';
    // Show the player's line immediately, then stream the companion reply through the
    // shared controller (tokens, per-message expression, cooldown-paced reveal).
    dungeonChatSurface.render([
      ...previousMessages,
      { role: 'user', content: text }
    ]);
    await runAssistantSseStream({
      surface: dungeonChatSurface,
      endpoint: '/api/dungeon/companion/talk/stream',
      body: { player_input: text },
      statusPrefix: 'companion',
      finalAssistantMode: 'last',
      refreshAfter: false
    });
  } catch (error) {
    // Roll the optimistic (and any partially revealed) line out by restoring the
    // pre-send history, and put the text back in the input so the player can retry.
    dungeonChatMessages = previousMessages;
    input.value = text;
    renderDungeonChat(currentDungeonView);
    reportError(error);
  } finally {
    dungeonActionInFlight = false;
    setDungeonChatInputDisabled(currentDungeonView?.companion?.down ?? false);
  }
}

// Builds a decorated icon token (frame ring via CSS, optional face/icon image with a
// glyph fallback so nothing breaks before the art assets land, optional HP microbar).
function dungeonTokenEl({ roleClass, elementClass = '', imageUrl = null, glyph = '', crest = false, down = false, hp = null, maxHp = null, label = '' }) {
  const token = document.createElement('div');
  token.className = ['dn-token', roleClass, elementClass, down ? 'dn-token--down' : ''].filter(Boolean).join(' ');
  if (label) token.title = label;
  const inner = document.createElement('div');
  inner.className = 'dn-token-inner';
  if (crest) {
    inner.innerHTML = DUNGEON_CREST_SVG;
  } else if (imageUrl) {
    const img = document.createElement('img');
    img.className = 'dn-token-img';
    img.alt = '';
    img.src = imageUrl;
    img.addEventListener('error', () => {
      img.remove();
      const fallback = document.createElement('span');
      fallback.className = 'dn-token-glyph';
      fallback.textContent = glyph;
      inner.append(fallback);
    });
    inner.append(img);
  } else {
    const fallback = document.createElement('span');
    fallback.className = 'dn-token-glyph';
    fallback.textContent = glyph;
    inner.append(fallback);
  }
  token.append(inner);
  if (hp != null && maxHp != null && maxHp > 0) {
    const bar = document.createElement('div');
    bar.className = 'dn-token-hp';
    const fill = document.createElement('div');
    fill.className = 'dn-token-hp-fill';
    fill.style.width = `${Math.max(0, Math.min(100, Math.round((hp / maxHp) * 100)))}%`;
    bar.append(fill);
    token.append(bar);
  }
  return token;
}

// Places a map entity over tile (x, y). New nodes get their transform set before they are
// connected, so they mount at the target with no slide; existing nodes change a connected
// node's transform, which the CSS transition animates as a tile-to-tile slide.
function upsertDungeonEntity(overlay, key, live, x, y, tokenEl) {
  live.add(key);
  dungeonEntityTiles.set(key, { x, y });
  const transform = `translate(calc((var(--dn-cell) + var(--dn-gap)) * ${x}), calc((var(--dn-cell) + var(--dn-gap)) * ${y}))`;
  let node = dungeonEntityNodes.get(key);
  if (!node) {
    node = document.createElement('div');
    node.className = 'dn-entity';
    node.style.transform = transform;
    node.replaceChildren(tokenEl);
    dungeonEntityNodes.set(key, node);
    overlay.append(node);
    return;
  }
  node.style.transform = transform;
  node.replaceChildren(tokenEl);
}

function renderDungeonGrid(view) {
  // The player's tile from the previous render — read before the entity overlay below overwrites it
  // and before a fresh board clears it. A same-board re-render where the player has NOT moved keeps
  // the camera exactly as placed (no follow content-clamp, no jump), so the entry center survives a
  // re-show / state refresh without any owed-center bookkeeping.
  const previousPlayerTile = dungeonEntityTiles.get('player') ?? null;
  const grid = document.querySelector('#dungeon-grid');
  // The board holds the rebuilt tile grid plus a persistent entity overlay, and sits inside
  // a clipping viewport so the deadzone camera can scroll the whole board (translate) while
  // the viewport masks everything outside the window. Only the tiles are rebuilt each render;
  // the overlay's entity nodes survive so movement animates.
  let board = grid.querySelector('.dn-board');
  if (!board) {
    const viewport = document.createElement('div');
    viewport.className = 'dn-viewport';
    board = document.createElement('div');
    board.className = 'dn-board';
    const tilesLayer = document.createElement('div');
    tilesLayer.className = 'dn-tiles';
    const entitiesLayer = document.createElement('div');
    entitiesLayer.className = 'dn-entities';
    // Transient combat effects (cast/melee/enemy-attack) render here; it lives inside the board
    // so effects scroll with the camera and align to tiles like the entity overlay.
    const effectsLayer = document.createElement('div');
    effectsLayer.className = 'dn-effects';
    board.append(tilesLayer, entitiesLayer, effectsLayer);
    viewport.append(board);
    grid.replaceChildren(viewport);
  }
  const tiles = board.querySelector('.dn-tiles');
  const overlay = board.querySelector('.dn-entities');
  tiles.style.setProperty('--dn-cols', view.width);
  tiles.style.setProperty('--dn-rows', view.height);

  // A new run or a new floor is a fresh board: drop the persistent entity nodes so each
  // entity re-mounts at its position instead of sliding across the screen from the old one,
  // and snap the camera to the new floor instead of panning across from the old one.
  const signature = `${view.run_id}:${view.floor}`;
  const signatureChanged = signature !== dungeonBoardSignature;
  if (signatureChanged) {
    dungeonBoardSignature = signature;
    dungeonEntityNodes.clear();
    dungeonEntityTiles.clear();
    overlay.replaceChildren();
  }

  // Tiles + static features (stairs, items). Moving entities are drawn in the overlay below.
  const itemAt = new Map(view.items.map((item) => [`${item.x},${item.y}`, item]));
  const cells = [];
  for (let y = 0; y < view.height; y += 1) {
    for (let x = 0; x < view.width; x += 1) {
      const cell = document.createElement('div');
      cell.className = 'dn-cell';
      if (!view.explored[y][x]) {
        cell.classList.add('dn-fog');
        cells.push(cell);
        continue;
      }
      if (!view.visible[y][x]) cell.classList.add('dn-dim');
      cell.classList.add(view.tiles[y][x] === 'floor' ? 'dn-floor' : 'dn-wall');
      const key = `${x},${y}`;
      if (view.stairs.x === x && view.stairs.y === y) {
        cell.append(dungeonTokenEl({ roleClass: 'dn-token--stairs', imageUrl: dungeonStairsIconUrl(), glyph: DUNGEON_GLYPHS.stairs, label: '下り階段' }));
      } else if (view.entrance.x === x && view.entrance.y === y) {
        // The floor's arrival point (floor 1 entrance / floor 2+ up-stairs). Retreat only banks from
        // here or the down-stairs (greed ladder), so it needs a distinct marker: a CSS-only up-stairs
        // glyph (＜, the mirror of the down-stairs ＞) in the cool ally hue vs the down-stairs' amber.
        cell.append(dungeonTokenEl({ roleClass: 'dn-token--entrance', glyph: DUNGEON_GLYPHS.entrance, label: '入場地点（撤退可）' }));
      } else if (itemAt.has(key)) {
        const item = itemAt.get(key);
        cell.append(dungeonTokenEl({ roleClass: 'dn-token--item', imageUrl: dungeonItemIconUrl(item.kind), glyph: item.glyph ?? DUNGEON_GLYPHS.item, label: item.name }));
      }
      cells.push(cell);
    }
  }
  tiles.replaceChildren(...cells);

  // Moving entities, keyed by identity so a position change animates: player, the companion
  // (when up), and each currently-visible enemy by its stable uid.
  const live = new Set();
  upsertDungeonEntity(overlay, 'player', live, view.player.x, view.player.y,
    dungeonTokenEl({ roleClass: 'dn-token--self', crest: true, hp: view.player.hp, maxHp: view.player.max_hp, label: '主人公' }));
  if (view.companion && !view.companion.down) {
    upsertDungeonEntity(overlay, 'companion', live, view.companion.x, view.companion.y,
      dungeonTokenEl({ roleClass: 'dn-token--ally', imageUrl: dungeonCompanionTokenFaceUrl(view.companion), glyph: DUNGEON_GLYPHS.companion, hp: view.companion.hp, maxHp: view.companion.max_hp, label: view.companion.name }));
  }
  for (const enemy of view.enemies) {
    upsertDungeonEntity(overlay, `enemy:${enemy.uid}`, live, enemy.x, enemy.y,
      dungeonTokenEl({ roleClass: `dn-token--enemy${enemy.elite ? ' dn-token--elite' : ''}`, elementClass: `dn-token--el-${enemy.element}`, imageUrl: dungeonEnemyIconUrl(enemy.archetype_id), glyph: enemy.glyph, hp: enemy.hp, maxHp: enemy.max_hp, label: `${enemy.name}（${DUNGEON_MAGIC_LABELS[enemy.element] ?? enemy.element}）` }));
  }
  // Remove entities that died, left view, or went down (the companion).
  for (const [key, node] of dungeonEntityNodes) {
    if (!live.has(key)) {
      node.remove();
      dungeonEntityNodes.delete(key);
      dungeonEntityTiles.delete(key);
    }
  }

  // Camera placement is a function of what changed: a fresh board (new run / floor) centers the
  // player; a same-board render where the player MOVED is a deadzone follow; a same-board render
  // where the player did NOT move (a re-show, a state refresh, an enemy-only turn) preserves the
  // camera as placed. A viewport resize is handled separately by the grid ResizeObserver ('reframe').
  const playerMoved = !previousPlayerTile
    || previousPlayerTile.x !== view.player.x || previousPlayerTile.y !== view.player.y;
  const mode = signatureChanged ? 'center' : (playerMoved ? 'follow' : 'preserve');
  layoutDungeonBoard(view, { mode });
}

// Bounding box (tile coords, inclusive) of the floor tiles — the explorable area the camera is
// allowed to scroll over. The player always stands on a floor tile, so at least one exists.
function dungeonFloorBounds(view) {
  let minX = Infinity;
  let minY = Infinity;
  let maxX = -Infinity;
  let maxY = -Infinity;
  for (let y = 0; y < view.height; y += 1) {
    for (let x = 0; x < view.width; x += 1) {
      if (view.tiles[y][x] !== 'floor') continue;
      if (x < minX) minX = x;
      if (x > maxX) maxX = x;
      if (y < minY) minY = y;
      if (y > maxY) maxY = y;
    }
  }
  return { minX, minY, maxX, maxY };
}

// The reframe anchor: where the player token is ACTUALLY drawn right now, read from the live rects
// so it reflects the real displayed frame — a follow pan AND a tile slide still mid-transition.
// `fracX`/`fracY` are its position as a fraction of the viewport (where to keep it on screen);
// `boardCenterX`/`boardCenterY` are its center in board pixels (its current, possibly fractional,
// tile position). Both come from the SAME measured rect, so they never mix a half-slid token with
// its final logical tile. The reframe path only runs with the play screen up and rendered, so the
// player node is always present here.
function measureDungeonReframeAnchor(viewport, board) {
  const node = dungeonEntityNodes.get('player');
  if (!node) throw new Error('dungeon: reframe needs the rendered player node');
  const playerRect = node.getBoundingClientRect();
  const boardRect = board.getBoundingClientRect();
  const frac = playerViewportFraction({ playerRect, viewportRect: viewport.getBoundingClientRect() });
  return {
    fracX: frac.x,
    fracY: frac.y,
    boardCenterX: (playerRect.left + playerRect.width / 2) - boardRect.left,
    boardCenterY: (playerRect.top + playerRect.height / 2) - boardRect.top
  };
}

// Commit every entity's transform to the CURRENT --dn-cell with no slide. An entity transform is
// `translate(calc((--dn-cell + --dn-gap) * tile))`, so when the tile size changes its resolved
// value changes and the 0.16s transform transition would slide the token to the new size a frame
// LATER than the CSS-grid tiles (which resize instantly) — a tile-vs-token desync at the switch.
// Suppressing the transition for one reflow snaps the tokens in the same frame as the tiles, so
// they rescale together. Called only on a cell-changing reframe (rare: a real viewport resize).
function snapDungeonEntitiesToCell(grid) {
  if (!dungeonEntityNodes.size) return;
  for (const node of dungeonEntityNodes.values()) node.style.transition = 'none';
  void grid.offsetWidth; // force the transition-less transforms to commit at the new cell
  for (const node of dungeonEntityNodes.values()) node.style.transition = '';
}

// Sizes the tiles and positions the deadzone camera for the current view. These are one
// layout: the cell size is chosen so the player's vision range fits the viewport, and the
// follow margin (where the camera starts scrolling) is the vision radius itself, so the lit
// area sits fully on-screen exactly as the camera begins to follow.
//
// Camera model: while the player stays inside a central deadzone the camera holds still and
// only the player moves; once the player reaches the deadzone edge the camera scrolls the
// board to keep them there, until the board hits a map edge. An axis whose map is smaller
// than the viewport is centered instead of scrolled.
//
// `mode` selects how the camera is placed for this layout:
//   'follow'   — a normal turn (the player moved): the deadzone follow scrolls from the previous offset.
//   'center'   — a fresh board (new run / floor): frame the player in the middle, once, against the
//                settled viewport (renderDungeonPlay lays the surrounding panels out first, so the
//                map column is already at its final width when this measures — no transient center).
//   'reframe'  — the viewport changed size (resize, or a HUD reflow): hold the player at the position
//                it is actually drawn at right now so it does not jump. A reframe whose viewport size
//                matches the last layout has nothing to do and is skipped.
//   'preserve' — a same-board re-render where the player did not move (a re-show, a state refresh, an
//                enemy-only turn): leave the camera exactly as placed.
function layoutDungeonBoard(view, { mode }) {
  const grid = document.querySelector('#dungeon-grid');
  if (!grid) return;
  const viewport = grid.querySelector('.dn-viewport');
  const board = viewport?.querySelector('.dn-board');
  if (!viewport || !board) return;
  // Nothing changed that moves the camera: keep the board exactly where it is (this is what makes a
  // pre-move re-show stay dead-centre, and a mid-run state refresh not jump).
  if (mode === 'preserve') return;
  const viewW = viewport.clientWidth;
  const viewH = viewport.clientHeight;
  // No size yet (the screen was not laid out): bail rather than divide by zero. renderDungeonPlay
  // shows the screen and the surrounding panels before the grid renders, so a fresh-board center
  // measures a real viewport here; a 0-size layout is a not-yet-laid-out call, not a lost center.
  if (viewW === 0 || viewH === 0) return;
  // A reframe responds to an ACTUAL viewport resize. When the grid ResizeObserver fires with no net
  // size change — the settle that fires right after a fresh board already centered at the final
  // width — there is nothing to reframe, so leave the centered frame as placed.
  if (mode === 'reframe' && viewW === dungeonViewportSize.w && viewH === dungeonViewportSize.h) return;

  // A reframe must hold the player where it is ACTUALLY drawn right now — read it (and the tile
  // size it was drawn under) before this layout changes the tile size, so a follow pan / tile slide
  // still in flight is captured (never the final logical tile that a mid-transition resize jumps to).
  const reframeAnchor = mode === 'reframe' ? measureDungeonReframeAnchor(viewport, board) : null;
  const reframeFromCell = mode === 'reframe' ? parseFloat(getComputedStyle(grid).getPropertyValue('--dn-cell')) : null;

  const gap = parseFloat(getComputedStyle(grid).getPropertyValue('--dn-gap'));
  if (!Number.isFinite(gap)) throw new Error('dungeon: --dn-gap must resolve to a length');
  const r = view.player_stats.vision_radius; // drives the follow margin only; the cell no longer depends on it

  const cell = computeDungeonCellSize({ viewW, viewH, gap, targetCells: DN_TARGET_CELLS, cellMin: DN_CELL_MIN, cellMax: DN_CELL_MAX });
  grid.style.setProperty('--dn-cell', `${cell}px`);

  const step = cell + gap;
  const playerX = view.player.x * step + cell / 2;
  const playerY = view.player.y * step + cell / 2;
  const marginX = computeFollowMargin({ visionRadius: r, step, cell, viewSize: viewW });
  const marginY = computeFollowMargin({ visionRadius: r, step, cell, viewSize: viewH });

  // Scroll bounds = the explorable area: the floor bounding box widened by one tile so the
  // bordering wall shows. Clamping the camera to this (not the full map) means the outermost
  // reachable floor tile always brings its map edge to the viewport edge, and the all-wall rows
  // beyond the outermost rooms are never scrolled into.
  const bounds = dungeonFloorBounds(view);
  const contentMinX = Math.max(0, bounds.minX - 1) * step;
  const contentMinY = Math.max(0, bounds.minY - 1) * step;
  const contentMaxX = (Math.min(view.width - 1, bounds.maxX + 1) + 1) * step - gap;
  const contentMaxY = (Math.min(view.height - 1, bounds.maxY + 1) + 1) * step - gap;

  let camera;
  if (mode === 'reframe' && cell !== reframeFromCell) {
    // The tile size actually changed (a genuine viewport resize). The CSS-grid tiles resize
    // instantly, so snap the entity tokens to the new size in the same frame (no 0.16s slide lag)
    // — tiles and tokens move together, no desync at the switch. Snapping commits each token to its
    // logical tile under the new cell, so anchor the camera on the player's logical tile held at the
    // screen fraction it was just drawn at: the player keeps its screen position and stays aligned
    // with its tile.
    snapDungeonEntitiesToCell(grid);
    camera = reframeDungeonCamera({
      playerX, playerY, fracX: reframeAnchor.fracX, fracY: reframeAnchor.fracY,
      contentMinX, contentMaxX, contentMinY, contentMaxY, viewW, viewH
    });
  } else if (mode === 'reframe') {
    // The tile size is unchanged (a small HUD/log reflow, or a no-op resize). Hold the player at its
    // actual current on-screen position: anchor on its DISPLAYED board-px center (its current,
    // possibly mid-slide, tile position) — an identity rescale here — paired with the displayed
    // fraction. One basis, so a reflow during a tile slide neither yanks the player to centre (the
    // HUD-reflow fix) nor jumps it a half-tile to its destination (the slide race).
    const anchorX = rescaleBoardPx({ px: reframeAnchor.boardCenterX, fromCell: reframeFromCell, toCell: cell, gap });
    const anchorY = rescaleBoardPx({ px: reframeAnchor.boardCenterY, fromCell: reframeFromCell, toCell: cell, gap });
    camera = reframeDungeonCamera({
      playerX: anchorX, playerY: anchorY, fracX: reframeAnchor.fracX, fracY: reframeAnchor.fracY,
      contentMinX, contentMaxX, contentMinY, contentMaxY, viewW, viewH
    });
  } else {
    // 'center' (a fresh board) and 'follow' (a move) use ONE camera rule: the deadzone follow,
    // content-clamped. They differ only in the deadzone seed — a move continues from the previous
    // camera, while a fresh-board entry seeds from the player-centred offset so the entry frame is
    // the centred-then-clamped position the follow would hold. The player thus enters exactly where
    // the follow keeps them, so the first step (still inside the deadzone) moves the camera by zero:
    // no jump from a clamp-less center handing off to a content-clamped follow.
    const seedX = mode === 'center' ? playerX - viewW / 2 : dungeonCamera.x;
    const seedY = mode === 'center' ? playerY - viewH / 2 : dungeonCamera.y;
    camera = computeDungeonCamera({
      playerX, playerY, contentMinX, contentMaxX, contentMinY, contentMaxY,
      viewW, viewH, marginX, marginY, prevX: seedX, prevY: seedY
    });
  }
  dungeonCamera = camera;
  // Record the viewport this layout was computed for, so the next reframe can tell a real resize
  // from a no-net-change ResizeObserver firing (the entry settle) and skip the latter.
  dungeonViewportSize = { w: viewW, h: viewH };

  const transform = `translate(${-camera.x}px, ${-camera.y}px)`;
  if (mode === 'follow') {
    board.style.transition = '';
    board.style.transform = transform;
  } else {
    // A center / reframe commits without a pan: kill the transition, commit, then restore so
    // later moves animate.
    board.style.transition = 'none';
    board.style.transform = transform;
    void board.offsetWidth;
    board.style.transition = '';
  }
}

// ----- combat effect animations -----
// Element events (cast / enemy_attack) play per-element asset sprites (a traveling bolt + a hit burst);
// melee (element: null) has no element sprite and keeps a neutral CSS strike. The six elements are fixed.
const DUNGEON_EFFECT_ELEMENTS = ['light', 'dark', 'fire', 'water', 'earth', 'wind'];
// Neutral tint for the melee strike — the only combat effect still drawn from CSS rather than an asset.
const DUNGEON_MELEE_EFFECT_COLOR = '#fff8e6';
// How long a run-ending turn's combat plays before the result screen takes over (one beat for
// the fatal blow; covers a projectile's travel + impact).
const DUNGEON_ENDED_ANIM_MS = 520;
// How long the run result stays on screen before slipping into the loading screen on the way
// back to the room — long enough to read the outcome/gains, short enough to feel snappy.
const DUNGEON_RESULT_HOLD_MS = 1600;
const DUNGEON_ENTER_LOADING_COPY = { title: '実践へ潜ります', status: '同行者との合流と最初の階の生成を待っています。' };
const DUNGEON_EXIT_LOADING_COPY = { title: '自室へ戻ります', status: '探索の後片付けを続けながら自室を開いています。' };
// Routing hub return: the companion dungeon finalize is drained under this loading copy before the hub
// opening starts, so the two never race on the LM pipeline. The destination is the hub, not the room.
const DUNGEON_HUB_RETURN_LOADING_COPY = { title: 'ハブへ戻ります', status: '探索の後片付けを続けながら、ハブへ戻る準備をしています。' };

// Per-element effect sprite URL. The server serves /canonical/* as .png only (no extension/jpg
// fallback), and the element set is fixed — an unknown element fails fast rather than guessing a sprite.
function dungeonEffectAssetUrl(element, part) {
  if (!DUNGEON_EFFECT_ELEMENTS.includes(element)) throw new Error(`dungeon effect: unknown element ${element}`);
  return `/canonical/dungeon/effects/${element}_${part}.png`;
}

// The board-px center where the entity currently at logical tile (x, y) is ACTUALLY drawn — its
// live rect relative to the board, so a token mid tile-slide reports its in-between position rather
// than its destination. Returns null when no live entity sits on that tile (e.g. an emptied target
// tile), so the caller can fall back to the logical tile center.
function dungeonEntityDisplayedCenter(x, y, board) {
  for (const [key, tile] of dungeonEntityTiles) {
    if (tile.x !== x || tile.y !== y) continue;
    const node = dungeonEntityNodes.get(key);
    if (!node) continue;
    const r = node.getBoundingClientRect();
    const b = board.getBoundingClientRect();
    return { x: (r.left + r.width / 2) - b.left, y: (r.top + r.height / 2) - b.top };
  }
  return null;
}

// Renders the just-resolved turn's combat events as short, non-blocking effects so the player
// can see who did what to whom: a projectile/strike travels actor->target (tinted by element
// for casts) and a hit lands a flash on the target. Fire-and-forget; effects self-remove and a
// new turn clears stale ones, so input is never gated. Respects reduced-motion.
//
// Endpoints come from the entity ACTUALLY drawn at the event tile, resolved at spawn time, so a
// cast/melee fired while the actor is still sliding from its previous tile shoots from the visible
// token — not the final logical tile a half-tile ahead (the self-action animation-state race).
function animateDungeonCombat(events) {
  const grid = document.querySelector('#dungeon-grid');
  const board = grid?.querySelector('.dn-board');
  const layer = board?.querySelector('.dn-effects');
  if (!layer) return;
  layer.replaceChildren();
  if (!events || !events.length) return;
  const gap = parseFloat(getComputedStyle(grid).getPropertyValue('--dn-gap'));
  const cell = parseFloat(getComputedStyle(grid).getPropertyValue('--dn-cell'));
  if (!Number.isFinite(gap) || !Number.isFinite(cell)) return;
  const step = cell + gap;
  const center = (n) => n * step + cell / 2;
  // Resolved at spawn time: where the actor/target token is drawn right now (mid-slide), or the
  // logical tile center when no live entity sits there.
  const origin = (x, y) => dungeonEntityDisplayedCenter(x, y, board) ?? { x: center(x), y: center(y) };
  const reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  events.forEach((event, index) => {
    // Stagger so a multi-enemy turn reads as a sequence, capped so tempo stays snappy.
    window.setTimeout(() => spawnDungeonEffect(layer, event, { origin, cell, reduce }), Math.min(index * 70, 280));
  });
}

function spawnDungeonEffect(layer, event, { origin, cell, reduce }) {
  const from = origin(event.from.x, event.from.y);
  const to = origin(event.to.x, event.to.y);
  // Element events (cast / enemy_attack) use per-element asset sprites; melee (element: null) keeps the
  // neutral CSS strike.
  if (event.element != null) spawnDungeonAssetEffect(layer, event, { from, to, cell, reduce });
  else spawnDungeonMeleeEffect(layer, event, { from, to, cell, reduce });
}

// Per-element asset effect: a bolt sprite travels actor->target, then on a hit an impact sprite bursts on
// the target. A miss lands no impact (kept from the prior contract). The bolt travels without orientation
// rotation because the source sprites do not share a consistent forward axis.
function spawnDungeonAssetEffect(layer, event, { from, to, cell, reduce }) {
  const bolt = document.createElement('img');
  bolt.className = 'dn-effect-bolt';
  bolt.alt = '';
  bolt.src = dungeonEffectAssetUrl(event.element, 'bolt');
  bolt.style.left = `${from.x}px`;
  bolt.style.top = `${from.y}px`;
  bolt.style.setProperty('--dn-effect-size', `${Math.round(cell * 0.9)}px`);
  layer.append(bolt);
  const landImpact = () => {
    bolt.remove();
    if (!event.hit) return;
    const impact = document.createElement('img');
    impact.className = 'dn-effect-burst';
    impact.alt = '';
    impact.src = dungeonEffectAssetUrl(event.element, 'impact');
    impact.style.left = `${to.x}px`;
    impact.style.top = `${to.y}px`;
    impact.style.setProperty('--dn-impact-size', `${Math.round(cell * 1.05)}px`);
    layer.append(impact);
    if (reduce) { window.setTimeout(() => impact.remove(), 200); return; }
    impact.animate(
      [{ transform: 'translate(-50%, -50%) scale(0.3)', opacity: 0.95 }, { transform: 'translate(-50%, -50%) scale(1)', opacity: 0 }],
      { duration: 240, easing: 'ease-out' }
    ).onfinish = () => impact.remove();
  };
  if (reduce) { window.setTimeout(landImpact, 0); return; }
  bolt.animate(
    [{ transform: 'translate(-50%, -50%)', left: `${from.x}px`, top: `${from.y}px` }, { transform: 'translate(-50%, -50%)', left: `${to.x}px`, top: `${to.y}px` }],
    { duration: 180, easing: 'ease-in' }
  ).onfinish = landImpact;
}

// Neutral melee strike (no element): the prior CSS orb + ring, tinted neutral. Same travel/impact timing
// and the same reduced-motion / miss contracts as the asset path.
function spawnDungeonMeleeEffect(layer, event, { from, to, cell, reduce }) {
  const projectile = document.createElement('div');
  projectile.className = 'dn-effect dn-effect--melee';
  projectile.style.setProperty('--dn-effect-color', DUNGEON_MELEE_EFFECT_COLOR);
  projectile.style.left = `${from.x}px`;
  projectile.style.top = `${from.y}px`;
  layer.append(projectile);
  const landImpact = () => {
    projectile.remove();
    if (!event.hit) return;
    const impact = document.createElement('div');
    impact.className = 'dn-effect-impact dn-effect-impact--melee';
    impact.style.setProperty('--dn-effect-color', DUNGEON_MELEE_EFFECT_COLOR);
    impact.style.left = `${to.x}px`;
    impact.style.top = `${to.y}px`;
    impact.style.setProperty('--dn-impact-size', `${Math.round(cell * 1.05)}px`);
    layer.append(impact);
    if (reduce) { window.setTimeout(() => impact.remove(), 200); return; }
    impact.animate(
      [{ transform: 'translate(-50%, -50%) scale(0.3)', opacity: 0.95 }, { transform: 'translate(-50%, -50%) scale(1)', opacity: 0 }],
      { duration: 240, easing: 'ease-out' }
    ).onfinish = () => impact.remove();
  };
  if (reduce) { window.setTimeout(landImpact, 0); return; }
  projectile.animate(
    [{ transform: 'translate(-50%, -50%)', left: `${from.x}px`, top: `${from.y}px` }, { transform: 'translate(-50%, -50%)', left: `${to.x}px`, top: `${to.y}px` }],
    { duration: 180, easing: 'ease-in' }
  ).onfinish = landImpact;
}

function dungeonBarEl(label, current, max, modifier) {
  const wrap = document.createElement('div');
  wrap.className = `dn-hud-bar ${modifier}`;
  const name = document.createElement('span');
  name.className = 'dn-hud-bar-label';
  name.textContent = label;
  const track = document.createElement('div');
  track.className = 'dn-hud-bar-track';
  const fill = document.createElement('div');
  fill.className = 'dn-hud-bar-fill';
  fill.style.width = `${max > 0 ? Math.max(0, Math.min(100, Math.round((current / max) * 100))) : 0}%`;
  track.append(fill);
  const value = document.createElement('span');
  value.className = 'dn-hud-bar-value';
  value.textContent = `${current}/${max}`;
  wrap.append(name, track, value);
  return wrap;
}

function dungeonChipEl(label, value) {
  const chip = document.createElement('div');
  chip.className = 'dn-hud-chip';
  const l = document.createElement('span');
  l.className = 'dn-hud-chip-label';
  l.textContent = label;
  const v = document.createElement('strong');
  v.textContent = value;
  chip.append(l, v);
  return chip;
}

// A party-member card: name + HP/MP bars, so the player's and the companion's vitals read side
// by side. A downed companion keeps its bars and adds a 戦闘不能 marker (only an absent companion
// is omitted, by the caller). The name is a clickable button (onNameClick) that opens the actor
// detail — the sole导線 to the detail now the fixed chat header is gone; errors are surfaced, not
// swallowed.
function dungeonActorBars(name, actor, down, onNameClick) {
  const card = document.createElement('div');
  card.className = `dn-hud-actor${down ? ' dn-hud-actor--down' : ''}`;
  // The name and the optional 戦闘不能 marker share one row, so a downed member (or a long name)
  // never adds a line — the card height is constant, keeping the HUD header reflow-stable.
  const head = document.createElement('div');
  head.className = 'dn-hud-actor-head';
  const nameEl = document.createElement('button');
  nameEl.type = 'button';
  nameEl.className = 'dn-hud-actor-name interaction-name-button';
  nameEl.textContent = name;
  nameEl.addEventListener('click', () => { try { onNameClick(); } catch (error) { reportError(error); } });
  head.append(nameEl);
  if (down) {
    const state = document.createElement('span');
    state.className = 'dn-hud-actor-state';
    state.textContent = '戦闘不能';
    head.append(state);
  }
  card.append(head);
  card.append(dungeonBarEl('HP', actor.hp, actor.max_hp, 'dn-hud-bar--hp'));
  card.append(dungeonBarEl('MP', actor.mp, actor.max_mp, 'dn-hud-bar--mp'));
  return card;
}

function renderDungeonHud(view) {
  const node = document.querySelector('#dungeon-hud-status');
  node.replaceChildren();
  node.append(dungeonChipEl('実践', `${view.floor}F / ${view.max_floors}`));
  // The turn climbs every action; tag its chip so the value reserves a digit-count-independent occupancy
  // width (see .dn-hud-chip--turn in style.css). That keeps the party vitals to its right from shifting
  // sideways as the turn grows from 1 to multiple digits.
  const turnChip = dungeonChipEl('ターン', String(view.turn));
  turnChip.classList.add('dn-hud-chip--turn');
  node.append(turnChip);
  // Player and companion vitals in parallel; the companion card is omitted only when solo.
  const party = document.createElement('div');
  party.className = 'dn-hud-party';
  // The party card names are clickable — 主人公 opens the hero detail (能力値＋装備＋獲得予定), a companion
  // opens the companion detail (画像＋能力値＋装備). This is the only导線 to the actor detail now the fixed
  // chat header (and its name-click) is gone.
  party.append(dungeonActorBars('主人公', view.player, false, () => openDungeonHeroDetail()));
  if (view.companion) party.append(dungeonActorBars(view.companion.name, view.companion, view.companion.down, () => openDungeonCompanionDetail(view.companion)));
  node.append(party);
  // Carry-home (pending gains) is intentionally NOT on the header — the hero detail (opened from the 主人公
  // party card name) carries the 獲得予定 section. The header keeps only the 実践 / ターン chips and the
  // party cards, so the freed width goes to the vitals (and the header height stays content-independent).
}

// The full closed set of dungeon action_error codes the engine can surface (move / cast / heal_spell /
// use_item / use_consumable / descend / retreat), each mapped to a player-readable line. A code outside
// this set is a real engine⇄frontend desync, so it throws (fail-fast) rather than silently painting a
// generic message — the new consumable vocabulary is added here alongside the existing movement/combat one.
const DUNGEON_ACTION_ERROR_MESSAGES = {
  blocked: 'そちらへは進めません。',
  not_on_stairs: '階段の上でのみ降りられます。',
  no_target: '視界内に対象がいません。',
  insufficient_mp: 'MP が足りません。',
  hp_full: 'HP はすでに満タンです。',
  no_item: 'そのアイテムを持っていません。',
  unknown_item: 'そのアイテムは使えません。',
  unknown_element: '使えない魔法です。',
  retreat_not_here: '入口または階段の上でのみ撤退できます。',
  invalid_aim: 'そこには投げられません（探索済みの床を狙ってください）。',
  invalid_target: 'その相手には使えません。',
  revive_used: 'この探索では、もう蘇生させられません。',
  unknown_consumable: 'その消耗品は使えません。',
  invalid_consumable: 'その消耗品は使えません。'
};

function dungeonActionErrorText(code) {
  if (!Object.prototype.hasOwnProperty.call(DUNGEON_ACTION_ERROR_MESSAGES, code)) {
    throw new Error(`unknown dungeon action_error code: ${JSON.stringify(code)}`);
  }
  return DUNGEON_ACTION_ERROR_MESSAGES[code];
}

function renderDungeonDock(view) {
  const spells = document.querySelector('#dungeon-spells');
  spells.replaceChildren();
  for (const spell of view.castable_elements ?? []) {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = `dungeon-spell dn-el-${spell.element}`;
    button.innerHTML = `<span class="dungeon-spell-el">${DUNGEON_MAGIC_LABELS[spell.element] ?? spell.element}</span><span class="dungeon-spell-mp">MP${spell.mp_cost}</span>`;
    button.title = `${spell.label} 威力${spell.power} / MP${spell.mp_cost}`;
    button.disabled = view.player.mp < spell.mp_cost;
    button.addEventListener('click', () => dungeonDo({ type: 'cast', element: spell.element }).catch(reportError));
    spells.append(button);
  }
  // The action row holds, on a single line, the self-heal plus the composite 貫通/回避 spells (order:
  // 回復・貫通・回避). renderDungeonDock owns the row: it clears it, appends the self-heal, then defers the
  // composite pair to renderDungeonCompositeSpells. Every button's label and enabled state come straight from
  // its engine-supplied view state (view.healing_spell / view.pierce_spell / view.evasion_spell) — the front
  // end never recomputes the heal amount, MP cost, power or duration. A missing contract fails fast (no silent
  // fallback) rather than dropping the button quietly.
  const actionSlot = document.querySelector('#dungeon-actions');
  actionSlot.replaceChildren();
  const healing = view.healing_spell;
  if (!healing) throw new Error('dungeon view is missing healing_spell');
  // Validate the full engine contract shape (action_type, mp_cost, heal_amount, recoverable_hp, can_use):
  // a malformed view.healing_spell — even a field the button does not display — fails fast.
  const { action_type, mp_cost, heal_amount, recoverable_hp, can_use } = healing;
  if (
    action_type !== 'heal_spell'
    || typeof mp_cost !== 'number'
    || typeof heal_amount !== 'number'
    || typeof recoverable_hp !== 'number'
    || typeof can_use !== 'boolean'
  ) {
    throw new Error('dungeon healing_spell is missing required fields');
  }
  const healButton = document.createElement('button');
  healButton.type = 'button';
  healButton.className = 'dungeon-spell dungeon-spell-heal';
  healButton.innerHTML = `<span class="dungeon-spell-el">回復</span><span class="dungeon-spell-mp">MP${mp_cost}</span>`;
  healButton.title = `自己回復 +${heal_amount} / MP${mp_cost}`;
  // can_use already encodes both MP sufficiency and "there is HP to recover" (full HP -> disabled).
  healButton.disabled = !can_use;
  healButton.addEventListener('click', () => dungeonDo({ type: action_type }).catch(reportError));
  actionSlot.append(healButton);
  // Composite spells (貫通 / 回避) follow the self-heal on the same action row, each rendered straight from its
  // engine-supplied state (view.pierce_spell / view.evasion_spell) — the front end never recomputes power,
  // cost or duration. A missing/malformed state fails fast (no silent fallback / dropped button).
  renderDungeonCompositeSpells(view);
  // The action log shows the full run history and scrolls; movement, 待機 (Space) and 階段を
  // 降りる (Enter) are keyboard actions now, so there are no dock buttons to gate.
  const log = document.querySelector('#dungeon-log');
  const atBottom = log.scrollHeight - log.scrollTop - log.clientHeight < 4;
  log.replaceChildren();
  for (const entry of view.log ?? []) {
    const p = document.createElement('p');
    p.textContent = entry;
    log.append(p);
  }
  if (view.action_error) {
    const note = document.createElement('p');
    note.className = 'dungeon-log-note';
    note.textContent = dungeonActionErrorText(view.action_error);
    log.append(note);
  }
  // Follow the newest line unless the player has scrolled up to read back the history.
  if (atBottom) log.scrollTop = log.scrollHeight;
}

// Appends the 貫通 / 回避 composite-spell buttons to the shared action row (after the self-heal), from their
// engine-supplied view states. renderDungeonDock has already cleared the row and appended the self-heal, so
// this only appends. Each state's full contract is validated (fail-fast, like the self-heal), and 回避's
// active state shows the remaining turns.
function renderDungeonCompositeSpells(view) {
  const slot = document.querySelector('#dungeon-actions');

  const pierce = view.pierce_spell;
  if (!pierce) throw new Error('dungeon view is missing pierce_spell');
  if (
    pierce.action_type !== 'pierce_spell'
    || typeof pierce.mp_cost !== 'number'
    || typeof pierce.power !== 'number'
    || typeof pierce.can_use !== 'boolean'
  ) {
    throw new Error('dungeon pierce_spell is missing required fields');
  }
  const pierceButton = document.createElement('button');
  pierceButton.type = 'button';
  pierceButton.className = 'dungeon-spell dungeon-spell-pierce';
  pierceButton.innerHTML = `<span class="dungeon-spell-el">貫通</span><span class="dungeon-spell-mp">MP${pierce.mp_cost}</span>`;
  pierceButton.title = `貫通魔法（防御無視）威力${pierce.power} / MP${pierce.mp_cost}`;
  pierceButton.disabled = !pierce.can_use;
  pierceButton.addEventListener('click', () => dungeonDo({ type: pierce.action_type }).catch(reportError));
  slot.append(pierceButton);

  const evasion = view.evasion_spell;
  if (!evasion) throw new Error('dungeon view is missing evasion_spell');
  if (
    evasion.action_type !== 'evasion_spell'
    || typeof evasion.mp_cost !== 'number'
    || typeof evasion.duration !== 'number'
    || typeof evasion.evasion_bonus !== 'number'
    || typeof evasion.turns_remaining !== 'number'
    || typeof evasion.active !== 'boolean'
    || typeof evasion.can_use !== 'boolean'
  ) {
    throw new Error('dungeon evasion_spell is missing required fields');
  }
  const evasionButton = document.createElement('button');
  evasionButton.type = 'button';
  evasionButton.className = 'dungeon-spell dungeon-spell-evasion';
  if (evasion.active) evasionButton.classList.add('is-active');
  const evasionLabel = evasion.active ? `回避 (残${evasion.turns_remaining})` : '回避';
  evasionButton.innerHTML = `<span class="dungeon-spell-el">${evasionLabel}</span><span class="dungeon-spell-mp">MP${evasion.mp_cost}</span>`;
  evasionButton.title = evasion.active
    ? `回避魔法（発動中・残り${evasion.turns_remaining}ターン）回避+${evasion.evasion_bonus} / MP${evasion.mp_cost}`
    : `回避魔法（${evasion.duration}ターン）回避+${evasion.evasion_bonus} / MP${evasion.mp_cost}`;
  evasionButton.disabled = !evasion.can_use;
  evasionButton.addEventListener('click', () => dungeonDo({ type: evasion.action_type }).catch(reportError));
  slot.append(evasionButton);
}

// ----- dungeon consumables (use owned alchemy dungeon_consumable items mid-run) -----
// view.consumables is the engine-authoritative list of owned dungeon consumables (item_id-sorted, only
// what is in the inventory — quantity 0 rows are absent by contract). Each row carries {item_id, name,
// description, effect_kind, target_mode, quantity, …kind tunables}. The band renders one chip per row; the
// chip's click resolves the row's target_mode: 'auto'/'revive' fire at once, 'aim' arms board targeting,
// 'ally' opens a self/companion pick. attack effects reuse the existing {kind:'cast'} events (no new
// animation code); heal/revive land as log lines.

// The compact effect summary shown on a consumable chip. effect_kind is a closed engine set — an unknown
// kind is a desync and throws (no silent generic label).
function dungeonConsumableSummaryText(row) {
  const element = DUNGEON_MAGIC_LABELS[row.element] ?? row.element;
  switch (row.effect_kind) {
    case 'attack_single': return `${element}・単体 威力${row.power}`;
    case 'attack_area': return `${element}・範囲${row.radius} 威力${row.power}`;
    case 'heal': return `HP+${row.heal_amount}`;
    case 'heal_full': return 'HP全回復';
    case 'mp_restore': return `MP+${row.mp_amount}`;
    case 'mp_restore_full': return 'MP全回復';
    case 'revive': return '同行者を蘇生';
    default: throw new Error(`unknown consumable effect_kind: ${JSON.stringify(row.effect_kind)}`);
  }
}

// Whether a chip is disabled at render time, with the reason (title) and an optional inline note. Only
// revive is render-gated (needs a downed companion and an unspent per-run revive — view.revive_used). Every
// other kind stays enabled and lets the server resolve its own guard into a turn-non-consuming action_error.
function dungeonConsumableDisabledState(view, row) {
  if (row.target_mode === 'revive') {
    if (view.revive_used) return { disabled: true, reason: 'この探索では蘇生を使い切りました。', note: '使い切り' };
    if (!view.companion || !view.companion.down) return { disabled: true, reason: 'ダウン中の同行者がいません。', note: '対象なし' };
  }
  return { disabled: false, reason: '', note: '' };
}

function buildDungeonConsumableChip(view, row) {
  const button = document.createElement('button');
  button.type = 'button';
  button.className = 'dungeon-consumable';
  button.dataset.itemId = row.item_id;
  button.dataset.targetMode = row.target_mode;
  // Attack consumables carry an element; reuse the shared per-element hue class so the chip border is tinted
  // by attribute exactly like the spell pills (the .dn-el-* classes only set `color`, which the chip's
  // currentColor border consumes — the name/summary keep their own ink tokens).
  if (row.element) button.classList.add(`dn-el-${row.element}`);
  const state = dungeonConsumableDisabledState(view, row);
  button.disabled = state.disabled;
  if (state.reason) button.title = state.reason;
  if (dungeonConsumableTargeting?.item_id === row.item_id) button.dataset.armed = 'true';

  const name = document.createElement('span');
  name.className = 'dungeon-consumable-name';
  name.textContent = row.name;
  const summary = document.createElement('span');
  summary.className = 'dungeon-consumable-summary';
  summary.textContent = dungeonConsumableSummaryText(row);
  const qty = document.createElement('span');
  qty.className = 'dungeon-consumable-qty';
  qty.textContent = `×${row.quantity}`;
  button.append(name, summary, qty);
  if (state.disabled && state.note) {
    const note = document.createElement('span');
    note.className = 'dungeon-consumable-note';
    note.textContent = state.note;
    button.append(note);
  }
  button.addEventListener('click', () => { try { onDungeonConsumableClick(view, row); } catch (error) { reportError(error); } });
  return button;
}

// ----- dungeon item columns (持ち込んだアイテム / 拾ったアイテム / 拾った素材) -----
// The play screen keeps all three item columns visible side by side, always-on (no menu needed): the
// 持ち込んだアイテム column lists view.consumables with the full use flow, the 拾ったアイテム column lists
// the run's floor pickups (view.inventory) with the use_item flow, and the 拾った素材 column mirrors
// view.material_buffer (display-only). Every column shares one shape (label + fixed-height, internally
// scrolling list + quiet empty state), and each is independent of its siblings, so a brought-only surface
// (e.g. the arena) renders just the consumables column and it still stands alone. A missing view contract
// on any column fail-fasts.

// Fill one item column's scrolling list: a row per entry, or a single quiet empty note. Shared by every
// dungeon column and reusable by any brought-only surface (each column is independent of its siblings).
function fillDungeonItemColumn(listEl, rows, buildRow, emptyText) {
  if (rows.length === 0) {
    const empty = document.createElement('p');
    empty.className = 'dungeon-item-column-empty';
    empty.textContent = emptyText;
    listEl.replaceChildren(empty);
    return;
  }
  listEl.replaceChildren(...rows.map(buildRow));
}

// One 拾った素材 row: the server-authoritative display name + picked-up count. Display only — the
// materials are banked on retreat, not used mid-run. A mis-shaped buffer item is a broken contract and throws.
function buildDungeonMaterialRow(item) {
  if (typeof item.display_name !== 'string' || item.display_name === '') {
    throw new Error(`dungeon material requires a non-empty display_name, got ${JSON.stringify(item)}`);
  }
  if (typeof item.quantity !== 'number' || !Number.isFinite(item.quantity)) {
    throw new Error(`dungeon material requires a numeric quantity, got ${JSON.stringify(item)}`);
  }
  const row = document.createElement('div');
  row.className = 'dungeon-item-row';
  const name = document.createElement('span');
  name.className = 'dungeon-item-row-name';
  name.textContent = item.display_name;
  const qty = document.createElement('span');
  qty.className = 'dungeon-item-row-qty';
  qty.textContent = `×${item.quantity.toLocaleString('ja-JP')}`;
  row.append(name, qty);
  return row;
}

// Renders the 拾った素材 column from view.material_buffer (item_id-sorted, server display names). An empty
// buffer keeps the column with a quiet empty note. A missing contract is a desync and throws (fail-fast).
function renderDungeonMaterials(view) {
  const list = document.querySelector('#dungeon-materials-list');
  if (!list) return;
  const buffer = view.material_buffer;
  if (!Array.isArray(buffer)) throw new Error('dungeon view is missing material_buffer');
  fillDungeonItemColumn(list, buffer, buildDungeonMaterialRow, 'まだ拾った素材はありません。');
}

// One 拾ったアイテム row: a floor pickup (癒し草 等) as a use button carrying its owned count. A click uses
// the item through the shared dungeonDo path (use_item by kind) — the single use route now that the menu
// inventory popup is gone (turn cost / effect / log stay the engine's existing use_item behavior). A
// mis-shaped inventory entry is a broken contract and throws (no silent skip of an unusable-looking row).
function buildDungeonPickupRow(item) {
  if (typeof item.kind !== 'string' || item.kind === '') {
    throw new Error(`dungeon inventory item requires a non-empty kind, got ${JSON.stringify(item)}`);
  }
  if (typeof item.name !== 'string' || item.name === '') {
    throw new Error(`dungeon inventory item requires a non-empty name, got ${JSON.stringify(item)}`);
  }
  if (typeof item.count !== 'number' || !Number.isFinite(item.count)) {
    throw new Error(`dungeon inventory item requires a numeric count, got ${JSON.stringify(item)}`);
  }
  const button = document.createElement('button');
  button.type = 'button';
  button.className = 'dungeon-item-use-row';
  button.dataset.itemKind = item.kind;
  const name = document.createElement('span');
  name.className = 'dungeon-item-row-name';
  name.textContent = item.name;
  const qty = document.createElement('span');
  qty.className = 'dungeon-item-row-qty';
  qty.textContent = `×${item.count.toLocaleString('ja-JP')}`;
  button.append(name, qty);
  button.addEventListener('click', () => { dungeonDo({ type: 'use_item', item_kind: item.kind }).catch(reportError); });
  return button;
}

// Renders the 拾ったアイテム column from view.inventory (the run's floor pickups, {kind,name,glyph,count}).
// An empty list keeps the column with a quiet empty note rather than collapsing — the region height is fixed
// in CSS so its content never changes the stage height (and thus the camera cell size). A missing/mis-typed
// inventory contract is a desync and throws (fail-fast, never a silent empty column).
function renderDungeonPickups(view) {
  const list = document.querySelector('#dungeon-pickups-list');
  if (!list) return;
  if (!Array.isArray(view.inventory)) throw new Error('dungeon view is missing inventory');
  fillDungeonItemColumn(list, view.inventory, buildDungeonPickupRow, 'まだ拾ったアイテムはありません。');
}

// Renders the 持ち込んだアイテム column from view.consumables. An empty list keeps the column with an explicit
// empty note rather than collapsing — the region height is fixed in CSS so its content never changes the
// stage height (and thus the camera cell size). A missing consumables contract is a desync and throws.
function renderDungeonConsumables(view) {
  const list = document.querySelector('#dungeon-consumables-list');
  if (!list) return;
  if (!Array.isArray(view.consumables)) throw new Error('dungeon view is missing consumables');
  fillDungeonItemColumn(list, view.consumables, (row) => buildDungeonConsumableChip(view, row), '持ち込んだ消耗品はありません。');
}

// A chip click: re-clicking the armed chip cancels its targeting; otherwise cancel any active targeting and
// resolve this chip's target_mode. auto/revive fire immediately (no extra input); aim/ally collect input first.
function onDungeonConsumableClick(view, row) {
  if (dungeonActionInFlight) { showProcessingToast(); return; }
  if (dungeonConsumableTargeting?.item_id === row.item_id) { cancelDungeonConsumableTargeting(); return; }
  cancelDungeonConsumableTargeting();
  if (row.target_mode === 'auto' || row.target_mode === 'revive') { useDungeonConsumable(row.item_id); return; }
  if (row.target_mode === 'aim') { enterDungeonAimMode(view, row); return; }
  if (row.target_mode === 'ally') { openDungeonAllyTargetPrompt(view, row); return; }
  throw new Error(`unknown consumable target_mode: ${JSON.stringify(row.target_mode)}`);
}

// Sends a use_consumable action, folding in any collected target/aim argument, then tears down targeting.
// dungeonDo re-renders the board (and the consumables band) with the fresh count / action_error.
function useDungeonConsumable(itemId, extra = {}) {
  teardownDungeonConsumableTargeting();
  dungeonDo({ type: 'use_consumable', item_id: itemId, ...extra }).catch(reportError);
}

// ── attack_area aim mode ─────────────────────────────────────────────────────────────────────────────────
// Arming an aim consumable lays an interactive tile grid over the board (inside the camera transform, so it
// aligns to the tiles) that highlights the legal landing tiles and, on hover, the Manhattan-radius blast. A
// click on a legal tile sends aim:{x,y}; an illegal tile is inert (client-blocked — the server is the final
// defense). Esc / re-clicking the chip / the 中止 button cancel.
function enterDungeonAimMode(view, row) {
  dungeonConsumableTargeting = { item_id: row.item_id, mode: 'aim', radius: row.radius, element: row.element, name: row.name };
  buildDungeonAimOverlay(view, row);
  document.querySelector('#dungeon-grid')?.classList.add('dn-aiming');
  showDungeonConsumablePrompt(`「${row.name}」の着弾点を選んでください（Escで中止）。`, [
    { label: '中止', onClick: () => cancelDungeonConsumableTargeting() }
  ]);
  renderDungeonConsumables(view);
}

// Mirrors the engine's line-of-sight walk (dungeonEngine.hasLineOfSight): the rounded cells strictly between
// player and target must all be floor. Kept identical so the client pre-filter matches the server's aim gate.
function dungeonHasLineOfSight(view, from, to) {
  const dx = to.x - from.x;
  const dy = to.y - from.y;
  const steps = Math.max(Math.abs(dx), Math.abs(dy));
  for (let step = 1; step < steps; step += 1) {
    const x = Math.round(from.x + (dx * step) / steps);
    const y = Math.round(from.y + (dy * step) / steps);
    if (x < 0 || y < 0 || x >= view.width || y >= view.height || view.tiles[y][x] !== 'floor') return false;
  }
  return true;
}

// A legal attack_area landing tile: in bounds, explored, walkable (floor), and with clear line of sight from
// the player — the same set planConsumable accepts (invalid_aim for the first three, blocked for LoS).
function dungeonAimTileValid(view, x, y) {
  if (x < 0 || y < 0 || x >= view.width || y >= view.height) return false;
  if (!view.explored[y][x]) return false;
  if (view.tiles[y][x] !== 'floor') return false;
  return dungeonHasLineOfSight(view, view.player, { x, y });
}

function buildDungeonAimOverlay(view, row) {
  const board = document.querySelector('#dungeon-grid .dn-board');
  if (!board) return;
  removeDungeonAimOverlay();
  const layer = document.createElement('div');
  layer.className = 'dn-aim';
  layer.style.setProperty('--dn-cols', view.width);
  layer.style.setProperty('--dn-rows', view.height);
  const cells = [];
  for (let y = 0; y < view.height; y += 1) {
    for (let x = 0; x < view.width; x += 1) {
      const cell = document.createElement('div');
      cell.className = 'dn-aim-cell';
      cell.dataset.x = x;
      cell.dataset.y = y;
      if (dungeonAimTileValid(view, x, y)) cell.classList.add('dn-aim-valid');
      cells.push(cell);
    }
  }
  layer.replaceChildren(...cells);
  layer.addEventListener('pointermove', (event) => onDungeonAimHover(event, row));
  layer.addEventListener('pointerleave', () => clearDungeonAimBlast());
  layer.addEventListener('click', (event) => { try { onDungeonAimClick(event, row); } catch (error) { reportError(error); } });
  board.append(layer);
}

function removeDungeonAimOverlay() {
  document.querySelector('#dungeon-grid .dn-aim')?.remove();
}

// Paint the Manhattan-radius blast preview centered on the hovered legal tile; hovering off a legal tile
// (a wall, fog, or the gap between cells) clears it.
function onDungeonAimHover(event, row) {
  const cell = event.target.closest('.dn-aim-cell');
  if (!cell || !cell.classList.contains('dn-aim-valid')) { clearDungeonAimBlast(); return; }
  paintDungeonAimBlast(row, Number(cell.dataset.x), Number(cell.dataset.y));
}

function paintDungeonAimBlast(row, cx, cy) {
  clearDungeonAimBlast();
  const layer = document.querySelector('#dungeon-grid .dn-aim');
  if (!layer) return;
  for (const cell of layer.querySelectorAll('.dn-aim-cell')) {
    const distance = Math.abs(Number(cell.dataset.x) - cx) + Math.abs(Number(cell.dataset.y) - cy);
    if (distance <= row.radius) cell.classList.add('dn-aim-blast');
  }
}

function clearDungeonAimBlast() {
  const layer = document.querySelector('#dungeon-grid .dn-aim');
  if (!layer) return;
  for (const cell of layer.querySelectorAll('.dn-aim-blast')) cell.classList.remove('dn-aim-blast');
}

// Click a landing tile: an illegal tile is not sent (client-side block); a legal tile fires aim:{x,y}.
function onDungeonAimClick(event, row) {
  if (dungeonActionInFlight) return;
  const cell = event.target.closest('.dn-aim-cell');
  if (!cell || !cell.classList.contains('dn-aim-valid')) return;
  useDungeonConsumable(row.item_id, { aim: { x: Number(cell.dataset.x), y: Number(cell.dataset.y) } });
}

// ── heal / MP ally pick ──────────────────────────────────────────────────────────────────────────────────
// Arming a heal/MP consumable opens the target prompt: 主人公 is always a valid target; the companion button
// is offered only when a living (non-down) companion is present — absent/down disables it (revive is the only
// path for a downed companion). The pick sends target:'player'|'companion'.
function openDungeonAllyTargetPrompt(view, row) {
  dungeonConsumableTargeting = { item_id: row.item_id, mode: 'ally', name: row.name };
  const companionUsable = !!view.companion && !view.companion.down;
  const companionTitle = !view.companion
    ? '同行者がいません。'
    : (view.companion.down ? '同行者はダウン中です（蘇生が必要）。' : '');
  showDungeonConsumablePrompt(`「${row.name}」を誰に使いますか？`, [
    { label: '主人公', onClick: () => useDungeonConsumable(row.item_id, { target: 'player' }) },
    {
      label: view.companion ? view.companion.name : '同行者',
      onClick: () => useDungeonConsumable(row.item_id, { target: 'companion' }),
      disabled: !companionUsable,
      title: companionTitle
    },
    { label: '中止', onClick: () => cancelDungeonConsumableTargeting() }
  ]);
  renderDungeonConsumables(view);
}

// ── prompt banner + teardown ─────────────────────────────────────────────────────────────────────────────
function showDungeonConsumablePrompt(text, actions) {
  const prompt = document.querySelector('#dungeon-consumable-prompt');
  if (!prompt) return;
  const message = document.createElement('span');
  message.className = 'dungeon-consumable-prompt-text';
  message.textContent = text;
  const actionRow = document.createElement('span');
  actionRow.className = 'dungeon-consumable-prompt-actions';
  for (const action of actions) {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'dungeon-consumable-prompt-action';
    button.textContent = action.label;
    if (action.disabled) button.disabled = true;
    if (action.title) button.title = action.title;
    button.addEventListener('click', () => { try { action.onClick(); } catch (error) { reportError(error); } });
    actionRow.append(button);
  }
  prompt.replaceChildren(message, actionRow);
  prompt.hidden = false;
}

// Clears targeting state, the aim overlay, the aim cursor, and the prompt — without re-rendering the band.
// Used by renderDungeonPlay (a fresh view invalidates any in-progress targeting) and by cancel below.
function teardownDungeonConsumableTargeting() {
  dungeonConsumableTargeting = null;
  removeDungeonAimOverlay();
  document.querySelector('#dungeon-grid')?.classList.remove('dn-aiming');
  const prompt = document.querySelector('#dungeon-consumable-prompt');
  if (prompt) { prompt.hidden = true; prompt.replaceChildren(); }
}

// Cancels active targeting and re-renders the band so the armed marker clears.
function cancelDungeonConsumableTargeting() {
  const wasTargeting = dungeonConsumableTargeting !== null;
  teardownDungeonConsumableTargeting();
  if (wasTargeting && currentDungeonView) renderDungeonConsumables(currentDungeonView);
}

function renderDungeonChat(view) {
  const chat = document.querySelector('#dungeon-chat');
  if (!view) {
    chat.hidden = true;
    return;
  }
  // Always-on during a run: the conversation panel keeps its rail slot whether or not a companion is
  // present (no toggle). The fixed chat header (companion face / name / ability bars) is gone — the
  // party card names in the HUD open the actor detail now. With no companion the panel shows an explicit
  // empty, disabled state in the log area (fail-closed: inputs disabled, no silent empty send) rather
  // than collapsing the layout.
  chat.hidden = false;
  const log = document.querySelector('#dungeon-chat-log');
  if (!view.companion) {
    const empty = document.createElement('p');
    empty.className = 'dungeon-chat-empty';
    empty.textContent = '同行者はいません';
    log.replaceChildren(empty);
    document.querySelector('#dungeon-talk-send').disabled = true;
    document.querySelector('#dungeon-talk-input').disabled = true;
    return;
  }
  // A homunculus companion keeps its per-message avatar override inside renderDungeonChatLog
  // (applyDungeonCompanionMessageFace); a selectable companion uses the shared row builder. Neither needs a
  // roster lookup here anymore — the name-click detail (from the HUD) resolves the roster itself.
  renderDungeonChatLog(dungeonChatMessages);
  document.querySelector('#dungeon-talk-send').disabled = view.companion.down;
  document.querySelector('#dungeon-talk-input').disabled = view.companion.down;
}

// ── unified actor-detail shell ───────────────────────────────────────────────────────────────────────────
// The shared section grammar for a run-time actor detail, screen-agnostic so the arena mirror can reuse it: an
// optional image slot (companion only — selectable standee / homunculus face; the hero has none), the 11-value
// parameters, the read-only equipment, and (dungeon hero only) the 獲得予定 section. The structural class names
// (actor-detail-*) are shared; each screen scopes its own token layer via the host container (dungeon = the
// #dungeon-actor-detail #academy-dungeon-screen scope consuming --dungeon-*, arena its own). The caller builds
// each section's inner nodes with its own builders (so the equipment card can reuse a screen-specific renderer);
// this shell only lays out the section grammar. A null image / acquisition node omits that section.
function buildActorDetailBody({ imageNode = null, parameterNodes, equipmentNode, acquisitionNode = null }) {
  const sections = document.createElement('div');
  sections.className = 'actor-detail-sections';
  if (imageNode) sections.append(buildActorDetailSection(null, [imageNode], 'actor-detail-image-section'));
  sections.append(buildActorDetailSection('能力値', parameterNodes, 'actor-detail-parameters-section'));
  sections.append(buildActorDetailSection('装備', [equipmentNode], 'actor-detail-equipment-section'));
  if (acquisitionNode) sections.append(buildActorDetailSection('獲得予定', [acquisitionNode], 'actor-detail-acquisition-section'));
  return sections;
}

function buildActorDetailSection(heading, nodes, modifierClass) {
  const section = document.createElement('section');
  section.className = `actor-detail-section${modifierClass ? ` ${modifierClass}` : ''}`;
  if (heading) {
    const head = document.createElement('h4');
    head.className = 'actor-detail-section-head';
    head.textContent = heading;
    section.append(head);
  }
  section.append(...nodes);
  return section;
}

// The companion image slot: a selectable companion's scene standee (portrait aspect) or a homunculus's face
// (1:1), shaped by the modifier. A missing/broken source hides the image (the shared error handler) rather than
// showing a broken-image icon.
function buildActorDetailImage({ src, alt, shape }) {
  const figure = document.createElement('figure');
  figure.className = `actor-detail-image-frame actor-detail-image-frame--${shape}`;
  const img = document.createElement('img');
  img.className = 'actor-detail-image';
  img.alt = alt;
  hideImageOnError(img);
  img.style.visibility = '';
  setActorImageSource(img, src);
  figure.append(img);
  return figure;
}

// The read-only equipment section for the detail shell: the weapon + amulet slots, each an equipped-instance
// detail (reusing the shared read-only inner builder — NO 解除 button) or a quiet 未装備 note. runEquipment is the
// run-view equipment snapshot (null when nothing is equipped, else {slots:{weapon,amulet}, effects}); its slots
// are validated fail-fast (a malformed slot throws before the DOM is touched — no half-rendered card).
function buildDungeonDetailEquipment(runEquipment) {
  const slots = runEquipment === null
    ? { weapon: null, amulet: null }
    : validateDungeonEquipmentSlots(runEquipment.slots, 'dungeon detail equipment');
  const wrap = document.createElement('div');
  wrap.className = 'actor-detail-equipment';
  for (const slot of WORKSHOP_EQUIPMENT_KINDS) {
    const card = document.createElement('div');
    card.className = 'actor-detail-equipment-slot';
    card.dataset.slot = slot;
    const head = document.createElement('p');
    head.className = 'actor-detail-equipment-slot-head';
    head.textContent = `${workshopKindLabel(slot)}スロット`;
    card.append(head);
    const view = slots[slot];
    if (view) {
      card.append(buildDungeonEquipmentInstanceDetail(view));
    } else {
      const empty = document.createElement('p');
      empty.className = 'actor-detail-equipment-empty';
      empty.textContent = '未装備';
      card.append(empty);
    }
    wrap.append(card);
  }
  return wrap;
}

// The hero's 獲得予定 section (dungeon only): the pending stat gains (上昇能力) and the boss-chest equipment banked
// this run (獲得予定装備). Same grammar the removed 持ち帰り popup used, now folded into the hero detail. The
// equipment buffer is a required run-view field (throws if missing — fail-fast).
function buildDungeonDetailAcquisition(view) {
  const wrap = document.createElement('div');
  wrap.className = 'actor-detail-acquisition';

  const preview = view.pending_gains_preview ?? { magic: {}, abilities: {} };
  const gainEntries = [
    ...Object.entries(preview.magic).map(([key, value]) => ({ label: DUNGEON_MAGIC_LABELS[key] ?? key, value })),
    ...Object.entries(preview.abilities).map(([key, value]) => ({ label: DUNGEON_ABILITY_LABELS[key] ?? key, value }))
  ];
  const gains = document.createElement('div');
  gains.className = 'dungeon-gains-section';
  const gainsHead = document.createElement('p');
  gainsHead.className = 'dungeon-gains-subhead';
  gainsHead.textContent = '上昇能力';
  gains.append(gainsHead);
  if (gainEntries.length) {
    const grid = document.createElement('div');
    grid.className = 'dungeon-gains-grid';
    for (const entry of gainEntries) {
      const row = document.createElement('div');
      row.className = 'dungeon-gains-row';
      const name = document.createElement('span');
      name.className = 'dungeon-gains-name';
      name.textContent = entry.label;
      const amount = document.createElement('strong');
      amount.className = 'dungeon-gains-amount';
      amount.textContent = `+${entry.value}`;
      row.append(name, amount);
      grid.append(row);
    }
    gains.append(grid);
  } else {
    const empty = document.createElement('p');
    empty.className = 'dungeon-gains-empty';
    empty.textContent = 'まだ持ち帰る能力上昇はありません。';
    gains.append(empty);
  }
  wrap.append(gains);

  const equipmentBuffer = view.equipment_buffer;
  if (!Array.isArray(equipmentBuffer)) throw new Error('dungeon view is missing equipment_buffer');
  const equipment = document.createElement('div');
  equipment.className = 'dungeon-gains-section';
  const equipmentHead = document.createElement('p');
  equipmentHead.className = 'dungeon-gains-subhead';
  equipmentHead.textContent = '獲得予定装備';
  equipment.append(equipmentHead);
  equipment.append(...buildDungeonEquipmentRows(equipmentBuffer, 'まだ手に入れた装備はありません。'));
  wrap.append(equipment);

  return wrap;
}

// Opens the unified actor-detail shell. The body is built (which validates the equipment slots / acquisition
// contract) BEFORE the shell is shown, so a broken contract throws without leaving a half-open dialog; the
// click handler's reportError surfaces it. Missing shell markup is broken wiring — fail fast.
function openDungeonActorDetail(title, bodyNode) {
  const popup = document.querySelector('#dungeon-actor-detail');
  const titleEl = document.querySelector('#dungeon-actor-detail-title');
  const body = document.querySelector('#dungeon-actor-detail-body');
  if (!popup || !titleEl || !body) {
    throw new Error('dungeon actor detail shell nodes are missing (broken markup wiring)');
  }
  titleEl.textContent = title;
  body.replaceChildren(bodyNode);
  popup.hidden = false;
}

function closeDungeonActorDetail() {
  const popup = document.querySelector('#dungeon-actor-detail');
  if (!popup) {
    throw new Error('dungeon actor detail shell node #dungeon-actor-detail is missing (broken markup wiring)');
  }
  popup.hidden = true;
}

// The hero (主人公) detail: no image, the 11 raw parameters (currentWorld.player_parameters — the same source the
// old stats popup used), the read-only equipment, and the 獲得予定 section (上昇能力 + 獲得予定装備). No HP/MP,
// no combat-reflected values (per the confirmed layout). All from the run view / page world state — no fetch.
function openDungeonHeroDetail() {
  const view = currentDungeonView;
  if (!view) return;
  const params = currentWorld?.player_parameters ?? {};
  const body = buildActorDetailBody({
    parameterNodes: buildParameterGroups(params),
    equipmentNode: buildDungeonDetailEquipment(view.equipment),
    acquisitionNode: buildDungeonDetailAcquisition(view)
  });
  openDungeonActorDetail('主人公', body);
}

// The companion detail: its image (selectable = scene standee resolved from the roster; homunculus = the
// entry-snapshot face_url), the 11 parameters, and the read-only equipment — no 獲得予定 (the carry-home is the
// hero's). A selectable companion resolves its roster character (a miss is a real desync — fail fast, same
// message as before); a homunculus draws its face + parameters from the run view companion (no extra fetch).
function openDungeonCompanionDetail(companion) {
  const homunculus = dungeonCompanionIsHomunculus(companion);
  let parameters;
  let image;
  if (homunculus) {
    parameters = companion.parameters;
    image = { src: companion.face_url, alt: `${companion.name}の顔`, shape: 'face' };
  } else {
    const character = selectableCharacters.find((item) => item.character_id === companion.character_id);
    if (!character) throw new Error(`dungeon companion not found in character roster: ${companion.character_id}`);
    parameters = character.parameters;
    image = { src: characterSceneStandeeUrl(character), alt: `${character.display_name ?? character.character_id}の一枚絵`, shape: 'standee' };
  }
  const body = buildActorDetailBody({
    imageNode: buildActorDetailImage(image),
    parameterNodes: buildParameterGroups(parameters),
    equipmentNode: buildDungeonDetailEquipment(companion.equipment),
    acquisitionNode: null
  });
  openDungeonActorDetail(companion.name, body);
}

// ----- popups (menu / inventory / stats / help / retreat / full log) -----

function showDungeonPopup(title, bodyEl) {
  document.querySelector('#dungeon-popup-title').textContent = title;
  document.querySelector('#dungeon-popup-body').replaceChildren(bodyEl);
  document.querySelector('#dungeon-popup').hidden = false;
}

function closeDungeonPopup() {
  document.querySelector('#dungeon-popup').hidden = true;
}

// Builds the 獲得装備 rows (銘 + meta line) for an equipment instance list, or an explicit empty note.
// Shared by the hero detail's 獲得予定 section (mid-run buffer) and the run-end result (retained/lost) so both
// render the same row grammar. A non-array items input is a broken contract and throws.
function buildDungeonEquipmentRows(items, emptyText) {
  if (!Array.isArray(items)) throw new Error(`dungeon equipment rows require an items array, got ${JSON.stringify(items)}`);
  if (items.length === 0) {
    const empty = document.createElement('p');
    empty.className = 'dungeon-gains-empty';
    empty.textContent = emptyText;
    return [empty];
  }
  const grid = document.createElement('div');
  grid.className = 'dungeon-gains-grid dungeon-equipment-grid';
  for (const item of items) {
    if (typeof item.name !== 'string' || item.name === '') {
      throw new Error(`dungeon equipment row requires a non-empty name, got ${JSON.stringify(item)}`);
    }
    const row = document.createElement('div');
    row.className = 'dungeon-gains-row dungeon-equipment-row';
    const name = document.createElement('span');
    name.className = 'dungeon-gains-name dungeon-equipment-name';
    name.textContent = item.name;
    const meta = document.createElement('span');
    meta.className = 'dungeon-gains-amount dungeon-equipment-meta';
    meta.textContent = dungeonEquipmentInstanceMetaText(item);
    row.append(name, meta);
    grid.append(row);
  }
  return [grid];
}

function openDungeonHelp() {
  const body = document.createElement('div');
  body.className = 'dungeon-help';
  body.innerHTML = `
    <p>矢印キー / 方向ボタンで移動。敵に向かって進むと攻撃します。</p>
    <p>魔法は視界内の最も近い敵に当たります（MP 消費）。階段の上で「降りる」と次の階へ。</p>
    <p><strong>撤退</strong>は各階の入口か階段の上でのみ可能で、道中の経験を能力として持ち帰ります。<strong>全滅</strong>すると道中の経験は失われます（greed ladder）。</p>
    <p>深い階ほど敵が強く報酬も大きくなります。同行者がいる時は 💬 で会話できます。</p>`;
  showDungeonPopup('ヘルプ', body);
}

// The retreat confirm is its own dedicated dungeon-styled modal (the run-end result sibling: obsidian panel +
// amber inner-ring, centered) — no longer the generic popup + entry action row. The body (eyebrow + title +
// message + the 撤退する / 続ける chip-pill pair) is built here since the message depends on can_retreat; the
// confirm is disabled off the entrance/stairs (can_retreat 契約 unchanged). Missing markup is broken wiring —
// fail fast.
function openDungeonRetreatConfirm() {
  const view = currentDungeonView;
  const body = document.querySelector('#dungeon-retreat-confirm-body');
  const popup = document.querySelector('#dungeon-retreat-confirm');
  if (!body || !popup) {
    throw new Error('dungeon retreat confirm nodes are missing (broken markup wiring)');
  }
  const eyebrow = document.createElement('p');
  eyebrow.className = 'eyebrow';
  eyebrow.textContent = 'Retreat';
  const title = document.createElement('h3');
  title.id = 'dungeon-retreat-confirm-title';
  title.textContent = '撤退の確認';
  const message = document.createElement('p');
  message.className = 'dungeon-retreat-confirm-message';
  message.textContent = view?.can_retreat
    ? '撤退して、道中で得た経験を能力として持ち帰りますか？'
    : 'ここでは撤退できません。各階の入口か階段の上まで戻ってください。';
  const actions = document.createElement('div');
  actions.className = 'dungeon-retreat-confirm-actions';
  const confirm = document.createElement('button');
  confirm.type = 'button';
  confirm.className = 'academy-map-action-button primary';
  confirm.textContent = '撤退する';
  confirm.disabled = !view?.can_retreat;
  confirm.addEventListener('click', () => dungeonRetreat().catch(reportError));
  const cancel = document.createElement('button');
  cancel.type = 'button';
  cancel.className = 'academy-map-action-button secondary';
  cancel.textContent = '続ける';
  cancel.addEventListener('click', () => closeDungeonRetreatConfirm());
  actions.append(confirm, cancel);
  body.replaceChildren(eyebrow, title, message, actions);
  popup.hidden = false;
}

function closeDungeonRetreatConfirm() {
  const popup = document.querySelector('#dungeon-retreat-confirm');
  if (!popup) {
    throw new Error('dungeon retreat confirm node #dungeon-retreat-confirm is missing (broken markup wiring)');
  }
  popup.hidden = true;
}

function renderDungeonPlay(view) {
  currentDungeonView = view;
  // A fresh view invalidates any in-progress consumable targeting (its tile coords / armed item may no
  // longer hold), so tear it down before re-rendering the band below.
  teardownDungeonConsumableTargeting();
  document.querySelector('#dungeon-entry').hidden = true;
  document.querySelector('#dungeon-result-popup').hidden = true;
  closeDungeonRetreatConfirm();
  closeDungeonActorDetail();
  document.querySelector('#dungeon-play').hidden = false;
  // Lay the surrounding panels out BEFORE the grid so the map column (.dungeon-stage) is already at its
  // final size when the grid measures and centers. The HUD spans the top, and the right rail
  // (.dungeon-side: the chat — shown whether or not a companion is present — over the item region and the
  // dock) claims the row's 5-share; rendering the grid last means a fresh board's entry center is computed
  // once against the settled viewport, instead of at the transient width it had before the rail un-hid
  // (which a later reframe would then content-clamp off-centre).
  renderDungeonHud(view);
  renderDungeonDock(view);
  // The item columns are laid out before the grid (like the HUD / dock / chat) so their fixed region height
  // is settled when renderDungeonGrid measures the viewport to center the camera. Rendered in DOM order:
  // 持ち込んだアイテム (consumables) / 拾ったアイテム (pickups) / 拾った素材 (materials).
  renderDungeonConsumables(view);
  renderDungeonPickups(view);
  renderDungeonMaterials(view);
  renderDungeonChat(view);
  renderDungeonGrid(view);
}

// Builds the single run-result content (eyebrow, heading, floor reached, gains line) for all three
// outcomes (踏破 / 撤退 / 全滅). There is exactly one result surface now — the popup floated over the
// board — so this is the sole content generator: the outcome difference is carried here, in the eyebrow
// and heading text and the gains line, not duplicated across surfaces. 踏破 reads as a 祝勝 (「ダンジョン
// 制覇」); the `data-status` marker on the heading lets the stylesheet tone the cleared victory accent
// declaratively. The heading owns the id the popup's aria-labelledby resolves to.
function buildDungeonResultNodes(result) {
  const eyebrows = { retreated: 'Retreat', cleared: 'Dungeon Cleared', dead: 'Defeat' };
  const headings = { retreated: '撤退しました', cleared: 'ダンジョン制覇', dead: '力尽きました' };
  // status is server-authored and constrained to the three run outcomes; an unexpected value is a real
  // desync, so fail fast rather than paint a generic label (no default-value fallback).
  if (!(result.status in headings)) throw new Error(`unknown dungeon result status: ${result.status}`);
  const eyebrow = document.createElement('p');
  eyebrow.className = 'eyebrow';
  eyebrow.textContent = eyebrows[result.status];
  const title = document.createElement('h3');
  title.id = 'dungeon-result-popup-title';
  title.dataset.status = result.status;
  title.textContent = headings[result.status];
  const summary = document.createElement('p');
  summary.textContent = `到達 ${result.floor_reached} / ${result.max_floors} 階`;
  const applied = result.applied_gains ?? { magic: {}, abilities: {} };
  const parts = [];
  for (const [key, value] of Object.entries(applied.magic)) parts.push(`${DUNGEON_MAGIC_LABELS[key] ?? key}+${value}`);
  for (const [key, value] of Object.entries(applied.abilities)) parts.push(`${DUNGEON_ABILITY_LABELS[key] ?? key}+${value}`);
  const gains = document.createElement('p');
  gains.textContent = result.status === 'dead'
    ? '道中の経験は失われました。'
    : (parts.length ? `能力上昇: ${parts.join('、')}` : '今回は能力上昇はありませんでした。');
  const nodes = [eyebrow, title, summary, gains];
  // The run-end result always carries a materials manifest; append the 持ち帰り / ロスト section when the run
  // picked up any (an empty pickup renders none). A missing/mis-shaped manifest fails fast inside the builder.
  const materials = buildDungeonResultMaterials(result.materials);
  if (materials) nodes.push(materials);
  // The run-end result also carries a boss-chest equipment manifest; append the 手に入れた / 失った装備
  // section when the run opened any (an empty manifest renders none). Same greed-ladder toning as materials.
  const equipment = buildDungeonResultEquipment(result.equipment);
  if (equipment) nodes.push(equipment);
  return nodes;
}

// Build the run-end equipment section (手に入れた / 失った装備), or null when the run opened no chest. The
// result always carries an equipment manifest: retained=true (踏破 / 撤退) reads as 手に入れた, retained=false
// (敗北) reads as その run で開けて失った — the same instances, toned as a loss. An empty items list renders no
// section; a missing/mis-shaped manifest is a broken server contract and throws (never silently skipped).
function buildDungeonResultEquipment(equipment) {
  if (typeof equipment !== 'object' || equipment === null || Array.isArray(equipment)) {
    throw new Error(`dungeon result requires an equipment object, got ${JSON.stringify(equipment)}`);
  }
  if (typeof equipment.retained !== 'boolean') {
    throw new Error(`dungeon result equipment requires a boolean retained, got ${JSON.stringify(equipment.retained)}`);
  }
  if (!Array.isArray(equipment.items)) {
    throw new Error(`dungeon result equipment requires an items array, got ${JSON.stringify(equipment.items)}`);
  }
  if (equipment.items.length === 0) return null;
  const section = document.createElement('div');
  section.className = 'dungeon-result-materials dungeon-result-equipment';
  section.dataset.retained = String(equipment.retained);
  const heading = document.createElement('p');
  heading.className = 'dungeon-result-materials-heading';
  heading.textContent = equipment.retained ? '手に入れた装備' : '失った装備';
  const list = document.createElement('ul');
  list.className = 'dungeon-result-materials-list';
  for (const item of equipment.items) {
    if (typeof item.name !== 'string' || item.name === '') {
      throw new Error(`dungeon result equipment requires a non-empty name, got ${JSON.stringify(item)}`);
    }
    const row = document.createElement('li');
    row.className = 'dungeon-result-materials-row dungeon-result-equipment-row';
    const name = document.createElement('span');
    name.className = 'dungeon-result-materials-name';
    name.textContent = item.name;
    const meta = document.createElement('span');
    meta.className = 'dungeon-result-materials-quantity';
    meta.textContent = dungeonEquipmentInstanceMetaText(item);
    row.append(name, meta);
    list.append(row);
  }
  section.append(heading, list);
  return section;
}

// Build the run-end materials section (持ち帰った / 失った素材), or null when the run picked up nothing. The
// result always carries a materials manifest: retained=true (踏破 / 撤退) reads as 持ち帰った, retained=false
// (敗北) reads as その run で拾って失った — the same items, toned as a loss. An empty items list is a legitimate
// "拾わなかった" run and renders no section; a missing/mis-shaped manifest is a broken server contract and
// throws (contractually required, never silently skipped). The run-end items carry only item_id / display_name
// / quantity (no element/tier), so this section shows the server-authored display name and count.
function buildDungeonResultMaterials(materials) {
  if (typeof materials !== 'object' || materials === null || Array.isArray(materials)) {
    throw new Error(`dungeon result requires a materials object, got ${JSON.stringify(materials)}`);
  }
  if (typeof materials.retained !== 'boolean') {
    throw new Error(`dungeon result materials requires a boolean retained, got ${JSON.stringify(materials.retained)}`);
  }
  if (!Array.isArray(materials.items)) {
    throw new Error(`dungeon result materials requires an items array, got ${JSON.stringify(materials.items)}`);
  }
  if (materials.items.length === 0) return null;
  const section = document.createElement('div');
  section.className = 'dungeon-result-materials';
  section.dataset.retained = String(materials.retained);
  const heading = document.createElement('p');
  heading.className = 'dungeon-result-materials-heading';
  heading.textContent = materials.retained ? '持ち帰った素材' : '失った素材';
  const list = document.createElement('ul');
  list.className = 'dungeon-result-materials-list';
  for (const item of materials.items) {
    if (typeof item.display_name !== 'string' || item.display_name === '') {
      throw new Error(`dungeon result material requires a non-empty display_name, got ${JSON.stringify(item)}`);
    }
    if (typeof item.quantity !== 'number' || !Number.isFinite(item.quantity)) {
      throw new Error(`dungeon result material requires a numeric quantity, got ${JSON.stringify(item)}`);
    }
    const row = document.createElement('li');
    row.className = 'dungeon-result-materials-row';
    const name = document.createElement('span');
    name.className = 'dungeon-result-materials-name';
    name.textContent = item.display_name;
    const quantity = document.createElement('span');
    quantity.className = 'dungeon-result-materials-quantity';
    quantity.textContent = `×${item.quantity.toLocaleString('ja-JP')}`;
    row.append(name, quantity);
    list.append(row);
  }
  section.append(heading, list);
  return section;
}

function renderDungeonResult(result) {
  currentDungeonView = null;
  dungeonChatMessages = [];
  teardownDungeonConsumableTargeting();
  closeDungeonPopup();
  closeDungeonRetreatConfirm();
  closeDungeonActorDetail();
  // Every run-end (踏破 / 撤退 / 全滅) floats the result as a dungeon-styled modal popup over the board —
  // one path, no surface swap. #dungeon-play and #dungeon-chat are NEVER hidden, so the board and chat
  // stay put behind the scrim and nothing reflows (the flex ratio is untouched, so the camera never
  // reframes). Only the entry card is force-hidden so it can never coexist with the popup. On a live end
  // the play surface stays as last rendered; on a held-finalize resume it was never rendered, so the
  // popup simply floats over the dungeon shell. The exit hand-off is unchanged — dungeonExitToRoom holds
  // the beat, then advances to the same return screen for every outcome.
  document.querySelector('#dungeon-entry').hidden = true;
  document.querySelector('#dungeon-result-popup-body').replaceChildren(...buildDungeonResultNodes(result));
  document.querySelector('#dungeon-result-popup').hidden = false;
  // For a synchronous (solo) end the banked parameters arrive here; a deferred companion end shows the
  // preview now and banks in the background, so it carries no world yet. No manual buttons: the result
  // is a transient beat — dungeonExitToRoom auto-advances through the loading screen back to the room.
  if (result.world?.player_parameters) {
    currentWorld = { ...(currentWorld ?? {}), player_parameters: result.world.player_parameters };
    renderTrainingPlayerParameters(result.world.player_parameters);
    renderPlayerParametersEditor(result.world.player_parameters);
  }
  if (currentRuntimeState) currentRuntimeState = result.state ?? currentRuntimeState;
}

document.querySelector('#academy-training-open-dungeon').addEventListener('click', () => showScreen('academy-dungeon'));
document.querySelector('#dungeon-enter').addEventListener('click', () => enterDungeon().catch(reportError));
document.querySelector('#dungeon-back-to-map').addEventListener('click', () => showScreen('academy-map'));
document.querySelector('#dungeon-retreat-button').addEventListener('click', () => { try { openDungeonRetreatConfirm(); } catch (error) { reportError(error); } });
document.querySelector('#dungeon-help-button').addEventListener('click', () => openDungeonHelp());
document.querySelector('#dungeon-popup-close').addEventListener('click', () => closeDungeonPopup());
document.querySelector('#dungeon-popup').addEventListener('click', (event) => { if (event.target.id === 'dungeon-popup') closeDungeonPopup(); });
// The retreat confirm + actor detail modals close on a backdrop click (matching the generic popup); the actor
// detail also closes via its × / backdrop [data-*-close] hooks wired above.
document.querySelector('#dungeon-retreat-confirm').addEventListener('click', (event) => { if (event.target.id === 'dungeon-retreat-confirm') closeDungeonRetreatConfirm(); });
document.querySelector('#dungeon-talk-send').addEventListener('click', () => dungeonTalk().catch(reportError));
const dungeonTalkInput = document.querySelector('#dungeon-talk-input');
let dungeonTalkIsComposing = false;
dungeonTalkInput.addEventListener('compositionstart', () => { dungeonTalkIsComposing = true; });
dungeonTalkInput.addEventListener('compositionend', () => { dungeonTalkIsComposing = false; });
dungeonTalkInput.addEventListener('keydown', (event) => {
  if (enterShouldSubmit(event, dungeonTalkIsComposing)) {
    event.preventDefault();
    dungeonTalk().catch(reportError);
  }
});
// The dungeon is driven entirely from the keyboard (the dock has no movement/action buttons):
// arrow keys move, Space waits, Enter descends.
const DUNGEON_ARROW_DIRS = { ArrowUp: 'up', ArrowDown: 'down', ArrowLeft: 'left', ArrowRight: 'right' };
window.addEventListener('keydown', (event) => {
  if (!screens['academy-dungeon'].classList.contains('active')) return;
  if (!currentDungeonView) return;
  // Any open dungeon modal (help popup, retreat confirm, actor detail) makes the board keyboard-inert.
  if (!document.querySelector('#dungeon-popup').hidden) return;
  if (!document.querySelector('#dungeon-retreat-confirm').hidden) return;
  if (!document.querySelector('#dungeon-actor-detail').hidden) return;
  // While a consumable is being targeted (an aim tile or an ally pick), the board is a target picker, not a
  // movement surface: Escape cancels, and no key drives a move / 待機 / 階段.
  if (dungeonConsumableTargeting) {
    if (event.key === 'Escape') { event.preventDefault(); cancelDungeonConsumableTargeting(); }
    return;
  }
  // Never steal keys from a focused control (the chat input, the menu button, etc.) or from the
  // focused action log — so typing, Space/Enter on a focused button, and scrolling the log with
  // the keyboard keep working instead of firing an accidental move/wait/descend.
  const active = document.activeElement;
  if (active && (active.id === 'dungeon-log' || ['INPUT', 'TEXTAREA', 'SELECT', 'BUTTON'].includes(active.tagName))) return;
  const direction = DUNGEON_ARROW_DIRS[event.key];
  if (direction) {
    event.preventDefault();
    dungeonDo({ type: 'move', direction }).catch(reportError);
    return;
  }
  if (event.key === ' ' || event.code === 'Space') {
    event.preventDefault();
    dungeonDo({ type: 'wait' }).catch(reportError);
    return;
  }
  if (event.key === 'Enter') {
    // Descend; off the stairs the engine returns a clear "stairs only" message in the log.
    event.preventDefault();
    dungeonDo({ type: 'descend' }).catch(reportError);
  }
});

renderMessageStream();
updateViewportMetrics();
window.addEventListener('resize', updateViewportMetrics);
if ('ResizeObserver' in window) {
  new ResizeObserver(updateViewportMetrics).observe(document.querySelector('.topbar'));
  // Re-fit the dungeon tiles and re-frame the camera whenever the map viewport actually resizes
  // (a window resize or the narrow-screen bottom-sheet switch that stacks the chat below the map).
  // The reframe holds the player at its current relative screen position rather than re-centering,
  // so a resize never jumps the player; a firing with no net size change is skipped in layoutDungeonBoard.
  const dungeonGridEl = document.querySelector('#dungeon-grid');
  if (dungeonGridEl) {
    new ResizeObserver(() => {
      if (!currentDungeonView || document.querySelector('#dungeon-play').hidden) return;
      layoutDungeonBoard(currentDungeonView, { mode: 'reframe' });
    }).observe(dungeonGridEl);
  }
}
// ===== 闘技会 (arena) screen =====
// A routing destination screen: the participate-form selection, the weekly 16-slot single-elimination bracket,
// the player's interactive matches (the dungeon combat grammar over a fixed all-visible board), and spectator
// replays. Presentation is the dungeon's obsidian chrome recolored to a crimson arena accent — a screen-scoped
// --arena-* token layer, no dungeon byte changes. The board renderer and combat animation are arena-scoped
// mirrors (renderDungeonGrid / animateDungeonCombat stay untouched); the item column (fillDungeonItemColumn),
// the consumable effect summary (dungeonConsumableSummaryText), and the per-element effect asset URL
// (dungeonEffectAssetUrl) are shared pure helpers reused directly (no double definition).

let currentArenaState = null;       // last validated GET /api/arena/state (selection or tournament view)
let currentArenaMatchView = null;   // the match engine view currently rendered (interactive or a replay frame)
let arenaActionInFlight = false;    // single-flight guard for enter / start / action / replay fetches
let arenaConsumableTargeting = null;
const arenaEntityNodes = new Map();
const arenaEntityTiles = new Map();
let arenaBoardSignature = null;
// The board scale is FROZEN per window size: --an-cell is computed once (from the match surface's fullest,
// dock+items-present layout) and reused until the window itself resizes. The match surface hides the item /
// dock / prompt / replay regions as the state changes (e.g. at 決着 the interactive dock+items vanish), which
// resizes the inner stage; without this lock the ResizeObserver would rezoom the board on that content toggle
// and warp an in-flight combat trajectory (the player-reported symptom). Keyed on window size so only a real
// window resize (mirrors the dungeon's window-only recompute) re-fits the board.
let arenaCellLock = null;           // frozen --an-cell (px) for the current window size, or null before first fit
let arenaCellLockWindow = null;     // { w, h } window inner size the frozen cell was computed for
let arenaReplay = null;             // { turns, index, timer } while a spectator replay is playing
let arenaReplaySpeed = 'low';       // session-held replay pacing (low = default interval, mid = 1/2, high = 1/4).
                                    // NOT persisted / never reset — it carries across replays for the whole page session.
// LLM flavor (試合前口上 / 優勝・敗退実況一文) UI state. Both surfaces are independent of the combat / reward flow:
// they fetch on their own (never touching arenaActionInFlight, so combat input is never blocked) and a generation
// failure shows an explicit error in its own slot while every non-flavor arena flow keeps working.
let arenaIntroMatchId = null;       // the match the intro banner currently reflects (single-flight token)
let arenaResultFlavorState = { text: null, pending: false, failed: false }; // the concluded tournament's 実況一文
const ARENA_ROUND_LABELS = ['1回戦', '準々決勝', '準決勝', '決勝'];
const ARENA_REPLAY_STEP_MS = 1100;  // auto-advance interval between replay turns (低速 = the unmodified baseline)
// 3-step spectator speed: 低速 = the baseline interval, 中速 = half it, 高速 = a quarter of it (client pacing only).
const ARENA_REPLAY_SPEED_DIVISORS = { low: 1, mid: 2, high: 4 };
const ARENA_REPLAY_SPEED_LABELS = { low: '低速', mid: '中速', high: '高速' };
const ARENA_ENDED_ANIM_MS = 520;    // how long a match-ending exchange plays before the bracket takes over
const ARENA_RESULT_HOLD_MS = 900;   // beat the final match frame holds before returning to the bracket
const ARENA_MELEE_EFFECT_COLOR = '#ffe0d0'; // neutral tint for the melee strike over the crimson ground

function setArenaSelectionStatus(text, { tone = null } = {}) {
  const node = document.querySelector('#arena-selection-status');
  if (!text) { node.hidden = true; node.textContent = ''; node.removeAttribute('data-tone'); return; }
  node.textContent = text;
  if (tone) node.dataset.tone = tone; else node.removeAttribute('data-tone');
  node.hidden = false;
}

function setArenaBracketStatus(text, { tone = null } = {}) {
  const node = document.querySelector('#arena-bracket-status');
  if (!text) { node.hidden = true; node.textContent = ''; node.removeAttribute('data-tone'); return; }
  node.textContent = text;
  if (tone) node.dataset.tone = tone; else node.removeAttribute('data-tone');
  node.hidden = false;
}

// Surface errors on whichever arena surface is visible (bracket if up, else selection). Arena is LLM-free, so
// there is no settings-redirect path; a 400/404/409 (already_entered / no_buddy / concluded / …) reads on the
// status line rather than a silent no-op.
function reportArenaScreenError(error) {
  const onBracket = !document.querySelector('#arena-bracket').hidden;
  (onBracket ? setArenaBracketStatus : setArenaSelectionStatus)(errorDisplayMessage(error), { tone: 'error' });
  console.error(error);
}

// Drop the frozen board scale so the next match re-fits under its own first (interactive) layout. Called when
// leaving the match surface and on screen (re)open, never on a per-action re-render — so a match keeps its scale
// from start through 決着, but a later match (or a resume after a spectate that froze a larger cell) starts clean.
function resetArenaBoardScale() {
  arenaCellLock = null;
  arenaCellLockWindow = null;
}

function showArenaSurface(name) {
  if (name !== 'match') { resetArenaBoardScale(); clearArenaMatchIntro(); }
  document.querySelector('#arena-selection').hidden = name !== 'selection';
  document.querySelector('#arena-bracket').hidden = name !== 'bracket';
  document.querySelector('#arena-match').hidden = name !== 'match';
}

// ----- LLM flavor: 試合前口上 (match intro banner) -----

function setArenaMatchIntroBanner({ state, text = '' }) {
  const node = document.querySelector('#arena-match-intro');
  if (state === 'hidden') { node.hidden = true; node.textContent = ''; node.removeAttribute('data-state'); return; }
  node.hidden = false;
  node.dataset.state = state; // 'pending' | 'ready' | 'error'
  node.textContent = text;
}

function clearArenaMatchIntro() {
  arenaIntroMatchId = null;
  setArenaMatchIntroBanner({ state: 'hidden' });
}

// Fetch (or restore the persisted) 口上 for a viewable match and show it in the match banner. Runs on its own —
// NOT gated by arenaActionInFlight — so board input keeps working while the 口上 streams; a 503 shows an explicit
// error in the banner without interrupting the match / replay. A newer match's intro supersedes a stale in-flight
// one via the arenaIntroMatchId token.
async function arenaShowMatchIntro(matchId) {
  arenaIntroMatchId = matchId;
  setArenaMatchIntroBanner({ state: 'pending', text: '口上を生成中…' });
  try {
    const payload = await postJson('/api/arena/match/intro', { match_id: matchId });
    const { intro } = validateArenaIntroResponse(payload);
    if (arenaIntroMatchId !== matchId) return; // a newer match took over — drop the stale result
    setArenaMatchIntroBanner({ state: 'ready', text: intro });
  } catch (error) {
    if (arenaIntroMatchId !== matchId) return;
    setArenaMatchIntroBanner({ state: 'error', text: `口上の生成に失敗しました（${errorDisplayMessage(error)}）` });
    console.error(error);
  }
}

// ----- LLM flavor: 優勝・敗退実況一文 (terminal result) -----

function resetArenaResultFlavor() {
  arenaResultFlavorState = { text: null, pending: false, failed: false };
}

// The flavor line node for the terminal result panel, reflecting the current fetch state (pending / ready /
// error). Rebuilt whenever the result panel re-renders, and swapped in place when a fetch completes.
function arenaResultFlavorNode() {
  const p = document.createElement('p');
  p.className = 'arena-result-flavor';
  p.id = 'arena-result-flavor';
  if (arenaResultFlavorState.text) { p.dataset.state = 'ready'; p.textContent = arenaResultFlavorState.text; }
  else if (arenaResultFlavorState.failed) { p.dataset.state = 'error'; p.textContent = '実況の生成に失敗しました。'; }
  else { p.dataset.state = 'pending'; p.textContent = '実況を生成中…'; }
  return p;
}

function refreshArenaResultFlavorDom() {
  const existing = document.querySelector('#arena-result-flavor');
  if (existing) existing.replaceWith(arenaResultFlavorNode());
}

// Fetch (or restore the persisted) 実況一文 once per concluded tournament. Idempotent + single-flight: a second
// call while a fetch is in flight, or after it succeeded, is a no-op. A 503 leaves an explicit error in the slot
// while the reward panel and 闘技会を出る stay operable.
async function arenaEnsureResultFlavor() {
  if (arenaResultFlavorState.text || arenaResultFlavorState.pending) return;
  arenaResultFlavorState.pending = true;
  arenaResultFlavorState.failed = false;
  try {
    const payload = await postJson('/api/arena/result-flavor', {});
    const { flavor } = validateArenaResultFlavorResponse(payload);
    arenaResultFlavorState.text = flavor;
  } catch (error) {
    arenaResultFlavorState.failed = true;
    console.error(error);
  } finally {
    arenaResultFlavorState.pending = false;
    refreshArenaResultFlavorDom();
  }
}

// Open the arena: the participate-form selection when no tournament is built this week, else the bracket (with
// the player's live match restored when one is in progress — reload resume). A malformed payload fails fast
// (validateArenaState) before any surface renders.
async function refreshArenaScreen() {
  stopArenaReplay();
  resetArenaBoardScale();
  resetArenaResultFlavor();
  const payload = await getJson('/api/arena/state');
  renderArenaState(validateArenaState(payload));
}

function renderArenaState(view) {
  currentArenaState = view;
  if (view.phase === 'selection') { renderArenaSelection(view); return; }
  // A tournament with a live match (start / resume) drops straight into the match surface; otherwise the bracket.
  if (view.current_match) {
    renderArenaMatch(view.current_match, view, { replay: false });
    if (view.current_match_id) arenaShowMatchIntro(view.current_match_id); // resume restores the persisted 口上
    return;
  }
  renderArenaBracket(view);
}

// ----- phase 1: participate-form selection -----

function renderArenaSelection(view) {
  teardownArenaConsumableTargeting();
  currentArenaMatchView = null;
  showArenaSurface('selection');
  setArenaSelectionStatus('');
  const container = document.querySelector('#arena-selection-modes');
  container.replaceChildren();
  const buddyName = view.buddy ? view.buddy.display_name : null;
  for (const mode of view.modes) {
    const card = document.createElement('button');
    card.type = 'button';
    card.className = 'arena-mode-card';
    card.dataset.mode = mode.mode;
    // An unavailable mode (no buddy) is shown DISABLED with its reason — never hidden (silent drop forbidden).
    card.disabled = !mode.available;
    const title = document.createElement('span');
    title.className = 'arena-mode-card-title';
    title.textContent = ARENA_MODE_LABELS[mode.mode];
    const desc = document.createElement('span');
    desc.className = 'arena-mode-card-desc';
    desc.textContent = ARENA_MODE_DESCRIPTIONS[mode.mode];
    card.append(title, desc);
    if ((mode.mode === 'pair' || mode.mode === 'spectate') && buddyName) {
      const buddy = document.createElement('span');
      buddy.className = 'arena-mode-card-buddy';
      buddy.textContent = `バディー：${buddyName}`;
      card.append(buddy);
    }
    if (!mode.available && mode.reason) {
      const note = document.createElement('span');
      note.className = 'arena-mode-card-note';
      note.textContent = arenaModeUnavailableReasonText(mode.reason);
      card.append(note);
    }
    card.addEventListener('click', () => arenaEnter(mode.mode).catch(reportArenaScreenError));
    container.append(card);
  }
}

async function arenaEnter(mode) {
  if (arenaActionInFlight) { showProcessingToast(); return; }
  arenaActionInFlight = true;
  try {
    resetArenaResultFlavor(); // a fresh tournament — the prior week's 実況一文 must not linger
    const payload = await postJson('/api/arena/enter', { mode });
    renderArenaState(validateArenaState(payload));
  } finally {
    arenaActionInFlight = false;
  }
}

// ----- phase 2: bracket -----

function renderArenaBracket(view) {
  teardownArenaConsumableTargeting();
  currentArenaMatchView = null;
  currentArenaState = view;
  showArenaSurface('bracket');
  setArenaBracketStatus('');
  renderArenaBracketChips(view);
  renderArenaBracketGrid(view);
  renderArenaBracketActions(view);
  renderArenaResult(view);
}

function renderArenaBracketChips(view) {
  const node = document.querySelector('#arena-bracket-chips');
  node.replaceChildren(
    arenaChipEl('形態', ARENA_MODE_LABELS[view.mode]),
    arenaChipEl('勝ち抜き', String(view.wins)),
    arenaChipEl('状態', view.terminal ? '終了' : '進行中')
  );
}

// unit_id -> the unit (identity + actors), for the bracket match cards (the bracket is server-authoritative — the
// client never re-pairs units, it only labels the rounds the view hands it). Each actor name is rendered as its own
// clickable name button so a 2v2 unit exposes both fighters' details.
function arenaUnitMap(view) {
  const map = new Map();
  for (const unit of view.units) map.set(unit.unit_id, unit);
  return map;
}

// The bracket is one CSS grid: columns are the rounds (16→8→4→2→優勝), rows are the round-0 match count worth of
// equal tracks (8 for a 16-unit bracket) plus a header row for the labels. A round-r match spans 2^r of those
// equal rows — explicit row-span doubling — so a round-N+1 match spans exactly its two round-N feeders and, with
// the card vertically centered in the span, its center lands on the feeders' shared row boundary (the advancement
// seam; backend adjacency: round r+1 match m is fed by round r matches 2m/2m+1). Because every round places its
// cards on the SAME shared row grid — not in independent per-round flex columns — the seam alignment is fixed by
// the grid geometry, not by card content height: watch buttons, name length, or empty '—' slots can never skew it.
// The template counts are read from the server bracket (round count, round-0 match count), so the skeleton scales
// with the bracket instead of hardcoding 4×8.
function renderArenaBracketGrid(view) {
  const grid = document.querySelector('#arena-bracket-grid');
  grid.replaceChildren();
  const unitsById = arenaUnitMap(view);
  const rounds = view.bracket.rounds;
  const nRounds = rounds.length;
  const baseRows = rounds[0].length; // finest row granularity = round-0 match count (the 16→8 first round)
  grid.style.gridTemplateColumns = `repeat(${nRounds}, minmax(var(--arena-bracket-round-min), 1fr))`;
  // Equal body rows never shrink below a full card height, so a card can never overflow its band and desync the
  // seams; when the grid is taller than the minimum they grow together (all 1fr), staying equal.
  grid.style.gridTemplateRows = `auto repeat(${baseRows}, minmax(var(--arena-bracket-card-min), 1fr))`;
  const lastRound = nRounds - 1;
  rounds.forEach((round, roundIndex) => {
    const span = 2 ** roundIndex; // each round spans twice its feeder's row count
    const head = document.createElement('p');
    head.className = 'arena-bracket-round-label';
    head.textContent = ARENA_ROUND_LABELS[roundIndex] ?? `第${roundIndex + 1}回戦`;
    head.style.gridColumn = String(roundIndex + 1);
    head.style.gridRow = '1';
    grid.append(head);
    for (const match of round) {
      const slot = document.createElement('div');
      slot.className = 'arena-bracket-match';
      // index parity = which feeder side (2m even → upper, 2m+1 odd → lower); source draws the outgoing elbow,
      // sink the incoming stub, so the two roles combine into the full round-to-round connector.
      slot.classList.add(match.index % 2 === 0 ? 'arena-bracket-match--upper' : 'arena-bracket-match--lower');
      if (roundIndex < lastRound) slot.classList.add('arena-bracket-match--source');
      if (roundIndex > 0) slot.classList.add('arena-bracket-match--sink');
      slot.style.gridColumn = String(roundIndex + 1);
      // body rows start at grid line 2 (line 1 is the label row); match m spans its 2^r rows from there.
      slot.style.gridRow = `${2 + match.index * span} / span ${span}`;
      slot.append(buildArenaMatchCard(view, match, unitsById));
      grid.append(slot);
    }
  });
}

function buildArenaMatchCard(view, match, unitsById) {
  const card = document.createElement('div');
  card.className = 'arena-match-card';
  if (match.is_player_match) card.classList.add('arena-match-card--player');
  card.append(buildArenaMatchRow(view, match, unitsById, match.team_a_unit_id));
  // The "対" divider brackets the two contestants of one match into a single readable pair.
  const vs = document.createElement('span');
  vs.className = 'arena-match-card-vs';
  vs.textContent = '対';
  vs.setAttribute('aria-hidden', 'true');
  card.append(vs);
  card.append(buildArenaMatchRow(view, match, unitsById, match.team_b_unit_id));
  // A resolved auto (non-player) match is spectator-replayable; a click plays its recomputed turn log.
  if (match.resolved && match.is_auto) {
    card.classList.add('arena-match-card--watchable');
    const watch = document.createElement('button');
    watch.type = 'button';
    watch.className = 'arena-match-card-watch';
    watch.textContent = '観戦';
    watch.addEventListener('click', () => startArenaReplay(match.match_id).catch(reportArenaScreenError));
    card.append(watch);
  }
  return card;
}

function buildArenaMatchRow(view, match, unitsById, unitId) {
  const row = document.createElement('div');
  row.className = 'arena-match-card-row';
  if (unitId && unitId === view.player_unit_id) row.classList.add('arena-match-card-row--player');
  const won = Boolean(match.winner_unit_id) && unitId === match.winner_unit_id;
  if (won) row.classList.add('arena-match-card-row--won');
  const name = document.createElement('span');
  name.className = 'arena-match-card-name';
  const unit = unitId ? unitsById.get(unitId) : null;
  if (!unit) {
    name.textContent = '—'; // an unfilled slot (a later round awaiting its winners)
  } else {
    // Each fighter is its own clickable name (a 2v2 unit shows both); the protagonist name is clickable too and
    // opens its own detail (能力値 + 装備, no image).
    unit.actors.forEach((actor, index) => {
      if (index > 0) name.append(document.createTextNode('・'));
      name.append(arenaNameButton(actor));
    });
  }
  row.append(name);
  if (won) {
    const mark = document.createElement('span');
    mark.className = 'arena-match-card-mark';
    mark.textContent = '✔';
    row.append(mark);
  }
  return row;
}

// The earliest unresolved player match whose opponent is already resolved (both unit ids filled) — the one the
// player can start now. spectate has no player match.
function arenaFindStartablePlayerMatch(view) {
  if (view.mode === 'spectate') return null;
  for (const round of view.bracket.rounds) {
    for (const match of round) {
      if (match.is_player_match && !match.resolved && match.team_a_unit_id && match.team_b_unit_id) return match;
    }
  }
  return null;
}

function renderArenaBracketActions(view) {
  const actions = document.querySelector('#arena-bracket-actions');
  actions.replaceChildren();
  if (view.terminal) {
    // The week was consumed at dispatch; leaving returns to the hub through the shared content-return path.
    actions.append(arenaActionButton('闘技会を出る', 'primary', () => arenaExit().catch(reportError)));
    return;
  }
  if (arenaFindStartablePlayerMatch(view)) {
    actions.append(arenaActionButton('試合開始', 'primary', () => arenaStartMatch().catch(reportArenaScreenError)));
  }
}

function renderArenaResult(view) {
  const panel = document.querySelector('#arena-result');
  if (!view.terminal || !view.content_result) { panel.hidden = true; panel.replaceChildren(); return; }
  const detail = validateArenaContentResult(view.content_result);
  panel.replaceChildren(...buildArenaResultNodes(detail), arenaResultFlavorNode());
  panel.hidden = false;
  // The 実況一文 is generated independently of the reward panel — a failure never blocks 闘技会を出る.
  arenaEnsureResultFlavor();
}

function buildArenaResultNodes(detail) {
  const eyebrow = document.createElement('p');
  eyebrow.className = 'eyebrow';
  eyebrow.textContent = 'Result';
  const title = document.createElement('h3');
  title.className = 'arena-result-title';
  title.dataset.outcome = detail.outcome;
  title.textContent = arenaOutcomeLabel(detail.outcome);
  const summary = document.createElement('p');
  summary.className = 'arena-result-summary';
  summary.textContent = `${detail.wins} 勝`;
  const prize = document.createElement('p');
  prize.className = 'arena-result-prize';
  prize.textContent = `賞金 ${detail.prize_money.toLocaleString('ja-JP')} G`;
  const nodes = [eyebrow, title, summary, prize];
  if (detail.materials.length) {
    const section = document.createElement('div');
    section.className = 'arena-result-materials';
    const heading = document.createElement('p');
    heading.className = 'arena-result-materials-heading';
    heading.textContent = '獲得素材';
    const list = document.createElement('ul');
    list.className = 'arena-result-materials-list';
    for (const item of detail.materials) {
      const row = document.createElement('li');
      row.className = 'arena-result-materials-row';
      const name = document.createElement('span');
      name.className = 'arena-result-materials-name';
      name.textContent = item.display_name;
      const qty = document.createElement('span');
      qty.className = 'arena-result-materials-quantity';
      qty.textContent = `×${item.quantity.toLocaleString('ja-JP')}`;
      row.append(name, qty);
      list.append(row);
    }
    section.append(heading, list);
    nodes.push(section);
  }
  return nodes;
}

async function arenaStartMatch() {
  if (arenaActionInFlight) { showProcessingToast(); return; }
  arenaActionInFlight = true;
  try {
    const payload = await postJson('/api/arena/match/start', {});
    const view = validateArenaMatchView(payload.view);
    const tournament = validateArenaState(payload.tournament);
    renderArenaMatch(view, tournament, { replay: false });
    if (tournament.current_match_id) arenaShowMatchIntro(tournament.current_match_id);
  } finally {
    arenaActionInFlight = false;
  }
}

// 闘技会を出る is a routing content completion whose return is always the hub (the arena is a routing-only
// destination, so the post-content screen is invariably 'interaction'): return through the shared
// loading-covered hub return (終了→ロード画面→迎え会話ストリーミング開始でハブ表示), the same primitive 鍛錬 / 調合 /
// 工房 use, so the hub-start wait is never a bare enterRoutingHub under the still-visible arena screen (a
// freeze). The loading screen is never terminal (returnToRoutingHubThroughLoadingScreen's un-strand defense).
async function arenaExit() {
  stopArenaReplay();
  await returnToRoutingHubThroughLoadingScreen();
}

// ----- phase 3/4: match surface (interactive play + spectator replay share one board renderer) -----

function renderArenaMatch(view, tournamentView, { replay = false } = {}) {
  currentArenaMatchView = view;
  if (tournamentView) currentArenaState = tournamentView;
  teardownArenaConsumableTargeting();
  showArenaSurface('match');
  // Interactive controls appear only when a living player controller is up (the view carries the player block)
  // and it is not a replay; a resolved / player-down frame and every replay frame render the board read-only.
  const interactive = !replay && view.active && Object.prototype.hasOwnProperty.call(view, 'player_actor_id');
  document.querySelector('#arena-replay-controls').hidden = !replay;
  document.querySelector('#arena-dock-main').hidden = !interactive;
  document.querySelector('#arena-items').hidden = !interactive;
  renderArenaHud(view);
  renderArenaLog(view);
  if (replay) renderArenaReplayControls();
  if (interactive) { renderArenaDock(view); renderArenaConsumables(view); }
  renderArenaBoard(view);
}

async function arenaDo(action) {
  if (arenaActionInFlight || !currentArenaMatchView) return;
  arenaActionInFlight = true;
  try {
    const payload = await postJson('/api/arena/action', { action });
    const view = validateArenaMatchView(payload.view);
    const tournament = validateArenaState(payload.tournament);
    if (view.active) {
      // The match continues: re-render with the fresh view and animate the exchange.
      renderArenaMatch(view, tournament, { replay: false });
      animateArenaCombat(view.events);
      return;
    }
    // The player's match resolved: play the final exchange on the still-visible board, hold a beat, then return
    // to the (advanced) bracket — terminal reflects the result + 闘技会を出る there.
    renderArenaMatch(view, tournament, { replay: false });
    if (view.events?.length) { animateArenaCombat(view.events); await sleep(ARENA_ENDED_ANIM_MS); }
    await sleep(ARENA_RESULT_HOLD_MS);
    renderArenaBracket(tournament);
  } finally {
    arenaActionInFlight = false;
  }
}

// The player's team when a living player controller is up; null in a replay / player-down frame (the board
// then colors team a as the near side).
function arenaFriendlyTeam(view) {
  if (!Object.prototype.hasOwnProperty.call(view, 'player_actor_id')) return null;
  const player = view.actors.find((actor) => actor.actor_id === view.player_actor_id);
  return player ? player.team : null;
}

function arenaPlayerTeamActors(view) {
  const player = view.actors.find((actor) => actor.actor_id === view.player_actor_id);
  if (!player) return [];
  return view.actors.filter((actor) => actor.team === player.team);
}
function arenaDownedTeammates(view) { return arenaPlayerTeamActors(view).filter((actor) => actor.down); }
function arenaLivingTeammates(view) { return arenaPlayerTeamActors(view).filter((actor) => !actor.down); }

// ----- HUD -----

function arenaBarEl(label, current, max, modifier) {
  const wrap = document.createElement('div');
  wrap.className = `an-hud-bar ${modifier}`;
  const name = document.createElement('span');
  name.className = 'an-hud-bar-label';
  name.textContent = label;
  const track = document.createElement('div');
  track.className = 'an-hud-bar-track';
  const fill = document.createElement('div');
  fill.className = 'an-hud-bar-fill';
  fill.style.width = `${max > 0 ? Math.max(0, Math.min(100, Math.round((current / max) * 100))) : 0}%`;
  track.append(fill);
  const value = document.createElement('span');
  value.className = 'an-hud-bar-value';
  value.textContent = `${current}/${max}`;
  wrap.append(name, track, value);
  return wrap;
}

function arenaChipEl(label, value) {
  const chip = document.createElement('div');
  chip.className = 'an-hud-chip';
  const l = document.createElement('span');
  l.className = 'an-hud-chip-label';
  l.textContent = label;
  const v = document.createElement('strong');
  v.textContent = value;
  chip.append(l, v);
  return chip;
}

function arenaActorBars(actor) {
  const card = document.createElement('div');
  card.className = `an-hud-actor${actor.down ? ' an-hud-actor--down' : ''}`;
  const head = document.createElement('div');
  head.className = 'an-hud-actor-head';
  // Every actor name (protagonist included) is a clickable button that opens its detail.
  const name = arenaNameButton(actor);
  name.classList.add('an-hud-actor-name');
  head.append(name);
  if (actor.down) {
    const state = document.createElement('span');
    state.className = 'an-hud-actor-state';
    state.textContent = '戦闘不能';
    head.append(state);
  }
  card.append(head, arenaBarEl('HP', actor.hp, actor.max_hp, 'an-hud-bar--hp'), arenaBarEl('MP', actor.mp, actor.max_mp, 'an-hud-bar--mp'));
  return card;
}

function arenaHudTeamColumn(label, actors, friendly) {
  const col = document.createElement('div');
  col.className = `an-hud-team${friendly ? ' an-hud-team--friendly' : ''}`;
  const head = document.createElement('p');
  head.className = 'an-hud-team-label';
  head.textContent = friendly ? `${label}（自陣）` : label;
  col.append(head);
  for (const actor of actors) col.append(arenaActorBars(actor));
  return col;
}

function renderArenaHud(view) {
  const node = document.querySelector('#arena-hud-status');
  node.replaceChildren();
  // The round number reserves a fixed 4-digit tabular width (arena-round-chip) so 1→2→3→4 digit counts never shift
  // the chip or the party columns beside it.
  const roundChip = arenaChipEl('ラウンド', String(view.round + 1));
  roundChip.classList.add('arena-round-chip');
  node.append(roundChip);
  const friendly = arenaFriendlyTeam(view);
  const party = document.createElement('div');
  party.className = 'an-hud-party';
  party.append(
    arenaHudTeamColumn('自陣', view.actors.filter((actor) => actor.team === 'a'), friendly === 'a'),
    arenaHudTeamColumn('相手', view.actors.filter((actor) => actor.team === 'b'), friendly === 'b')
  );
  node.append(party);
}

// ----- dock (spells + heal) + log -----

function renderArenaDock(view) {
  const spells = document.querySelector('#arena-spells');
  spells.replaceChildren();
  const player = view.actors.find((actor) => actor.actor_id === view.player_actor_id);
  for (const spell of view.castable_elements ?? []) {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = `arena-spell an-el-${spell.element}`;
    button.innerHTML = `<span class="arena-spell-el">${DUNGEON_MAGIC_LABELS[spell.element] ?? spell.element}</span><span class="arena-spell-mp">MP${spell.mp_cost}</span>`;
    button.title = `${spell.label ?? ''} 威力${spell.power ?? ''} / MP${spell.mp_cost}`;
    button.disabled = !player || player.mp < spell.mp_cost;
    button.addEventListener('click', () => arenaDo({ type: 'cast', element: spell.element }).catch(reportError));
    spells.append(button);
  }
  // Self-heal on its own row below the attack spells — label + enabled state come straight from the engine
  // view.healing_spell (the front end never recomputes the heal amount / MP cost). A missing contract fails fast.
  const healSlot = document.querySelector('#arena-heal');
  healSlot.replaceChildren();
  const healing = view.healing_spell;
  if (!healing) throw new Error('arena view is missing healing_spell');
  const { action_type, mp_cost, heal_amount, can_use } = healing;
  if (action_type !== 'heal_spell' || typeof mp_cost !== 'number' || typeof heal_amount !== 'number' || typeof can_use !== 'boolean') {
    throw new Error('arena healing_spell is missing required fields');
  }
  const healButton = document.createElement('button');
  healButton.type = 'button';
  healButton.className = 'arena-spell arena-spell-heal';
  healButton.innerHTML = `<span class="arena-spell-el">回復</span><span class="arena-spell-mp">MP${mp_cost}</span>`;
  healButton.title = `自己回復 +${heal_amount} / MP${mp_cost}`;
  healButton.disabled = !can_use;
  healButton.addEventListener('click', () => arenaDo({ type: action_type }).catch(reportError));
  healSlot.append(healButton);
}

function renderArenaLog(view) {
  const log = document.querySelector('#arena-log');
  const atBottom = log.scrollHeight - log.scrollTop - log.clientHeight < 4;
  log.replaceChildren();
  for (const entry of view.log ?? []) {
    const p = document.createElement('p');
    p.textContent = entry;
    log.append(p);
  }
  if (view.action_error) {
    const note = document.createElement('p');
    note.className = 'arena-log-note';
    note.textContent = arenaActionErrorText(view.action_error);
    log.append(note);
  }
  if (atBottom) log.scrollTop = log.scrollHeight;
}

// ----- brought-item column (持ち込みアイテム only — no pickups) -----

function renderArenaConsumables(view) {
  const list = document.querySelector('#arena-consumables-list');
  if (!list) return;
  if (!Array.isArray(view.consumables)) throw new Error('arena view is missing consumables');
  // fillDungeonItemColumn is the shared brought-only column part (it stands alone without a sibling pickup column).
  fillDungeonItemColumn(list, view.consumables, (row) => buildArenaConsumableChip(view, row), '持ち込んだ消耗品はありません。');
}

// Only revive is render-gated (needs a downed teammate + an unspent per-match revive); every other kind stays
// enabled and lets the server resolve its own guard into a turn-non-consuming action_error.
function arenaConsumableDisabledState(view, row) {
  if (row.target_mode === 'revive') {
    if (view.revive_used) return { disabled: true, reason: 'この試合では蘇生を使い切りました。', note: '使い切り' };
    if (!arenaDownedTeammates(view).length) return { disabled: true, reason: 'ダウン中の味方がいません。', note: '対象なし' };
  }
  return { disabled: false, reason: '', note: '' };
}

function buildArenaConsumableChip(view, row) {
  const button = document.createElement('button');
  button.type = 'button';
  button.className = 'arena-consumable';
  button.dataset.itemId = row.item_id;
  button.dataset.targetMode = row.target_mode;
  if (row.element) button.classList.add(`an-el-${row.element}`);
  const state = arenaConsumableDisabledState(view, row);
  button.disabled = state.disabled;
  if (state.reason) button.title = state.reason;
  if (arenaConsumableTargeting?.item_id === row.item_id) button.dataset.armed = 'true';
  const name = document.createElement('span');
  name.className = 'arena-consumable-name';
  name.textContent = row.name;
  const summary = document.createElement('span');
  summary.className = 'arena-consumable-summary';
  summary.textContent = dungeonConsumableSummaryText(row);
  const qty = document.createElement('span');
  qty.className = 'arena-consumable-qty';
  qty.textContent = `×${row.quantity}`;
  button.append(name, summary, qty);
  if (state.disabled && state.note) {
    const note = document.createElement('span');
    note.className = 'arena-consumable-note';
    note.textContent = state.note;
    button.append(note);
  }
  button.addEventListener('click', () => { try { onArenaConsumableClick(view, row); } catch (error) { reportError(error); } });
  return button;
}

// A chip click resolves the row's target_mode. auto fires at once; aim arms board targeting; ally / revive open
// an actor_id pick over the player's team (living for heal/MP, downed for revive) — the arena generalization of
// the dungeon's player/companion vocabulary to the all-visible board.
function onArenaConsumableClick(view, row) {
  if (arenaActionInFlight) { showProcessingToast(); return; }
  if (arenaConsumableTargeting?.item_id === row.item_id) { cancelArenaConsumableTargeting(); return; }
  cancelArenaConsumableTargeting();
  if (row.target_mode === 'auto') { useArenaConsumable(row.item_id); return; }
  if (row.target_mode === 'aim') { enterArenaAimMode(view, row); return; }
  if (row.target_mode === 'ally') { openArenaAllyTargetPrompt(view, row, { downed: false }); return; }
  if (row.target_mode === 'revive') { openArenaAllyTargetPrompt(view, row, { downed: true }); return; }
  throw new Error(`unknown consumable target_mode: ${JSON.stringify(row.target_mode)}`);
}

function useArenaConsumable(itemId, extra = {}) {
  teardownArenaConsumableTargeting();
  arenaDo({ type: 'use_consumable', item_id: itemId, ...extra }).catch(reportError);
}

// heal / MP / revive pick: the target is an actor_id from the player's team (living for heal/MP, downed for
// revive). The pick sends target:<actor_id>.
function openArenaAllyTargetPrompt(view, row, { downed }) {
  arenaConsumableTargeting = { item_id: row.item_id, mode: downed ? 'revive' : 'ally', name: row.name };
  const targets = downed ? arenaDownedTeammates(view) : arenaLivingTeammates(view);
  const actions = targets.map((actor) => ({
    label: actor.name,
    onClick: () => useArenaConsumable(row.item_id, { target: actor.actor_id })
  }));
  actions.push({ label: '中止', onClick: () => cancelArenaConsumableTargeting() });
  const message = targets.length
    ? (downed ? `「${row.name}」で誰を蘇生しますか？` : `「${row.name}」を誰に使いますか？`)
    : '対象になる味方がいません。';
  showArenaConsumablePrompt(message, actions);
  renderArenaConsumables(view);
}

// ----- attack_area aim mode (all-visible board: in-bounds + floor + line of sight, no fog gate) -----

function enterArenaAimMode(view, row) {
  arenaConsumableTargeting = { item_id: row.item_id, mode: 'aim', radius: row.radius, element: row.element, name: row.name };
  buildArenaAimOverlay(view, row);
  document.querySelector('#arena-grid')?.classList.add('an-aiming');
  showArenaConsumablePrompt(`「${row.name}」の着弾点を選んでください（Escで中止）。`, [
    { label: '中止', onClick: () => cancelArenaConsumableTargeting() }
  ]);
  renderArenaConsumables(view);
}

// Mirrors the engine's line-of-sight walk (arenaEngine.hasLineOfSight): the rounded cells strictly between the
// player and the target must all be floor. Kept identical so the client pre-filter matches the server's aim gate.
function arenaHasLineOfSight(view, from, to) {
  const dx = to.x - from.x;
  const dy = to.y - from.y;
  const steps = Math.max(Math.abs(dx), Math.abs(dy));
  for (let step = 1; step < steps; step += 1) {
    const x = Math.round(from.x + (dx * step) / steps);
    const y = Math.round(from.y + (dy * step) / steps);
    if (x < 0 || y < 0 || x >= view.width || y >= view.height || view.tiles[y][x] !== 'floor') return false;
  }
  return true;
}

function arenaAimTileValid(view, x, y) {
  if (x < 0 || y < 0 || x >= view.width || y >= view.height) return false;
  if (view.tiles[y][x] !== 'floor') return false;
  const player = view.actors.find((actor) => actor.actor_id === view.player_actor_id);
  if (!player) return false;
  return arenaHasLineOfSight(view, player, { x, y });
}

function buildArenaAimOverlay(view, row) {
  const board = document.querySelector('#arena-grid .an-board');
  if (!board) return;
  document.querySelector('#arena-grid .an-aim')?.remove();
  const layer = document.createElement('div');
  layer.className = 'an-aim';
  layer.style.setProperty('--an-cols', view.width);
  layer.style.setProperty('--an-rows', view.height);
  const cells = [];
  for (let y = 0; y < view.height; y += 1) {
    for (let x = 0; x < view.width; x += 1) {
      const cell = document.createElement('div');
      cell.className = 'an-aim-cell';
      cell.dataset.x = x;
      cell.dataset.y = y;
      if (arenaAimTileValid(view, x, y)) cell.classList.add('an-aim-valid');
      cells.push(cell);
    }
  }
  layer.replaceChildren(...cells);
  layer.addEventListener('pointermove', (event) => onArenaAimHover(event, row));
  layer.addEventListener('pointerleave', () => clearArenaAimBlast());
  layer.addEventListener('click', (event) => { try { onArenaAimClick(event, row); } catch (error) { reportError(error); } });
  board.append(layer);
}

function onArenaAimHover(event, row) {
  const cell = event.target.closest('.an-aim-cell');
  if (!cell || !cell.classList.contains('an-aim-valid')) { clearArenaAimBlast(); return; }
  paintArenaAimBlast(row, Number(cell.dataset.x), Number(cell.dataset.y));
}

function paintArenaAimBlast(row, cx, cy) {
  clearArenaAimBlast();
  const layer = document.querySelector('#arena-grid .an-aim');
  if (!layer) return;
  for (const cell of layer.querySelectorAll('.an-aim-cell')) {
    const distance = Math.abs(Number(cell.dataset.x) - cx) + Math.abs(Number(cell.dataset.y) - cy);
    if (distance <= row.radius) cell.classList.add('an-aim-blast');
  }
}

function clearArenaAimBlast() {
  const layer = document.querySelector('#arena-grid .an-aim');
  if (!layer) return;
  for (const cell of layer.querySelectorAll('.an-aim-blast')) cell.classList.remove('an-aim-blast');
}

function onArenaAimClick(event, row) {
  if (arenaActionInFlight) return;
  const cell = event.target.closest('.an-aim-cell');
  if (!cell || !cell.classList.contains('an-aim-valid')) return;
  useArenaConsumable(row.item_id, { aim: { x: Number(cell.dataset.x), y: Number(cell.dataset.y) } });
}

function showArenaConsumablePrompt(text, actions) {
  const prompt = document.querySelector('#arena-consumable-prompt');
  if (!prompt) return;
  const message = document.createElement('span');
  message.className = 'arena-consumable-prompt-text';
  message.textContent = text;
  const actionRow = document.createElement('span');
  actionRow.className = 'arena-consumable-prompt-actions';
  for (const action of actions) {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'arena-consumable-prompt-action';
    button.textContent = action.label;
    if (action.disabled) button.disabled = true;
    if (action.title) button.title = action.title;
    button.addEventListener('click', () => { try { action.onClick(); } catch (error) { reportError(error); } });
    actionRow.append(button);
  }
  prompt.replaceChildren(message, actionRow);
  prompt.hidden = false;
}

function teardownArenaConsumableTargeting() {
  arenaConsumableTargeting = null;
  document.querySelector('#arena-grid .an-aim')?.remove();
  document.querySelector('#arena-grid')?.classList.remove('an-aiming');
  const prompt = document.querySelector('#arena-consumable-prompt');
  if (prompt) { prompt.hidden = true; prompt.replaceChildren(); }
}

function cancelArenaConsumableTargeting() {
  const wasTargeting = arenaConsumableTargeting !== null;
  teardownArenaConsumableTargeting();
  if (wasTargeting && currentArenaMatchView) renderArenaConsumables(currentArenaMatchView);
}

// ----- student-face resolution + character-detail (name click) -----

// The face image for a student unit's board token. A homunculus is not in the selectable roster, so it uses the
// enriched actor.face_url (the arena view carries it — see arenaSession); a character resolves its visual set from
// the selectable roster by actor_id (= character_id), exactly like the dungeon ally token. Unresolvable identity
// throws (roster desync / missing face_url) — no silent default-icon fallback. The protagonist never reaches here.
function arenaActorFaceUrl(actor) {
  if (actor.kind === 'homunculus') {
    if (typeof actor.face_url !== 'string' || !actor.face_url) {
      throw new Error(`arena homunculus actor is missing face_url: ${actor.actor_id}`);
    }
    return actor.face_url;
  }
  const character = (selectableCharacters ?? []).find((entry) => entry.character_id === actor.actor_id);
  if (!character) throw new Error(`arena actor not found in character roster: ${actor.actor_id}`);
  const visualSetId = character.visual_set_id;
  if (!visualSetId) throw new Error(`arena actor is missing visual_set_id: ${actor.actor_id}`);
  return `/canonical/character_visual_sets/${visualSetId}/face_emotions/neutral.jpg`;
}

// A clickable actor name (HUD / bracket) — every actor (protagonist included) opens its detail via
// openArenaActorDetail, surfaced through reportArenaScreenError.
function arenaNameButton(actor) {
  const button = document.createElement('button');
  button.type = 'button';
  button.className = 'arena-name-button interaction-name-button';
  button.textContent = actor.name;
  button.addEventListener('click', () => { try { openArenaActorDetail(actor); } catch (error) { reportArenaScreenError(error); } });
  return button;
}

// Opens an actor's detail in the unified actor-detail shell (arena token scope): the same section grammar as the
// dungeon (image / 能力値 / 装備 — no 獲得予定 in the arena). The protagonist has no image; a roster character shows
// its scene standee; a homunculus shows its enriched face. The 能力値 + 装備 read the projection's entry-snapshot
// values (actor.parameters / actor.equipment — snapshot strict, no roster / current-world re-resolve). A roster
// miss (image resolution) is a real desync → throw; the equipment contract is validated before the DOM is touched.
function openArenaActorDetail(actor) {
  const body = buildActorDetailBody({
    imageNode: arenaActorDetailImage(actor),
    parameterNodes: buildParameterGroups(actor.parameters),
    equipmentNode: buildArenaDetailEquipment(actor.equipment ?? null),
    acquisitionNode: null
  });
  openArenaActorDetailShell(actor.name, body);
}

// The detail image slot: none for the protagonist, the scene standee (portrait) for a roster character (resolved
// from the roster by actor_id — a miss is a desync → throw), the enriched face (1:1) for a homunculus.
function arenaActorDetailImage(actor) {
  if (actor.kind === 'protagonist') return null;
  if (actor.kind === 'homunculus') {
    return buildActorDetailImage({ src: actor.face_url, alt: `${actor.name}の顔`, shape: 'face' });
  }
  const character = (selectableCharacters ?? []).find((item) => item.character_id === actor.actor_id);
  if (!character) throw new Error(`arena actor not found in character roster: ${actor.actor_id}`);
  return buildActorDetailImage({
    src: characterSceneStandeeUrl(character),
    alt: `${character.display_name ?? character.character_id}の一枚絵`,
    shape: 'standee'
  });
}

// The arena read-only equipment section: weapon + amulet slots (shared .actor-detail-equipment* grammar), each an
// equipped-instance detail (arena-scoped card — NO 解除 button) or a quiet 未装備 note. runEquipment is the
// entry-snapshot run-equipment (null when nothing is equipped, else {slots:{weapon,amulet}, effects}); its slots
// are validated fail-fast (a malformed slot throws before the DOM is touched).
function buildArenaDetailEquipment(runEquipment) {
  const slots = runEquipment === null
    ? { weapon: null, amulet: null }
    : validateDungeonEquipmentSlots(runEquipment.slots, 'arena detail equipment');
  const wrap = document.createElement('div');
  wrap.className = 'actor-detail-equipment';
  for (const slot of WORKSHOP_EQUIPMENT_KINDS) {
    const card = document.createElement('div');
    card.className = 'actor-detail-equipment-slot';
    card.dataset.slot = slot;
    const head = document.createElement('p');
    head.className = 'actor-detail-equipment-slot-head';
    head.textContent = `${workshopKindLabel(slot)}スロット`;
    card.append(head);
    const view = slots[slot];
    if (view) {
      card.append(buildArenaEquipmentInstanceDetail(view));
    } else {
      const empty = document.createElement('p');
      empty.className = 'actor-detail-equipment-empty';
      empty.textContent = '未装備';
      card.append(empty);
    }
    wrap.append(card);
  }
  return wrap;
}

// One equipped-instance card (arena-scoped): name + identity meta (shared vocab via dungeonEquipmentInstanceMetaText)
// + the base / bonus effect rows. The arena classes carry the crimson token layer; the shape mirrors the dungeon
// instance card so both detail shells read the same.
function buildArenaEquipmentInstanceDetail(view) {
  const { instance, baseEffects, bonusEffects } = view;
  const detail = document.createElement('div');
  detail.className = 'arena-equipment-instance';
  detail.dataset.element = instance.element;
  const name = document.createElement('p');
  name.className = 'arena-equipment-instance-name';
  name.textContent = instance.name;
  const meta = document.createElement('p');
  meta.className = 'arena-equipment-instance-meta';
  meta.textContent = dungeonEquipmentInstanceMetaText(instance);
  const effects = document.createElement('div');
  effects.className = 'arena-equipment-instance-effects';
  effects.append(
    buildArenaEquipmentEffectRow('基礎性能', baseEffects),
    buildArenaEquipmentEffectRow('付加性能', bonusEffects)
  );
  detail.append(name, meta, effects);
  return detail;
}

function buildArenaEquipmentEffectRow(label, entries) {
  const row = document.createElement('div');
  row.className = 'arena-equipment-effect-row';
  const rowLabel = document.createElement('span');
  rowLabel.className = 'arena-equipment-effect-label';
  rowLabel.textContent = label;
  const chips = document.createElement('span');
  chips.className = 'arena-equipment-effect-chips';
  if (entries.length === 0) {
    const none = document.createElement('span');
    none.className = 'arena-equipment-effect-none';
    none.textContent = 'なし';
    chips.append(none);
  } else {
    for (const entry of entries) {
      const chip = document.createElement('span');
      chip.className = 'arena-equipment-effect';
      chip.textContent = `${entry.label}+${entry.value}`;
      chips.append(chip);
    }
  }
  row.append(rowLabel, chips);
  return row;
}

// Opens the unified actor-detail shell for the arena. The body is built (validating the equipment contract) BEFORE
// the shell is shown, so a broken contract throws without leaving a half-open dialog. Missing markup is broken
// wiring — fail fast.
function openArenaActorDetailShell(title, bodyNode) {
  const popup = document.querySelector('#arena-actor-detail');
  const titleEl = document.querySelector('#arena-actor-detail-title');
  const body = document.querySelector('#arena-actor-detail-body');
  if (!popup || !titleEl || !body) {
    throw new Error('arena actor detail shell nodes are missing (broken markup wiring)');
  }
  titleEl.textContent = title;
  body.replaceChildren(bodyNode);
  popup.hidden = false;
}

function closeArenaActorDetail() {
  const popup = document.querySelector('#arena-actor-detail');
  if (!popup) throw new Error('arena actor detail shell node #arena-actor-detail is missing (broken markup wiring)');
  popup.hidden = true;
}

// ----- board renderer (arena-scoped; fixed all-visible board, no camera) -----

function arenaTokenEl({ roleClass, elementClass = '', imageUrl = null, glyph = '', hp = null, maxHp = null, label = '' }) {
  const token = document.createElement('div');
  token.className = ['an-token', roleClass, elementClass].filter(Boolean).join(' ');
  if (label) token.title = label;
  const inner = document.createElement('div');
  inner.className = 'an-token-inner';
  // A student unit (roster character / homunculus) wears its face image like the dungeon ally token; the
  // protagonist has no imageUrl and keeps the faceless emblem glyph. A broken image URL surfaces the glyph.
  if (imageUrl) {
    const img = document.createElement('img');
    img.className = 'an-token-img';
    img.alt = '';
    img.src = imageUrl;
    img.addEventListener('error', () => {
      img.remove();
      const fallback = document.createElement('span');
      fallback.className = 'an-token-glyph';
      fallback.textContent = glyph;
      inner.append(fallback);
    });
    inner.append(img);
  } else {
    const glyphEl = document.createElement('span');
    glyphEl.className = 'an-token-glyph';
    glyphEl.textContent = glyph;
    inner.append(glyphEl);
  }
  token.append(inner);
  if (hp != null && maxHp != null && maxHp > 0) {
    const bar = document.createElement('div');
    bar.className = 'an-token-hp';
    const fill = document.createElement('div');
    fill.className = 'an-token-hp-fill';
    fill.style.width = `${Math.max(0, Math.min(100, Math.round((hp / maxHp) * 100)))}%`;
    bar.append(fill);
    token.append(bar);
  }
  return token;
}

function upsertArenaEntity(overlay, key, live, x, y, tokenEl) {
  live.add(key);
  arenaEntityTiles.set(key, { x, y });
  const transform = `translate(calc((var(--an-cell) + var(--an-gap)) * ${x}), calc((var(--an-cell) + var(--an-gap)) * ${y}))`;
  let node = arenaEntityNodes.get(key);
  if (!node) {
    node = document.createElement('div');
    node.className = 'an-entity';
    node.style.transform = transform;
    node.replaceChildren(tokenEl);
    arenaEntityNodes.set(key, node);
    overlay.append(node);
    return;
  }
  node.style.transform = transform;
  node.replaceChildren(tokenEl);
}

function renderArenaBoard(view) {
  const grid = document.querySelector('#arena-grid');
  let board = grid.querySelector('.an-board');
  if (!board) {
    const viewport = document.createElement('div');
    viewport.className = 'an-viewport';
    board = document.createElement('div');
    board.className = 'an-board';
    const tilesLayer = document.createElement('div');
    tilesLayer.className = 'an-tiles';
    const entitiesLayer = document.createElement('div');
    entitiesLayer.className = 'an-entities';
    const effectsLayer = document.createElement('div');
    effectsLayer.className = 'an-effects';
    board.append(tilesLayer, entitiesLayer, effectsLayer);
    viewport.append(board);
    grid.replaceChildren(viewport);
  }
  const tiles = board.querySelector('.an-tiles');
  const overlay = board.querySelector('.an-entities');

  const friendly = arenaFriendlyTeam(view);
  // Resolve every on-board token (role + face image / emblem glyph) BEFORE mutating any board DOM, so an
  // unresolvable student face (roster desync / missing homunculus face_url) throws without leaving a
  // half-painted board. The protagonist stays a faceless emblem; students wear their face like the dungeon ally.
  const tokenSpecs = view.actors.filter((actor) => !actor.down).map((actor) => {
    let roleClass;
    let glyph;
    let imageUrl = null;
    if (actor.kind === 'protagonist') { roleClass = 'an-token--self'; glyph = '★'; }
    else {
      roleClass = (friendly !== null ? actor.team === friendly : actor.team === 'a') ? 'an-token--ally' : 'an-token--enemy';
      glyph = '◆';
      imageUrl = arenaActorFaceUrl(actor);
    }
    return { actor, roleClass, glyph, imageUrl };
  });

  tiles.style.setProperty('--an-cols', view.width);
  tiles.style.setProperty('--an-rows', view.height);

  // A new match is a fresh board: drop the persistent entity nodes so each re-mounts at its position instead of
  // sliding in from a prior match's layout.
  if (view.match_id !== arenaBoardSignature) {
    arenaBoardSignature = view.match_id;
    arenaEntityNodes.clear();
    arenaEntityTiles.clear();
    overlay.replaceChildren();
  }

  const cells = [];
  for (let y = 0; y < view.height; y += 1) {
    for (let x = 0; x < view.width; x += 1) {
      const cell = document.createElement('div');
      cell.className = `an-cell ${view.tiles[y][x] === 'floor' ? 'an-floor' : 'an-wall'}`;
      cells.push(cell);
    }
  }
  tiles.replaceChildren(...cells);

  const live = new Set();
  for (const { actor, roleClass, glyph, imageUrl } of tokenSpecs) {
    upsertArenaEntity(overlay, `actor:${actor.actor_id}`, live, actor.x, actor.y,
      arenaTokenEl({ roleClass, elementClass: `an-token--el-${actor.element}`, imageUrl, glyph, hp: actor.hp, maxHp: actor.max_hp,
        label: `${actor.name}（${DUNGEON_MAGIC_LABELS[actor.element] ?? actor.element}）` }));
  }
  for (const [key, node] of arenaEntityNodes) {
    if (!live.has(key)) { node.remove(); arenaEntityNodes.delete(key); arenaEntityTiles.delete(key); }
  }
  layoutArenaBoard(view);
}

// The arena board shows every tile at once (no fog / no camera), so layout is a single fit: the largest cell
// that fits the whole 11×9 board in the stage on both axes. The result is FROZEN per window size (arenaCellLock)
// so a content-driven stage resize — the dock / item / prompt / replay regions coming and going as the match
// state changes, most sharply at 決着 — reuses the frozen scale instead of rezooming the board (which would warp
// an in-flight combat trajectory). Only a real window resize recomputes. Because the first fit runs under the
// interactive (dock+items present) layout, the frozen cell already fits when those regions are shown, so hiding
// them later never overflows. A viewport not yet sized bails (the ResizeObserver re-runs after layout).
function layoutArenaBoard(view) {
  const grid = document.querySelector('#arena-grid');
  if (!grid) return;
  const win = { w: window.innerWidth, h: window.innerHeight };
  if (arenaCellLock !== null && arenaCellLockWindow && arenaCellLockWindow.w === win.w && arenaCellLockWindow.h === win.h) {
    grid.style.setProperty('--an-cell', `${arenaCellLock}px`);
    return;
  }
  const viewport = grid.querySelector('.an-viewport');
  if (!viewport) return;
  const availW = viewport.clientWidth;
  const availH = viewport.clientHeight;
  if (availW === 0 || availH === 0) return;
  const gap = parseFloat(getComputedStyle(grid).getPropertyValue('--an-gap'));
  if (!Number.isFinite(gap)) throw new Error('arena: --an-gap must resolve to a length');
  const cellW = (availW - gap * (view.width - 1)) / view.width;
  const cellH = (availH - gap * (view.height - 1)) / view.height;
  const cell = Math.max(1, Math.floor(Math.min(cellW, cellH)));
  arenaCellLock = cell;
  arenaCellLockWindow = win;
  grid.style.setProperty('--an-cell', `${cell}px`);
}

// ----- combat effects (arena-scoped mirror of the dungeon animation; reuses the shared per-element asset URL) -----

function arenaEntityDisplayedCenter(x, y, board) {
  for (const [key, tile] of arenaEntityTiles) {
    if (tile.x !== x || tile.y !== y) continue;
    const node = arenaEntityNodes.get(key);
    if (!node) continue;
    const r = node.getBoundingClientRect();
    const b = board.getBoundingClientRect();
    return { x: (r.left + r.width / 2) - b.left, y: (r.top + r.height / 2) - b.top };
  }
  return null;
}

function animateArenaCombat(events) {
  const grid = document.querySelector('#arena-grid');
  const board = grid?.querySelector('.an-board');
  const layer = board?.querySelector('.an-effects');
  if (!layer) return;
  layer.replaceChildren();
  if (!events || !events.length) return;
  const gap = parseFloat(getComputedStyle(grid).getPropertyValue('--an-gap'));
  const cell = parseFloat(getComputedStyle(grid).getPropertyValue('--an-cell'));
  if (!Number.isFinite(gap) || !Number.isFinite(cell)) return;
  const step = cell + gap;
  const center = (n) => n * step + cell / 2;
  const origin = (x, y) => arenaEntityDisplayedCenter(x, y, board) ?? { x: center(x), y: center(y) };
  const reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  events.forEach((event, index) => {
    window.setTimeout(() => spawnArenaEffect(layer, event, { origin, cell, reduce }), Math.min(index * 70, 280));
  });
}

function spawnArenaEffect(layer, event, { origin, cell, reduce }) {
  const from = origin(event.from.x, event.from.y);
  const to = origin(event.to.x, event.to.y);
  if (event.element != null) spawnArenaAssetEffect(layer, event, { from, to, cell, reduce });
  else spawnArenaMeleeEffect(layer, event, { from, to, cell, reduce });
}

function spawnArenaAssetEffect(layer, event, { from, to, cell, reduce }) {
  const bolt = document.createElement('img');
  bolt.className = 'an-effect-bolt';
  bolt.alt = '';
  bolt.src = dungeonEffectAssetUrl(event.element, 'bolt');
  bolt.style.left = `${from.x}px`;
  bolt.style.top = `${from.y}px`;
  bolt.style.setProperty('--an-effect-size', `${Math.round(cell * 0.9)}px`);
  layer.append(bolt);
  const landImpact = () => {
    bolt.remove();
    if (!event.hit) return;
    const impact = document.createElement('img');
    impact.className = 'an-effect-burst';
    impact.alt = '';
    impact.src = dungeonEffectAssetUrl(event.element, 'impact');
    impact.style.left = `${to.x}px`;
    impact.style.top = `${to.y}px`;
    impact.style.setProperty('--an-impact-size', `${Math.round(cell * 1.05)}px`);
    layer.append(impact);
    if (reduce) { window.setTimeout(() => impact.remove(), 200); return; }
    impact.animate(
      [{ transform: 'translate(-50%, -50%) scale(0.3)', opacity: 0.95 }, { transform: 'translate(-50%, -50%) scale(1)', opacity: 0 }],
      { duration: 240, easing: 'ease-out' }
    ).onfinish = () => impact.remove();
  };
  if (reduce) { window.setTimeout(landImpact, 0); return; }
  bolt.animate(
    [{ transform: 'translate(-50%, -50%)', left: `${from.x}px`, top: `${from.y}px` }, { transform: 'translate(-50%, -50%)', left: `${to.x}px`, top: `${to.y}px` }],
    { duration: 180, easing: 'ease-in' }
  ).onfinish = landImpact;
}

function spawnArenaMeleeEffect(layer, event, { from, to, cell, reduce }) {
  const projectile = document.createElement('div');
  projectile.className = 'an-effect an-effect--melee';
  projectile.style.setProperty('--an-effect-color', ARENA_MELEE_EFFECT_COLOR);
  projectile.style.left = `${from.x}px`;
  projectile.style.top = `${from.y}px`;
  layer.append(projectile);
  const landImpact = () => {
    projectile.remove();
    if (!event.hit) return;
    const impact = document.createElement('div');
    impact.className = 'an-effect-impact an-effect-impact--melee';
    impact.style.setProperty('--an-effect-color', ARENA_MELEE_EFFECT_COLOR);
    impact.style.left = `${to.x}px`;
    impact.style.top = `${to.y}px`;
    impact.style.setProperty('--an-impact-size', `${Math.round(cell * 1.05)}px`);
    layer.append(impact);
    if (reduce) { window.setTimeout(() => impact.remove(), 200); return; }
    impact.animate(
      [{ transform: 'translate(-50%, -50%) scale(0.3)', opacity: 0.95 }, { transform: 'translate(-50%, -50%) scale(1)', opacity: 0 }],
      { duration: 240, easing: 'ease-out' }
    ).onfinish = () => impact.remove();
  };
  if (reduce) { window.setTimeout(landImpact, 0); return; }
  projectile.animate(
    [{ transform: 'translate(-50%, -50%)', left: `${from.x}px`, top: `${from.y}px` }, { transform: 'translate(-50%, -50%)', left: `${to.x}px`, top: `${to.y}px` }],
    { duration: 180, easing: 'ease-in' }
  ).onfinish = landImpact;
}

// ----- spectator replay -----

async function startArenaReplay(matchId) {
  if (arenaActionInFlight) { showProcessingToast(); return; }
  arenaActionInFlight = true;
  try {
    const payload = await getJson(`/api/arena/match/${encodeURIComponent(matchId)}/replay`);
    const replay = validateArenaReplay(payload);
    stopArenaReplay();
    arenaReplay = { turns: replay.turns, index: 0, timer: null };
    renderArenaMatch(replay.turns[0].view, currentArenaState, { replay: true });
    arenaShowMatchIntro(matchId); // the intro for the auto match being watched
    arenaScheduleReplayStep();
  } finally {
    arenaActionInFlight = false;
  }
}

// The current auto-advance interval: the baseline divided by the selected speed. A speed change takes effect on the
// NEXT scheduled step (the in-flight timeout keeps its interval), matching 「次のターン送りから反映」.
function arenaReplayStepMs() {
  return ARENA_REPLAY_STEP_MS / ARENA_REPLAY_SPEED_DIVISORS[arenaReplaySpeed];
}

function arenaScheduleReplayStep() {
  if (!arenaReplay || arenaReplay.index >= arenaReplay.turns.length - 1) return;
  arenaReplay.timer = window.setTimeout(() => arenaReplayAdvance(), arenaReplayStepMs());
}

function arenaReplayAdvance() {
  if (!arenaReplay || arenaReplay.index >= arenaReplay.turns.length - 1) return;
  arenaReplay.index += 1;
  const turn = arenaReplay.turns[arenaReplay.index];
  renderArenaMatch(turn.view, currentArenaState, { replay: true });
  animateArenaCombat(turn.events);
  arenaScheduleReplayStep();
}

// Skip to the final frame (the outcome), stopping the auto-advance.
function arenaReplaySkip() {
  if (!arenaReplay) return;
  if (arenaReplay.timer) { window.clearTimeout(arenaReplay.timer); arenaReplay.timer = null; }
  arenaReplay.index = arenaReplay.turns.length - 1;
  renderArenaMatch(arenaReplay.turns[arenaReplay.index].view, currentArenaState, { replay: true });
}

function stopArenaReplay() {
  if (arenaReplay?.timer) window.clearTimeout(arenaReplay.timer);
  arenaReplay = null;
}

function renderArenaReplayControls() {
  const node = document.querySelector('#arena-replay-controls');
  node.replaceChildren();
  const atEnd = !arenaReplay || arenaReplay.index >= arenaReplay.turns.length - 1;
  const info = document.createElement('span');
  info.className = 'arena-replay-info';
  info.textContent = arenaReplay ? `${arenaReplay.index + 1} / ${arenaReplay.turns.length}` : '';
  node.append(info, arenaReplaySpeedControl());
  if (!atEnd) node.append(arenaActionButton('スキップ', 'secondary', () => { try { arenaReplaySkip(); } catch (error) { reportError(error); } }));
  node.append(arenaActionButton('ブラケットへ戻る', 'secondary', () => {
    stopArenaReplay();
    if (currentArenaState?.phase === 'tournament') renderArenaBracket(currentArenaState);
    else refreshArenaScreen().catch(reportArenaScreenError);
  }));
}

// The 低速/中速/高速 speed toggle. The selection lives in arenaReplaySpeed (session-held, never reset), so it carries
// across replays; picking a speed re-renders the controls (to move the selected mark) and the next scheduled step
// picks up the new interval.
function arenaReplaySpeedControl() {
  const group = document.createElement('div');
  group.className = 'arena-replay-speed';
  group.setAttribute('role', 'group');
  group.setAttribute('aria-label', '再生速度');
  for (const key of ['low', 'mid', 'high']) {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'arena-replay-speed-button';
    button.textContent = ARENA_REPLAY_SPEED_LABELS[key];
    const selected = arenaReplaySpeed === key;
    button.classList.toggle('is-selected', selected);
    button.setAttribute('aria-pressed', selected ? 'true' : 'false');
    button.addEventListener('click', () => { arenaReplaySpeed = key; renderArenaReplayControls(); });
    group.append(button);
  }
  return group;
}

// ----- shared arena CTA button -----

function arenaActionButton(label, variant, handler) {
  const button = document.createElement('button');
  button.type = 'button';
  button.className = `arena-action-button ${variant}`;
  button.textContent = label;
  button.addEventListener('click', handler);
  return button;
}

// ----- match-surface wiring (static nodes) -----

document.querySelector('#arena-match-back').addEventListener('click', () => {
  stopArenaReplay();
  if (currentArenaState?.phase === 'tournament') { renderArenaBracket(currentArenaState); return; }
  refreshArenaScreen().catch(reportArenaScreenError);
});

// The arena match is driven from the keyboard like the dungeon (the dock has no movement buttons): arrow keys
// move, Space waits. There is no descend/retreat. Replay frames and consumable targeting are non-move surfaces.
const ARENA_ARROW_DIRS = { ArrowUp: 'up', ArrowDown: 'down', ArrowLeft: 'left', ArrowRight: 'right' };
window.addEventListener('keydown', (event) => {
  if (!screens['academy-arena'].classList.contains('active')) return;
  if (document.querySelector('#arena-match').hidden) return;
  if (arenaReplay) return; // a replay is a non-interactive surface
  if (!currentArenaMatchView || !currentArenaMatchView.active) return;
  if (!Object.prototype.hasOwnProperty.call(currentArenaMatchView, 'player_actor_id')) return;
  if (arenaConsumableTargeting) {
    if (event.key === 'Escape') { event.preventDefault(); cancelArenaConsumableTargeting(); }
    return;
  }
  const active = document.activeElement;
  if (active && (active.id === 'arena-log' || ['INPUT', 'TEXTAREA', 'SELECT', 'BUTTON'].includes(active.tagName))) return;
  const direction = ARENA_ARROW_DIRS[event.key];
  if (direction) { event.preventDefault(); arenaDo({ type: 'move', direction }).catch(reportError); return; }
  if (event.key === ' ' || event.code === 'Space') { event.preventDefault(); arenaDo({ type: 'wait' }).catch(reportError); }
});

if ('ResizeObserver' in window) {
  const arenaGridEl = document.querySelector('#arena-grid');
  if (arenaGridEl) {
    // Refit the all-visible board whenever the arena stage resizes (window resize / narrow-screen reflow).
    new ResizeObserver(() => {
      if (!currentArenaMatchView || document.querySelector('#arena-match').hidden) return;
      layoutArenaBoard(currentArenaMatchView);
    }).observe(arenaGridEl);
  }
}

// ── Dev-only drag calibration (frame-decoration corners + map pins) ────────────────────────────────────
// Opened with ?calibrate=<screen> (e.g. ?calibrate=routing-hub / ?calibrate=academy-map). It shows the target
// screen and lays a draggable handle over each registered target, of which there are two kinds read from the
// declarative registries (frameDecorationCalibration.js):
//   • corner ornament — dragging updates a pair of translate-offset CSS custom properties in px (set on the
//     registered style host, inherited by its ::before/::after or real-element consumer); export is a CSS
//     declaration block to bake back into the defaults.
//   • map pin — dragging moves the stage marker by a percentage of the map image; export is a JS object
//     literal to paste back over the truth-source constant (academyMapStagePinCoordinates).
// The tool body dispatches on the target kind but is otherwise generic — a new corner or a new pin group is a
// registry entry, no code here changes. Without the query, none of this runs and normal play is byte-equivalent.
const CALIBRATION_CORNER_POINT = {
  'top-left': (rect) => ({ x: rect.left, y: rect.top }),
  'top-right': (rect) => ({ x: rect.right, y: rect.top }),
  'bottom-left': (rect) => ({ x: rect.left, y: rect.bottom }),
  'bottom-right': (rect) => ({ x: rect.right, y: rect.bottom })
};

let frameDecorationCalibrationState = null;

function requireCalibrationElement(selector, role, targetId) {
  const element = document.querySelector(selector);
  if (!element) {
    throw new Error(`calibration target ${targetId}: ${role} selector ${JSON.stringify(selector)} matched no element`);
  }
  return element;
}

function readCalibrationOffsetPx(computed, varName, targetId) {
  // Delegate the accept/reject boundary to the pure parser (strict px format, fail-fast on empty / non-px).
  return parseCalibrationOffsetPx(computed.getPropertyValue(varName), { varName, targetId });
}

// Resolve a registry entry against the live DOM: the anchor and style-host elements must exist and the
// offset custom properties must be defined (their CSS defaults). A missing selector or undefined property
// fail-fasts — a broken registration is surfaced, never silently skipped. The initial offset is read from
// the current property values so calibration continues from any already-baked offset.
function resolveCalibrationTarget(target) {
  const anchor = requireCalibrationElement(target.anchorSelector, 'anchor', target.id);
  const styleHost = requireCalibrationElement(target.styleHostSelector, 'style host', target.id);
  const computed = getComputedStyle(styleHost);
  const offset = {
    x: readCalibrationOffsetPx(computed, target.varX, target.id),
    y: readCalibrationOffsetPx(computed, target.varY, target.id)
  };
  // Capture the starting state so リセット returns to the screen's declared baseline (which may be a non-zero
  // baked offset), not to a hardcoded origin.
  return { target, anchor, styleHost, offset, baseline: { x: offset.x, y: offset.y } };
}

function applyCalibrationOffset(entry) {
  entry.styleHost.style.setProperty(entry.target.varX, `${Math.round(entry.offset.x)}px`);
  entry.styleHost.style.setProperty(entry.target.varY, `${Math.round(entry.offset.y)}px`);
}

function positionCalibrationHandle(entry) {
  const rect = entry.anchor.getBoundingClientRect();
  const point = CALIBRATION_CORNER_POINT[entry.target.corner](rect);
  entry.handle.style.left = `${point.x + entry.offset.x}px`;
  entry.handle.style.top = `${point.y + entry.offset.y}px`;
}

function repositionCalibrationHandles() {
  const state = frameDecorationCalibrationState;
  if (!state) return;
  for (const entry of state.corners) positionCalibrationHandle(entry);
  for (const group of state.pinGroups) for (const pin of group.pins) positionMapPinHandle(pin);
}

function calibrationReadoutRow(name, valueText) {
  const li = document.createElement('li');
  const nameEl = document.createElement('span');
  nameEl.textContent = name;
  const valueEl = document.createElement('span');
  valueEl.textContent = valueText;
  li.append(nameEl, valueEl);
  return li;
}

function updateCalibrationReadout() {
  const state = frameDecorationCalibrationState;
  if (!state) return;
  if (state.cornerReadout) {
    state.cornerReadout.replaceChildren(...state.corners.map((entry) =>
      calibrationReadoutRow(entry.target.label, `${Math.round(entry.offset.x)}, ${Math.round(entry.offset.y)}`)));
    state.cornerExport.value = formatCalibrationOffsetsCss(state.corners.map((entry) => ({
      target: entry.target,
      x: entry.offset.x,
      y: entry.offset.y
    })));
  }
  for (const group of state.pinGroups) {
    group.readout.replaceChildren(...group.pins.map((pin) =>
      calibrationReadoutRow(pin.pinId, `${roundMapPinCoordinate(pin.offset.x)}, ${roundMapPinCoordinate(pin.offset.y)}`)));
    const overrides = {};
    for (const pin of group.pins) overrides[pin.pinId] = { x: pin.offset.x, y: pin.offset.y };
    group.exportBox.value = formatMapPinCoordinatesJs({
      coordinatesName: group.coordinatesName,
      baseCoordinates: group.baseCoordinates,
      overrides
    });
  }
}

function beginCalibrationDrag(event, entry) {
  event.preventDefault();
  const handle = entry.handle;
  handle.setPointerCapture(event.pointerId);
  handle.dataset.dragging = 'true';
  const startX = event.clientX;
  const startY = event.clientY;
  const startOffset = { ...entry.offset };
  const move = (moveEvent) => {
    entry.offset = {
      x: startOffset.x + (moveEvent.clientX - startX),
      y: startOffset.y + (moveEvent.clientY - startY)
    };
    applyCalibrationOffset(entry);
    positionCalibrationHandle(entry);
    updateCalibrationReadout();
  };
  const end = () => {
    handle.removeEventListener('pointermove', move);
    handle.removeEventListener('pointerup', end);
    handle.removeEventListener('pointercancel', end);
    delete handle.dataset.dragging;
  };
  handle.addEventListener('pointermove', move);
  handle.addEventListener('pointerup', end);
  handle.addEventListener('pointercancel', end);
}

function createCalibrationHandle(entry) {
  const handle = document.createElement('button');
  handle.type = 'button';
  handle.className = 'frame-decoration-calibration-handle';
  handle.dataset.calibrationId = entry.target.id;
  handle.setAttribute('aria-label', `${entry.target.label} を移動`);
  const label = document.createElement('span');
  label.className = 'frame-decoration-calibration-handle-label';
  label.textContent = entry.target.label;
  handle.append(label);
  handle.addEventListener('pointerdown', (event) => beginCalibrationDrag(event, entry));
  entry.handle = handle;
  return handle;
}

// ── Map-pin calibration kind ───────────────────────────────────────────────────────────────────────────
// A pin group is resolved so that EVERY pin in the truth source gets a draggable handle — not just the pins the
// active field happens to render. The rendered pin nodes are zipped with the same renderable-location list
// renderAcademyMap produced (identical function + order) to recover each rendered node's locationId WITHOUT
// stamping anything onto the shipped pin markup (normal play stays byte-equivalent; no data attribute is added).
// Every truth-source id then binds to a live rendered node when one exists, or to a calibration-only marker
// synthesized at its % when it does not (event stages, or stages absent from the current field) — so all stages
// are positionable. An unknown coordinates source, a rendered node/location count desync, or a non-finite
// coordinate fail-fasts.
function resolveMapPinCalibrationPins(entry) {
  const container = requireCalibrationElement(entry.containerSelector, 'container', entry.id);
  const coordinates = MAP_PIN_CALIBRATION_COORDINATE_SOURCES[entry.coordinatesName];
  if (!coordinates) {
    throw new Error(`map-pins ${entry.id}: unknown coordinates source ${JSON.stringify(entry.coordinatesName)}`);
  }
  const ids = Object.keys(coordinates);
  if (ids.length === 0) {
    throw new Error(`map-pins ${entry.id}: coordinates source ${JSON.stringify(entry.coordinatesName)} has no pins`);
  }
  const renderedNodes = [...container.querySelectorAll(entry.nodeSelector)];
  const renderedLocations = academyMapRegionRenderableNodes(activeMapRegion, currentField?.locations ?? []);
  if (renderedNodes.length !== renderedLocations.length) {
    throw new Error(`map-pins ${entry.id}: ${renderedNodes.length} rendered pin nodes but ${renderedLocations.length} renderable locations (desync)`);
  }
  const nodeByLocationId = new Map(renderedLocations.map((location, index) => [location.id, renderedNodes[index]]));
  return ids.map((pinId) => {
    const base = coordinates[pinId];
    if (!base || !Number.isFinite(base.x) || !Number.isFinite(base.y)) {
      throw new Error(`map-pins ${entry.id}: pin ${JSON.stringify(pinId)} has no finite ${entry.coordinatesName} coordinate`);
    }
    let node = nodeByLocationId.get(pinId);
    const synthetic = node === undefined;
    if (synthetic) node = createCalibrationPinMarker(container, base);
    node.classList.add('is-drag-editable');
    return {
      entry,
      container,
      node,
      pinId,
      synthetic,
      offset: { x: base.x, y: base.y },
      baseline: { x: base.x, y: base.y }
    };
  });
}

// A calibration-only pin marker for a stage the normal render does not draw (an event stage, or one absent from
// the current field). It is a real .academy-map-node visual so it drags identically to a live pin, plus a
// modifier so the calibrator can tell it apart. It exists ONLY under ?calibrate=academy-map — normal play never
// creates one (renderAcademyMap is untouched).
function createCalibrationPinMarker(container, base) {
  const marker = document.createElement('div');
  marker.className = 'academy-map-node academy-map-node--calibration-synthetic';
  marker.style.backgroundImage = `url('${academyMapPinImageUrl(activeMapRegion, false, false)}')`;
  marker.style.left = `${base.x}%`;
  marker.style.top = `${base.y}%`;
  container.append(marker);
  return marker;
}

// Write the pin's current % back onto the live map node (renderAcademyMap consumes button.style.left/top = %).
function applyMapPinOffset(pin) {
  pin.node.style.left = `${pin.offset.x}%`;
  pin.node.style.top = `${pin.offset.y}%`;
}

// The pin marker's anchor is bottom-center (translate(-50%,-100%)), so the pin tip sits at the rect's
// bottom-center — that is the point the % coordinate names, and where the handle rides.
function positionMapPinHandle(pin) {
  const rect = pin.node.getBoundingClientRect();
  pin.handle.style.left = `${rect.left + rect.width / 2}px`;
  pin.handle.style.top = `${rect.bottom}px`;
}

function beginMapPinDrag(event, pin) {
  event.preventDefault();
  const handle = pin.handle;
  handle.setPointerCapture(event.pointerId);
  handle.dataset.dragging = 'true';
  pin.node.classList.add('is-dragging');
  // The pointer delta is in screen px; convert to a % of the map image (the stage layer = the container) so
  // the exported value is in the same left-origin percentage renderAcademyMap writes.
  const containerRect = pin.container.getBoundingClientRect();
  const startX = event.clientX;
  const startY = event.clientY;
  const startOffset = { ...pin.offset };
  const move = (moveEvent) => {
    pin.offset = {
      x: startOffset.x + ((moveEvent.clientX - startX) / containerRect.width) * 100,
      y: startOffset.y + ((moveEvent.clientY - startY) / containerRect.height) * 100
    };
    applyMapPinOffset(pin);
    positionMapPinHandle(pin);
    updateCalibrationReadout();
  };
  const end = () => {
    handle.removeEventListener('pointermove', move);
    handle.removeEventListener('pointerup', end);
    handle.removeEventListener('pointercancel', end);
    delete handle.dataset.dragging;
    pin.node.classList.remove('is-dragging');
  };
  handle.addEventListener('pointermove', move);
  handle.addEventListener('pointerup', end);
  handle.addEventListener('pointercancel', end);
}

function createMapPinHandle(pin) {
  const handle = document.createElement('button');
  handle.type = 'button';
  handle.className = 'frame-decoration-calibration-handle frame-decoration-calibration-handle--pin';
  handle.dataset.calibrationId = `${pin.entry.id}:${pin.pinId}`;
  handle.dataset.calibrationPinId = pin.pinId;
  handle.setAttribute('aria-label', `${pin.pinId} を移動`);
  const label = document.createElement('span');
  label.className = 'frame-decoration-calibration-handle-label';
  label.textContent = pin.pinId;
  handle.append(label);
  handle.addEventListener('pointerdown', (event) => beginMapPinDrag(event, pin));
  pin.handle = handle;
  return handle;
}

function buildCalibrationPanel(corners, pinGroups) {
  const panel = document.createElement('div');
  panel.className = 'frame-decoration-calibration-panel';
  const heading = document.createElement('h2');
  heading.textContent = 'フレーム装飾 校正モード';
  const help = document.createElement('p');
  help.textContent = 'ハンドルをドラッグして位置を合わせ、下のテキストをコピーして Lead に渡してください。';
  panel.append(heading, help);
  const actions = document.createElement('div');
  actions.className = 'frame-decoration-calibration-actions';

  let cornerReadout = null;
  let cornerExport = null;
  if (corners.length) {
    cornerReadout = document.createElement('ul');
    cornerReadout.className = 'frame-decoration-calibration-readout';
    cornerExport = document.createElement('textarea');
    cornerExport.className = 'frame-decoration-calibration-export';
    cornerExport.readOnly = true;
    panel.append(cornerReadout, cornerExport);
    actions.append(buildCalibrationCopyButton('CSSをコピー', 'copy-corners', () => cornerExport.value));
  }

  for (const group of pinGroups) {
    const sectionLabel = document.createElement('p');
    sectionLabel.className = 'frame-decoration-calibration-section-label';
    sectionLabel.textContent = `${group.entry.label}（表示 ${group.pins.length} 件 / 出力 ${Object.keys(group.baseCoordinates).length} 件）`;
    const readout = document.createElement('ul');
    readout.className = 'frame-decoration-calibration-readout frame-decoration-calibration-pin-readout';
    const exportBox = document.createElement('textarea');
    exportBox.className = 'frame-decoration-calibration-export frame-decoration-calibration-pin-export';
    exportBox.readOnly = true;
    group.readout = readout;
    group.exportBox = exportBox;
    panel.append(sectionLabel, readout, exportBox);
    actions.append(buildCalibrationCopyButton('ピン座標JSをコピー', 'copy-pins', () => exportBox.value));
  }

  const resetButton = document.createElement('button');
  resetButton.type = 'button';
  resetButton.textContent = '既定に戻す';
  resetButton.dataset.calibrationAction = 'reset';
  resetButton.addEventListener('click', () => {
    const state = frameDecorationCalibrationState;
    // Restore every target to its captured baseline (the declared/baked start), not a hardcoded 0 / seed value.
    restoreCalibrationBaselines(state.corners);
    for (const entry of state.corners) {
      applyCalibrationOffset(entry);
      positionCalibrationHandle(entry);
    }
    for (const group of state.pinGroups) {
      restoreCalibrationBaselines(group.pins);
      for (const pin of group.pins) {
        applyMapPinOffset(pin);
        positionMapPinHandle(pin);
      }
    }
    updateCalibrationReadout();
  });
  actions.append(resetButton);
  panel.append(actions);
  return { panel, cornerReadout, cornerExport };
}

// No ad-hoc alternate path / silent fallback: copy requires the async clipboard API. When it is genuinely
// unavailable it surfaces an explicit error rather than quietly doing something else — the always-visible
// read-only export box is the manual copy affordance, and the button stays truthful.
function buildCalibrationCopyButton(labelText, action, getExportText) {
  const button = document.createElement('button');
  button.type = 'button';
  button.textContent = labelText;
  button.dataset.calibrationAction = action;
  button.addEventListener('click', () => {
    if (typeof navigator.clipboard?.writeText !== 'function') {
      reportError(new Error('クリップボード API (navigator.clipboard.writeText) が使えません。下のテキストボックスから手動でコピーしてください。'));
      return;
    }
    navigator.clipboard.writeText(getExportText()).catch(reportError);
  });
  return button;
}

function buildFrameDecorationCalibrationOverlay(cornerTargets, pinGroupTargets) {
  const corners = cornerTargets.map(resolveCalibrationTarget);
  const pinGroups = pinGroupTargets.map((entry) => ({
    entry,
    pins: resolveMapPinCalibrationPins(entry),
    coordinatesName: entry.coordinatesName,
    baseCoordinates: MAP_PIN_CALIBRATION_COORDINATE_SOURCES[entry.coordinatesName],
    readout: null,
    exportBox: null
  }));
  const layer = document.createElement('div');
  layer.className = 'frame-decoration-calibration-layer';
  const { panel, cornerReadout, cornerExport } = buildCalibrationPanel(corners, pinGroups);
  layer.append(panel);
  for (const entry of corners) layer.append(createCalibrationHandle(entry));
  for (const group of pinGroups) for (const pin of group.pins) layer.append(createMapPinHandle(pin));
  document.body.append(layer);
  frameDecorationCalibrationState = { corners, pinGroups, layer, cornerReadout, cornerExport };
  repositionCalibrationHandles();
  updateCalibrationReadout();
  window.addEventListener('resize', repositionCalibrationHandles);
  window.addEventListener('scroll', repositionCalibrationHandles, true);
}

// Switch the multi-region map screen to the ?region= selector before the map-pin overlay is built. A region id
// that is not a known map region fail-fasts (mirrors the unknown-screen fail-fast) instead of silently routing
// through the default-region behavior of mapRegionDefinition — a wrong ?region= is a broken invocation, not a
// state to degrade past.
function applyCalibrationMapRegion(region) {
  const known = ACADEMY_MAP_REGIONS.some((definition) => definition.id === region);
  if (!known) {
    throw new Error(`?calibrate region ${JSON.stringify(region)} is not a known map region (known: ${ACADEMY_MAP_REGIONS.map((definition) => definition.id).join(', ')})`);
  }
  setActiveMapRegion(region);
}

function activateFrameDecorationCalibration(screen) {
  validateCalibrationRegistry(FRAME_DECORATION_CALIBRATION_TARGETS);
  validateMapPinCalibrationRegistry(MAP_PIN_CALIBRATION_TARGETS);
  const region = readCalibrationRegion(window.location.search);
  const { corners, pins } = calibrationTargetsForScreen(screen);
  showScreen(screen);
  // Build the overlay after the screen has laid out so the anchor / pin rects (and thus handle positions) are real.
  requestAnimationFrame(() => {
    // The map screen hosts several regions on one DOM; ?region= switches to the one being calibrated so its
    // background + live pins render. Absent, the screen keeps its default region. Only the pin groups whose
    // region is active are built, so exactly one region's pins are calibrated at a time.
    if (region !== null) applyCalibrationMapRegion(region);
    const activePins = pins.filter((entry) => entry.region === activeMapRegion);
    if (pins.length > 0 && activePins.length === 0) {
      throw new Error(`no map-pin calibration group for screen ${JSON.stringify(screen)} region ${JSON.stringify(activeMapRegion)} (registered regions: ${[...new Set(pins.map((entry) => entry.region))].join(', ')})`);
    }
    buildFrameDecorationCalibrationOverlay(corners, activePins);
  });
}

function applyFrameDecorationCalibrationOverride() {
  const screen = readCalibrationScreen(window.location.search);
  if (screen === null) return;
  activateFrameDecorationCalibration(screen);
}

// ===== 競売場 (auction) screen =====
// A conversation-day-family content screen (its own screen-scoped --auction-* token layer) driven entirely from
// the frontend across the auction's per-utterance HTTP surface (spec auction.md「HTTP surface」). The persisted
// granularity is the LOT: the slot advances only at resolve. A lot's in-progress bidding (current price / standing
// highest bidder / who has dropped / turn cursor) is held HERE and re-validated server-side against the
// authoritative slot each request; a reload restarts the current lot's bidding from the top. The chat reuses the
// shared conversation-stage reveal machinery (createConversationStage + createTurnReveal); the board and the
// numeric bid bar are app.js-owned — the auction analogue of the daytime stage-image slot. The SSE reader is
// consumer-owned (the auction's result shape { lot_index, utterance, ... } is not conversation-shaped, so the
// shared runAssistantSseStream is not reused).

// The authored auctioneer master: a non-selectable actor (atelier-actor 流儀) resolved by sourceSheetImageUrl so
// the master's face renders from its own authored visual set (auction_garou) rather than borrowing the roster head.
// NPC bidders / reaction characters are seated selectable-roster characters and resolve from selectableCharacters
// by their character_id. No default-face / placeholder fallback: an unresolved id fails at sourceSheetImageUrl.
const AUCTION_MASTER_ACTOR = Object.freeze({
  character_id: 'auction_garou',
  display_name: '競売人ガロウ',
  visual_set_id: 'auction_garou',
  face_url: '/canonical/character_visual_sets/auction_garou/face_emotions/neutral.jpg'
});
const AUCTION_PLAYER_WINNER_ID = 'player';
const AUCTION_PLAYER_LABEL = 'あなた';
// 競売場 is a routing-only destination (the auction API rejects non-routing with 409 ROUTING_MODE_REQUIRED), so its
// post-content return is always the routing hub — the exact value resolvePostContentScreen({ mode: 'routing' })
// yields server-side and the value returnToRoutingHubFromContent requires. Held as this invariant rather than a
// silently-defaulted screen id.
const AUCTION_POST_CONTENT_SCREEN = 'interaction';
// Authored 地の演出 (LLM 非関与): the 流札 line and the between-lot murmurs that fill the serial-LM gaps.
const AUCTION_PASSED_IN_NARRATION = 'どこからも声は上がらず、槌は静かに置かれた。この品は流れ、また別の宵を待つ。';
// A player-won 籠入りの生き物 (house lot) is not an inventory item — it goes onto the 星の揺り籠 caged surface
// (backend writer). This screen otherwise has no way to show that destination, so an authored 地の文 names it; the
// identifying part (the lot name) comes straight from the view — the frontend never re-derives 品種/band.
function auctionCagedCreatureAwardNarration(lot) {
  return `落札した「${lot.name}」は、星の揺り籠の籠入りに迎え入れられた。`;
}
const AUCTION_MURMUR_POOL = Object.freeze([
  '会場のあちこちで、値踏みするようなざわめきが起こる。',
  'ランタンの灯が揺れ、天鵞絨の緞帳がかすかに波打つ。',
  '扇を鳴らす音、囁き交わす声——宵の会場が次の品を待って熱を帯びていく。',
  '槌の余韻が消え、燭台の炎だけが小さく爆ぜた。'
]);
let auctionMurmurCursor = 0;

function auctionActorById(characterId) {
  return characterId === AUCTION_MASTER_ACTOR.character_id ? AUCTION_MASTER_ACTOR : null;
}

function auctionMasterSpeaker() {
  return { character_id: AUCTION_MASTER_ACTOR.character_id, character_name: AUCTION_MASTER_ACTOR.display_name };
}

// Auction session state (frontend-carried; not persisted — see the module header).
let auctionSlotView = null;        // last GET/enter/resolve state view (bidders / lots / awards / current_lot_index / status)
let auctionBidState = null;        // { current, highestBidder, highestBidderName, history[], activeNpcIds:Set, playerActive }
let auctionCurrentSpeaker = auctionMasterSpeaker(); // fed to the stage surface's assistantIdentity (inert for the custom reader)
let auctionFlowInFlight = false;   // guards the re-entrant showScreen during a loading transition and double-drive
let auctionActionInFlight = false; // single-flight guard for a player bid / pass submission
let auctionPlayerResolve = null;   // resolves the pending player-turn promise when the bid / drop button is pressed
let auctionMoney = null;           // last known player money, for the bid-bar validation + board display
let auctionLotGoaded = false;      // one master goad per lot before the player's standing-bid decision
let auctionMasterUtterances = [];  // this visit's already-spoken master 口上 (opening/goad/hammer), carried to each
                                   // master request so the model varies each 口上 (反復回避ハンドオフ). Not persisted;
                                   // a reload restarts the visit and this accumulator (per-utterance design).
// 出品側 (player-consignment) session state (frontend-carried; not persisted — same lot-granular design as the house
// lots). The consignment lot runs before the house lots when the player lists an asset this visit.
let auctionConsignmentView = null;        // the current visit's consignment view (state.consignment / submit response): { status, presentation, band, initial_price, min_increment, ... }
let auctionConsignmentChoiceResolve = null; // resolves the 出品/skip picker choice ({ kind:'submit', source } | { kind:'skip' })
let auctionPhase = null;                   // 'picker' | 'consignment' | 'house' | 'closed' — the entry phase, read post-cover to choose what to render
// The 流札 line for a consignment lot: unlike a house-lot 流札 (the品 flows away), the player's own unsold asset
// stays with them — the authored 地の文 says so (authored, LLM 非関与).
const AUCTION_CONSIGNMENT_PASSED_IN_NARRATION = 'どこからも声は上がらず、槌は静かに置かれた。この品は落札されず、あなたの手元に残った。';

const auctionStage = createConversationStage({
  screenSelector: '#academy-auction-screen',
  streamSelector: '#academy-auction-message-stream',
  statusSelector: '#academy-auction-status',
  controlSelectors: ['#academy-auction-bid-input', '#academy-auction-bid', '#academy-auction-drop'],
  weekSelector: '#academy-auction-week',
  moonSelector: '#academy-auction-moon-phase',
  respondingClass: 'is-auction-responding',
  playerSpokeClass: 'is-auction-player-spoke',
  dispatchClimaxClass: 'is-auction-dispatch-climax',
  playerSpokeMs: 600,
  dispatchClimaxMs: 900,
  weekTotal: CONVERSATION_DAY_TOTAL_WEEKS,
  moonPhaseCount: 8,
  weekLabel: (week, total) => `第${week}週 / ${total}`,
  moonAriaLabel: (phase, count) => `月相 ${phase + 1} / ${count}`,
  currentWeek: () => conversationStageWeek(currentRuntimeState?.elapsed_weeks),
  personaVisual: () => null,
  assistantIdentity: () => auctionCurrentSpeaker,
  refresh: () => refresh(),
  ambient: createConversationDayAmbient({ canvasSelector: '#academy-auction-motes', moteColorRgb: '240, 178, 74', moteCount: 64 }),
  // The auction screen has no info drawer / category rail: these selectors resolve to no nodes, so openInfo is
  // never reached (no category buttons) and closeInfo / setActiveCategory are guarded no-ops.
  infoPopupSelector: '#academy-auction-info-popup',
  infoTitleSelector: '#academy-auction-info-popup-title',
  infoBodySelector: '#academy-auction-info-popup-body',
  infoIconSelector: '#academy-auction-info-popup-icon',
  categoryButtonSelector: '.academy-auction-category-button',
  categoryDataKey: 'auctionCategory',
  categoryTitles: {},
  categoryIconUrl: (category) => `/canonical/auction/icons/${category}.png`,
  categoryRenderers: {}
}, {
  displayMessages,
  createMessageRows,
  messagesFromConversation,
  conversationPopupCooldownMs,
  sleep,
  setActorImageSource
});

function reportAuctionScreenError(error) {
  if (handleRuntimeApiError(error, { allowSettingsRedirect: true })) return;
  // AUCTION_GENERATION_FAILED is a 503 that is NOT an LM-config/connection error (which the redirect above
  // handles): the generation gate rejected the LLM output. Surface it as retryable rather than sending the
  // player to settings.
  if (error?.errorCode === 'AUCTION_GENERATION_FAILED') {
    auctionStage.setStatus('生成に失敗しました。もう一度お試しください。', { tone: 'error' });
    console.error(error);
    return;
  }
  auctionStage.setStatus(errorDisplayMessage(error), { tone: 'error' });
  console.error(error);
}

function auctionLotView(lotIndex) {
  const lot = auctionSlotView?.lots?.find((entry) => entry.lot_index === lotIndex);
  if (!lot) throw new Error(`auction lot view not found for index ${lotIndex}`);
  return lot;
}

function auctionCurrentLotView() {
  if (!auctionSlotView || auctionSlotView.current_lot_index >= auctionSlotView.lots.length) return null;
  return auctionLotView(auctionSlotView.current_lot_index);
}

function showAuctionLive() {
  const live = document.querySelector('#academy-auction-live');
  const closed = document.querySelector('#academy-auction-closed');
  const consignment = document.querySelector('#academy-auction-consignment');
  if (live) live.hidden = false;
  if (closed) closed.hidden = true;
  if (consignment) consignment.hidden = true;
}

// Shows the 出品 picker overlay (before the house lots), hiding the live board/chat and the closed view.
function showAuctionConsignmentPicker() {
  const live = document.querySelector('#academy-auction-live');
  const closed = document.querySelector('#academy-auction-closed');
  const consignment = document.querySelector('#academy-auction-consignment');
  if (live) live.hidden = true;
  if (closed) closed.hidden = true;
  if (consignment) consignment.hidden = false;
}

function hideAuctionConsignmentPicker() {
  const consignment = document.querySelector('#academy-auction-consignment');
  if (consignment) consignment.hidden = true;
}

// The board's 「あなたの出品」 badge is shown only while the player's own consignment lot is on the board.
function setAuctionConsignorBadge(visible) {
  const badge = document.querySelector('#academy-auction-consignor-badge');
  if (badge) badge.hidden = !visible;
}

// The auction assistant bubble carries its OWN speaker identity (master / a seated bidder), so createMessageRows
// resolves the right face via sourceSheetImageUrl per message (the master through auctionActorById, a bidder
// through the selectable roster). Emotion is always neutral (the SSE result carries none).
function auctionMessage(speaker, content) {
  // No emotion travels the auction SSE result, so every auction bubble is the actor's neutral face — carried as
  // expression:'neutral' (createMessageRows resolves the neutral face_emotions route from it). The
  // face_emotion_variant_id is left to createMessageRows' default so this does not pin a neutral icon variant.
  return {
    role: 'assistant',
    character_id: speaker.character_id,
    character_name: speaker.character_name,
    content,
    expression: 'neutral'
  };
}

// Consumer-owned SSE reader for one auction speech (master 口上 / goad / hammer, character reaction). Frames events
// exactly like the shared stream helper (event:/data: over \n\n blocks) but returns the auction result payload
// ({ lot_index, utterance, ... }). onStreamStart fires once on the first token so the entry loading cover can
// release on the opening's first stream.
async function readAuctionSpeechSse(endpoint, body, { onDelta, onComplete, onStreamStart = null }) {
  const response = await fetch(endpoint, {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify(body)
  });
  if (!response.ok) {
    const text = await response.text();
    throw createApiError({ url: endpoint, status: response.status, payload: parseJsonText(text), fallbackText: text });
  }
  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let buffer = '';
  let finalResult = null;
  let streamStarted = false;
  const notifyStreamStarted = () => {
    if (streamStarted) return;
    streamStarted = true;
    onStreamStart?.();
  };
  const noteLoadingDelta = createLoadingProgressDeltaThrottle();
  const handleBlock = (block) => {
    const event = block.split('\n').find((line) => line.startsWith('event: '))?.slice(7);
    const dataText = block.split('\n').find((line) => line.startsWith('data: '))?.slice(6);
    const data = dataText ? JSON.parse(dataText) : null;
    if (event === 'assistant_delta') { notifyStreamStarted(); noteLoadingDelta(); onDelta(data.delta ?? ''); }
    if (event === 'assistant_complete') { notifyStreamStarted(); notifyAcademyLoadingProgress(); onComplete(data.content ?? ''); }
    if (event === 'result') { finalResult = data; notifyAcademyLoadingProgress(); }
    if (event === 'error') throw createApiError({ url: endpoint, status: 503, payload: data, fallbackText: data?.error ?? '' });
  };
  while (true) {
    const { value, done } = await reader.read();
    buffer += decoder.decode(value ?? new Uint8Array(), { stream: !done });
    const blocks = buffer.split('\n\n');
    buffer = blocks.pop() ?? '';
    for (const block of blocks) if (block.trim()) handleBlock(block);
    if (done) break;
  }
  if (buffer.trim()) handleBlock(buffer);
  if (!finalResult) throw new Error('auction speech stream ended without a final result');
  return finalResult;
}

// Streams one speech, revealing completed 吹き出し単位 through the shared reveal queue as they arrive, then commits
// the finished utterance to the stage history. On failure the reveal is cancelled and the pre-speech history is
// restored (no half-revealed bubble left behind).
async function revealAuctionSpeech({ speaker, endpoint, body, onStreamStart = null }) {
  auctionCurrentSpeaker = { character_id: speaker.character_id, character_name: speaker.character_name };
  const base = [...auctionStage.surface.getHistory()];
  const reveal = auctionStage.createTurnReveal(base);
  let fullText = '';
  let segCount = 0;
  const enqueueFrom = (text) => {
    if (!text.trim()) return;
    const segments = displayMessages([auctionMessage(speaker, text)]).filter((segment) => (segment.content ?? '').trim());
    const fresh = segments.slice(segCount);
    segCount += fresh.length;
    reveal.enqueue(fresh);
  };
  let result = null;
  try {
    result = await readAuctionSpeechSse(endpoint, body, {
      onStreamStart,
      onDelta: (delta) => { fullText += delta; enqueueFrom(completedAssistantPrefix(fullText)); },
      onComplete: (content) => { fullText = content || fullText; enqueueFrom(fullText); }
    });
    await reveal.drain();
  } catch (error) {
    reveal.cancel();
    auctionStage.surface.setHistory(base);
    auctionStage.renderStream(base);
    throw error;
  }
  auctionStage.surface.setHistory([...base, auctionMessage(speaker, fullText)]);
  return result;
}

// Records a just-spoken master 口上 into this visit's accumulator, which is sent to every subsequent master request
// as the 反復回避ハンドオフ (so the model does not open every lot with the same 賛辞). Returns the result unchanged.
function recordAuctionMasterUtterance(result) {
  const text = String(result?.utterance ?? '').trim();
  if (text) auctionMasterUtterances.push(text);
  return result;
}

// Reveals one already-generated utterance (an NPC bid decision is a JSON turn, not SSE) through the same pop-in
// reveal queue so it obeys the shared 吹き出し単位・等間隔 discipline.
async function revealAuctionUtterance(speaker, text) {
  if (!String(text ?? '').trim()) return;
  auctionCurrentSpeaker = { character_id: speaker.character_id, character_name: speaker.character_name };
  const base = [...auctionStage.surface.getHistory()];
  const message = auctionMessage(speaker, text);
  const reveal = auctionStage.createTurnReveal(base);
  reveal.enqueue(displayMessages([message]).filter((segment) => (segment.content ?? '').trim()));
  await reveal.drain();
  auctionStage.surface.setHistory([...base, message]);
}

// Appends an authored 地の文 (流札 / murmur) as a narration bubble with the same cooldown-paced pop-in.
async function appendAuctionNarration(text) {
  const base = [...auctionStage.surface.getHistory()];
  const message = { role: 'narration', content: text, face_emotion_variant_id: 'narration_face', expression: 'narration' };
  const next = [...base, message];
  auctionStage.surface.setHistory(next);
  auctionStage.renderStream(next, { popFromDisplayIndex: displayMessages(base).length });
  await sleep(conversationPopupCooldownMs());
}

// Appends the player's own ground-text (bid / pass) as a right-side narration bubble.
async function appendAuctionPlayerNarration(text) {
  const base = [...auctionStage.surface.getHistory()];
  const message = { role: 'player-narration', content: text };
  const next = [...base, message];
  auctionStage.surface.setHistory(next);
  auctionStage.renderStream(next, { popFromDisplayIndex: displayMessages(base).length });
  await sleep(conversationPopupCooldownMs());
}

function nextAuctionMurmur() {
  const line = AUCTION_MURMUR_POOL[auctionMurmurCursor % AUCTION_MURMUR_POOL.length];
  auctionMurmurCursor += 1;
  return line;
}

// ----- board / bid-bar rendering -----

function pulseAuctionFigure(selector) {
  const value = document.querySelector(selector);
  const figure = value?.closest('.academy-auction-figure');
  if (!figure) return;
  figure.classList.remove('is-updated');
  void figure.offsetWidth;
  figure.classList.add('is-updated');
}

function renderAuctionHistory() {
  const list = document.querySelector('#academy-auction-history');
  if (!list) return;
  // A null bid state means no bids yet on the current lot (a fresh lot switch, before initAuctionBidState): clear the
  // prior lot's rows rather than leaving them stale beneath the new lot's board.
  if (!auctionBidState) { list.replaceChildren(); return; }
  list.replaceChildren(...auctionBidState.history.map((entry, index) => {
    const li = document.createElement('li');
    li.dataset.action = entry.action;
    if (index === auctionBidState.history.length - 1) li.classList.add('is-fresh');
    li.textContent = entry.action === 'bid' ? `${entry.display_name}：${entry.amount}G` : `${entry.display_name}：降りた`;
    return li;
  }));
  list.scrollTop = list.scrollHeight;
}

function renderAuctionBoardFromState({ pulse = false } = {}) {
  const lot = auctionCurrentLotView();
  if (!lot) return;
  const set = (selector, text) => { const node = document.querySelector(selector); if (node) node.textContent = text; };
  set('#academy-auction-board-category', lot.category_label);
  set('#academy-auction-board-name', lot.name);
  set('#academy-auction-board-blurb', lot.blurb);
  set('#academy-auction-lot-progress', `ロット ${lot.lot_index + 1} / ${auctionSlotView.lots.length}`);
  const current = auctionBidState ? auctionBidState.current : lot.initial_price;
  const highestName = auctionBidState?.highestBidder === AUCTION_PLAYER_WINNER_ID
    ? AUCTION_PLAYER_LABEL
    : (auctionBidState?.highestBidderName ?? 'まだなし');
  set('#academy-auction-current', `${current}G`);
  set('#academy-auction-highest', highestName);
  set('#academy-auction-increment', `${lot.min_increment}G`);
  set('#academy-auction-money', auctionMoney !== null ? `${auctionMoney}G` : '—');
  renderAuctionHistory();
  setAuctionConsignorBadge(false); // a house lot is never the player's own listing
  if (pulse) {
    pulseAuctionFigure('#academy-auction-current');
    pulseAuctionFigure('#academy-auction-highest');
  }
}

// Renders the board for the player's own consignment lot: the listing presentation (not a house lot view), the
// 「あなたの出品」 badge, and the NPC-only bid figures. The player money is shown for context but there is no bid bar.
function renderAuctionConsignmentBoardFromState({ pulse = false } = {}) {
  if (!auctionConsignmentView) return;
  const set = (selector, text) => { const node = document.querySelector(selector); if (node) node.textContent = text; };
  const presentation = auctionConsignmentView.presentation;
  set('#academy-auction-board-category', presentation.category_label);
  set('#academy-auction-board-name', presentation.name);
  set('#academy-auction-board-blurb', presentation.blurb);
  set('#academy-auction-lot-progress', '出品ロット');
  const current = auctionBidState ? auctionBidState.current : auctionConsignmentView.initial_price;
  // The player never bids on their own lot, so the highest bidder is always a seated NPC or まだなし (never あなた).
  const highestName = auctionBidState?.highestBidderName ?? 'まだなし';
  set('#academy-auction-current', `${current}G`);
  set('#academy-auction-highest', highestName);
  set('#academy-auction-increment', `${auctionConsignmentView.min_increment}G`);
  set('#academy-auction-money', auctionMoney !== null ? `${auctionMoney}G` : '—');
  renderAuctionHistory();
  setAuctionConsignorBadge(true);
  if (pulse) {
    pulseAuctionFigure('#academy-auction-current');
    pulseAuctionFigure('#academy-auction-highest');
  }
}

function renderAuctionScreenChrome() {
  auctionStage.renderWeekAndMoon();
  auctionStage.startAmbient();
}

function setAuctionBidNote(text) {
  const note = document.querySelector('#academy-auction-bid-note');
  if (!note) return;
  const message = String(text ?? '').trim();
  note.hidden = !message;
  note.textContent = message;
}

function disableAuctionBidControls(disabled) {
  for (const selector of ['#academy-auction-bid-input', '#academy-auction-bid', '#academy-auction-drop']) {
    const node = document.querySelector(selector);
    if (node) node.disabled = disabled;
  }
}

function setAuctionBidBarActive(active, lot = null) {
  disableAuctionBidControls(!active);
  const bar = document.querySelector('#academy-auction-bid-bar');
  if (bar) bar.dataset.active = active ? 'true' : 'false';
  const input = document.querySelector('#academy-auction-bid-input');
  if (active && lot && input) {
    input.min = String(lot.min_increment);
    input.placeholder = `上乗せ額（最低${lot.min_increment}G）`;
  }
  if (!active) setAuctionBidNote('');
}

// ----- bid state machine -----

function initAuctionBidState(lot) {
  auctionBidState = {
    current: lot.initial_price,
    highestBidder: null,
    highestBidderName: null,
    history: [],
    activeNpcIds: new Set(auctionSlotView.bidders.map((bidder) => bidder.character_id)),
    playerActive: true
  };
}

function auctionActiveParticipantCount() {
  return auctionBidState.activeNpcIds.size + (auctionBidState.playerActive ? 1 : 0);
}

// The lot is ready to resolve when no one is left to raise: with a standing highest bid, when the only remaining
// active participant is that highest bidder (everyone else dropped); with no bid at all, only once everyone has
// dropped (a 流札). The current highest bidder never drops (they are skipped on their own turn), so an
// active-count of 1 with a standing bid is always the highest bidder alone.
function auctionLotResolutionReady() {
  const active = auctionActiveParticipantCount();
  if (auctionBidState.highestBidder === null) return active === 0;
  return active <= 1;
}

function requestAuctionNpcBid(lotIndex, bidder) {
  return postJson('/api/auction/npc-bid', {
    lot_index: lotIndex,
    character_id: bidder.character_id,
    current: auctionBidState.current,
    highest_bidder: auctionBidState.highestBidder,
    highest_bidder_name: auctionBidState.highestBidderName,
    history: auctionBidState.history.slice()
  });
}

function applyAuctionNpcDecision(bidder, decision) {
  if (decision.action === 'bid') {
    auctionBidState.current = decision.current;            // server-revalidated standing amount
    auctionBidState.highestBidder = decision.highest_bidder; // = bidder.character_id
    auctionBidState.highestBidderName = bidder.display_name;
    auctionBidState.history.push({ display_name: bidder.display_name, action: 'bid', amount: decision.current });
  } else {
    auctionBidState.activeNpcIds.delete(bidder.character_id);
    auctionBidState.history.push({ display_name: bidder.display_name, action: 'pass' });
  }
}

// One sub-round of NPC bids over `askList` (this round's active, non-highest seated bidders, in seated order).
// 数珠つなぎ (1本先行・並列発射なし): the next bidder's request is fired as soon as the current bidder's decision
// returns (so the serial LM generates it while the current utterance reveals) — never two requests in flight.
async function runAuctionNpcSubRound(lotIndex, askList) {
  let pending = askList.length ? requestAuctionNpcBid(lotIndex, askList[0]) : null;
  for (let i = 0; i < askList.length; i += 1) {
    const bidder = askList[i];
    const decision = await pending;
    applyAuctionNpcDecision(bidder, decision);
    pending = (i + 1 < askList.length) ? requestAuctionNpcBid(lotIndex, askList[i + 1]) : null;
    await revealAuctionUtterance({ character_id: bidder.character_id, character_name: bidder.display_name }, decision.utterance);
    renderAuctionBoardFromState({ pulse: decision.action === 'bid' });
    if (auctionLotResolutionReady()) break;
  }
}

// Suspends the flow for the player's turn; resolved by the bid / drop button handlers (submitAuctionPlayerBid /
// submitAuctionPlayerPass), which continue the loop.
function runAuctionPlayerTurn(lot) {
  return new Promise((resolve) => {
    auctionPlayerResolve = resolve;
    setAuctionBidBarActive(true, lot);
  });
}

async function runAuctionBidLoop(lotIndex) {
  const lot = auctionLotView(lotIndex);
  initAuctionBidState(lot);
  auctionLotGoaded = false;
  // A being lot with no free 錬成室 slot cannot be adopted: disable the player's bidding and say why (never a
  // silent hide). The player watches the seated bidders contest it.
  const playerCanBid = !(lot.category === 'being' && lot.adoptable === false);
  if (!playerCanBid) {
    auctionBidState.playerActive = false;
    setAuctionBidBarActive(false);
    setAuctionBidNote('錬成室の枠が空いていないため、この品には入札できません。');
  }
  renderAuctionBoardFromState();
  while (!auctionLotResolutionReady()) {
    const askList = auctionSlotView.bidders.filter((bidder) =>
      auctionBidState.activeNpcIds.has(bidder.character_id) && auctionBidState.highestBidder !== bidder.character_id);
    if (askList.length) await runAuctionNpcSubRound(lotIndex, askList);
    if (auctionLotResolutionReady()) break;
    if (auctionBidState.playerActive && auctionBidState.highestBidder !== AUCTION_PLAYER_WINNER_ID) {
      if (!auctionLotGoaded && auctionBidState.highestBidder !== null) {
        auctionLotGoaded = true;
        recordAuctionMasterUtterance(await revealAuctionSpeech({
          speaker: auctionMasterSpeaker(),
          endpoint: '/api/auction/lot/goad/stream',
          body: { lot_index: lotIndex, current: auctionBidState.current, bidder_name: auctionBidState.highestBidderName, prior_utterances: auctionMasterUtterances.slice() }
        }));
      }
      await runAuctionPlayerTurn(lot);
    }
    if (auctionLotResolutionReady()) break;
    // No NPC could be asked this round and the player is highest or has dropped: no further raise is possible.
    if (!askList.length && (auctionBidState.highestBidder === AUCTION_PLAYER_WINNER_ID || !auctionBidState.playerActive)) break;
  }
  await resolveAuctionCurrentLot(lotIndex);
}

async function submitAuctionPlayerBid() {
  if (!auctionPlayerResolve) return;
  if (auctionActionInFlight) { showProcessingToast(); return; }
  const lot = auctionCurrentLotView();
  if (!lot) return;
  const input = document.querySelector('#academy-auction-bid-input');
  const add = Number((input?.value ?? '').trim());
  if (!Number.isInteger(add) || add <= 0) { setAuctionBidNote('上乗せ額は正の整数で入力してください。'); return; }
  if (add < lot.min_increment) { setAuctionBidNote(`最低増分は${lot.min_increment}Gです。それ以上を上乗せしてください。`); return; }
  const nextPrice = auctionBidState.current + add;
  if (auctionMoney !== null && nextPrice > auctionMoney) { setAuctionBidNote(`入札額${nextPrice}Gが所持金${auctionMoney}Gを超えています。`); return; }
  auctionActionInFlight = true;
  disableAuctionBidControls(true);
  try {
    const result = await postJson('/api/auction/bid', { lot_index: lot.lot_index, current: auctionBidState.current, add_amount: add });
    auctionBidState.current = result.current;
    auctionBidState.highestBidder = AUCTION_PLAYER_WINNER_ID;
    auctionBidState.highestBidderName = AUCTION_PLAYER_LABEL;
    auctionBidState.history.push({ display_name: AUCTION_PLAYER_LABEL, action: 'bid', amount: result.current });
    auctionMoney = result.money;
    if (input) input.value = '';
    setAuctionBidNote('');
    setAuctionBidBarActive(false);
    await appendAuctionPlayerNarration(`${result.current}Gで競り上げた。`);
    renderAuctionBoardFromState({ pulse: true });
    const resolve = auctionPlayerResolve;
    auctionPlayerResolve = null;
    resolve();
  } catch (error) {
    const reason = auctionBidErrorReason(error);
    if (reason) {
      setAuctionBidNote(reason);
      disableAuctionBidControls(false); // let the player revise the amount and retry
    } else {
      reportAuctionScreenError(error);
      disableAuctionBidControls(false);
    }
  } finally {
    auctionActionInFlight = false;
  }
}

async function submitAuctionPlayerPass() {
  if (!auctionPlayerResolve) return;
  if (auctionActionInFlight) { showProcessingToast(); return; }
  const lot = auctionCurrentLotView();
  if (!lot) return;
  auctionActionInFlight = true;
  disableAuctionBidControls(true);
  try {
    await postJson('/api/auction/bid', { lot_index: lot.lot_index, pass: true });
    auctionBidState.playerActive = false;
    auctionBidState.history.push({ display_name: AUCTION_PLAYER_LABEL, action: 'pass' });
    setAuctionBidBarActive(false);
    await appendAuctionPlayerNarration('ここは見送ることにした。');
    renderAuctionBoardFromState();
    const resolve = auctionPlayerResolve;
    auctionPlayerResolve = null;
    resolve();
  } catch (error) {
    reportAuctionScreenError(error);
    disableAuctionBidControls(false);
  } finally {
    auctionActionInFlight = false;
  }
}

function auctionBidErrorReason(error) {
  if (error?.errorCode === 'AUCTION_BELOW_MIN_INCREMENT' || error?.errorCode === 'AUCTION_INSUFFICIENT_MONEY') {
    return error.message;
  }
  return null;
}

// Resolves the current lot: winner is the standing highest bidder ('player' | a seated character_id) or null
// (流札). An awarded lot gets the master's hammer 落札宣言 (streamed); a player win refreshes the authoritative
// money / equipment / inventory. A 流札 gets the authored 地の演出. On the third lot's resolution the auction
// closes and returns the closed view; otherwise the flow advances to the next lot.
async function resolveAuctionCurrentLot(lotIndex) {
  const lot = auctionLotView(lotIndex); // captured before the resolve reassigns auctionSlotView to the advanced slot
  const winner = auctionBidState.highestBidder;
  const amount = winner === null ? null : auctionBidState.current;
  setAuctionBidBarActive(false);
  const result = await postJson('/api/auction/lot/resolve', { lot_index: lotIndex, winner, amount });
  auctionSlotView = result.state;
  if (result.resolution.outcome === 'awarded') {
    recordAuctionMasterUtterance(await revealAuctionSpeech({ speaker: auctionMasterSpeaker(), endpoint: '/api/auction/lot/hammer/stream', body: { lot_index: lotIndex, prior_utterances: auctionMasterUtterances.slice() } }));
    if (winner === AUCTION_PLAYER_WINNER_ID) {
      await refresh();
      if (Number.isInteger(currentInventory?.money)) auctionMoney = currentInventory.money;
      // A 籠入りの生き物 win lands on the 星の揺り籠 caged surface, not in the inventory refresh above — name the
      // destination so the player sees where it went (the caged list itself picks it up on the next overlay open).
      if (lot.category === 'caged_creature') await appendAuctionNarration(auctionCagedCreatureAwardNarration(lot));
    }
  } else {
    await appendAuctionNarration(AUCTION_PASSED_IN_NARRATION);
  }
  if (result.resolution.closed) {
    // The third lot's 決着 speech (awarded: the hammer 口上 reveal / 流札: the authored 演出) is the last thing said
    // this visit. Hold it on screen for the shared reading pause (DRAIN_READING_PAUSE_MS — hub 見送り / 昼会話 達成
    // 自動終了 と単一ソース共有) before swapping to the closed view, so the closing words are legible instead of the
    // screen snapping away the moment they render.
    await sleep(DRAIN_READING_PAUSE_MS);
    renderAuctionClosed(auctionSlotView);
    return;
  }
  await appendAuctionNarration(nextAuctionMurmur());
  await runAuctionLot(auctionSlotView.current_lot_index);
}

// Runs one lot start-to-finish: master opening 口上 → seated-bidder reactions (prior_reactions chain) → bid loop.
async function runAuctionLot(lotIndex, { onOpeningStreamStart = null } = {}) {
  // The board follows the lot whose 口上 is being heard. Drop the prior lot's bid figures (initAuctionBidState only
  // runs once the bid loop starts, after the reactions) and paint this lot's board — fresh 初期額 / まだなし / empty
  // 履歴 — the instant its opening 口上 stream begins (onStreamStart = first token), not after the reactions play out.
  // The switch composes with any caller onStreamStart (e.g. the entry loading-cover release on the first lot).
  auctionBidState = null;
  recordAuctionMasterUtterance(await revealAuctionSpeech({
    speaker: auctionMasterSpeaker(),
    endpoint: '/api/auction/lot/opening/stream',
    body: { lot_index: lotIndex, prior_utterances: auctionMasterUtterances.slice() },
    onStreamStart: () => { renderAuctionBoardFromState(); onOpeningStreamStart?.(); }
  }));
  const priorReactions = [];
  for (const bidder of auctionSlotView.bidders) {
    const result = await revealAuctionSpeech({
      speaker: { character_id: bidder.character_id, character_name: bidder.display_name },
      endpoint: '/api/auction/lot/reaction/stream',
      body: { lot_index: lotIndex, character_id: bidder.character_id, prior_reactions: priorReactions.slice() }
    });
    priorReactions.push({ display_name: result.display_name, utterance: result.utterance });
  }
  await runAuctionBidLoop(lotIndex);
}

// ----- 出品側 (player-consignment) lot -----

// True when this entry should open the 出品 picker: no consignment decided yet (未決) and the house lots have not
// begun (current_lot_index 0 — the consignment window). A resolved / skipped consignment, or house bidding already
// underway, skips the picker.
function auctionConsignmentNeedsPicker(view) {
  return view.consignment === null && view.current_lot_index === 0;
}

// The consignment bid state is the house bid-state shape with the player permanently inactive: the player never
// bids on their own lot, so only seated NPCs contest it. auctionLotResolutionReady / auctionActiveParticipantCount
// then resolve NPC-only (highest alone → awarded, everyone passed → 流札) with no player branch.
function initAuctionConsignmentBidState() {
  auctionBidState = {
    current: auctionConsignmentView.initial_price,
    highestBidder: null,
    highestBidderName: null,
    history: [],
    activeNpcIds: new Set(auctionSlotView.bidders.map((bidder) => bidder.character_id)),
    playerActive: false
  };
}

function requestAuctionConsignmentNpcBid(bidder) {
  return postJson('/api/auction/consignment/npc-bid', {
    character_id: bidder.character_id,
    current: auctionBidState.current,
    highest_bidder: auctionBidState.highestBidder,
    highest_bidder_name: auctionBidState.highestBidderName,
    history: auctionBidState.history.slice()
  });
}

// One NPC sub-round over the consignment lot, mirroring the house sub-round's 数珠つなぎ (1本先行・並列発射なし):
// the next bidder's request is fired as the current decision returns, never two in flight.
async function runAuctionConsignmentNpcSubRound(askList) {
  let pending = askList.length ? requestAuctionConsignmentNpcBid(askList[0]) : null;
  for (let i = 0; i < askList.length; i += 1) {
    const bidder = askList[i];
    const decision = await pending;
    applyAuctionNpcDecision(bidder, decision);
    pending = (i + 1 < askList.length) ? requestAuctionConsignmentNpcBid(askList[i + 1]) : null;
    await revealAuctionUtterance({ character_id: bidder.character_id, character_name: bidder.display_name }, decision.utterance);
    renderAuctionConsignmentBoardFromState({ pulse: decision.action === 'bid' });
    if (auctionLotResolutionReady()) break;
  }
}

// NPC-only round-robin over the consignment lot: seated order, pass = drop, the highest bidder skips its own turn,
// and it ends when only the highest remains (awarded) or everyone passed (流札). No player turn, no goad.
async function runAuctionConsignmentBidLoop() {
  initAuctionConsignmentBidState();
  renderAuctionConsignmentBoardFromState();
  while (!auctionLotResolutionReady()) {
    const askList = auctionSlotView.bidders.filter((bidder) =>
      auctionBidState.activeNpcIds.has(bidder.character_id) && auctionBidState.highestBidder !== bidder.character_id);
    if (!askList.length) break; // only the highest bidder (or no one) remains — already resolution-ready
    await runAuctionConsignmentNpcSubRound(askList);
  }
}

// Resolves the consignment lot: the winner is the standing highest NPC bidder (a seated character_id) or null (流札
// — the asset stays with the player). An awarded lot gets the master's hammer 落札宣言 (streamed) and credits the
// payout (payout.money is the authoritative post-credit money); a 流札 gets the authored 品が残る 地の演出. Either
// way the flow then advances to the house lots (the consignment does not advance the house slot).
async function resolveAuctionConsignmentLot() {
  const winner = auctionBidState.highestBidder; // a seated character_id or null — never 'player'
  const amount = winner === null ? null : auctionBidState.current;
  const result = await postJson('/api/auction/consignment/resolve', { winner, amount });
  auctionConsignmentView = result.consignment;
  if (result.resolution.outcome === 'awarded') {
    recordAuctionMasterUtterance(await revealAuctionSpeech({
      speaker: auctionMasterSpeaker(),
      endpoint: '/api/auction/consignment/hammer/stream',
      body: { prior_utterances: auctionMasterUtterances.slice() }
    }));
    // An awarded consignment always credits the player: payout.money is the contract-guaranteed authoritative
    // post-credit balance (auction.md HTTP surface). A missing / non-integer payout.money is a broken upstream
    // contract, not a display default — fail fast rather than silently leaving stale money on screen.
    if (!result.payout || !Number.isInteger(result.payout.money)) {
      throw new Error('auction consignment awarded resolve is missing an authoritative payout.money');
    }
    auctionMoney = result.payout.money; // the removed asset itself shows on the next refresh
    renderAuctionConsignmentBoardFromState();
  } else {
    await appendAuctionNarration(AUCTION_CONSIGNMENT_PASSED_IN_NARRATION);
  }
  setAuctionConsignorBadge(false);
  auctionPhase = 'house';
  await appendAuctionNarration(nextAuctionMurmur());
  await runAuctionLot(auctionSlotView.current_lot_index);
}

// Runs the consignment lot start-to-finish: master 出品披露口上 (its prior_utterances is empty — the first speech of
// the visit) → seated-bidder reactions (prior_reactions chain) → NPC-only bid loop → resolve → on to the house lots.
async function runAuctionConsignmentLot({ onOpeningStreamStart = null } = {}) {
  showAuctionLive();
  renderAuctionConsignmentBoardFromState();
  recordAuctionMasterUtterance(await revealAuctionSpeech({
    speaker: auctionMasterSpeaker(),
    endpoint: '/api/auction/consignment/opening/stream',
    body: { prior_utterances: auctionMasterUtterances.slice() },
    onStreamStart: onOpeningStreamStart
  }));
  const priorReactions = [];
  for (const bidder of auctionSlotView.bidders) {
    const result = await revealAuctionSpeech({
      speaker: { character_id: bidder.character_id, character_name: bidder.display_name },
      endpoint: '/api/auction/consignment/reaction/stream',
      body: { character_id: bidder.character_id, prior_reactions: priorReactions.slice() }
    });
    priorReactions.push({ display_name: result.display_name, utterance: result.utterance });
  }
  await runAuctionConsignmentBidLoop();
  await resolveAuctionConsignmentLot();
}

// ----- 出品 picker (asset selection before the house lots) -----

// Renders the consignable-asset options (unequipped equipment + sell_price>0 items + 籠入りの生き物). Each option
// carries its value-anchor band; picking one submits it. An empty list shows the explicit 「出品できる品がありません」
// note (never a silent hide) — the player still has the 出品しない affordance. The 籠入り (caged) options fold into
// the same list with the same option markup (name/category_label/blurb/band come straight from the view — the
// frontend never re-derives 品種/band).
function renderAuctionConsignmentOptions(options) {
  const list = document.querySelector('#academy-auction-consignment-options');
  const empty = document.querySelector('#academy-auction-consignment-empty');
  // The options contract (auction.md HTTP surface) always carries all three arrays. A missing array is a broken
  // upstream shape, not an empty-list default — fail fast rather than silently rendering nothing.
  if (!Array.isArray(options.equipment) || !Array.isArray(options.items) || !Array.isArray(options.caged)) {
    throw new Error('auction consignment options must carry equipment, items, and caged arrays');
  }
  const entries = [...options.equipment, ...options.items, ...options.caged];
  if (empty) empty.hidden = entries.length > 0;
  if (!list) return;
  list.replaceChildren(...entries.map((entry) => {
    const li = document.createElement('li');
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'academy-auction-consignment-option';
    button.dataset.kind = entry.kind;
    // Source shape by kind (auction.md 出品側): 所持品 is keyed by item_id, an equipment instance and a caged
    // creature both by instance_id. Keying off item vs. instance folds star_cradle_creature in without a caged
    // branch; an unknown kind is caught by the backend's closed-vocab submit gate, not silently mis-shaped here.
    const source = entry.kind === 'item'
      ? { kind: 'item', item_id: entry.item_id }
      : { kind: entry.kind, instance_id: entry.instance_id };
    const name = document.createElement('span');
    name.className = 'academy-auction-consignment-option-name';
    name.textContent = entry.kind === 'item' ? `${entry.name}（×${entry.quantity}）` : entry.name;
    const meta = document.createElement('span');
    meta.className = 'academy-auction-consignment-option-meta';
    meta.textContent = `${entry.category_label}・${entry.band}帯・見込み ${entry.value_anchor}G`;
    button.append(name, meta);
    button.addEventListener('click', () => submitAuctionConsignmentChoice(source));
    li.append(button);
    return li;
  }));
}

function awaitAuctionConsignmentChoice() {
  return new Promise((resolve) => { auctionConsignmentChoiceResolve = resolve; });
}

function setAuctionConsignmentPickerBusy(busy) {
  const skip = document.querySelector('#academy-auction-consignment-skip');
  if (skip) skip.disabled = busy;
  for (const button of document.querySelectorAll('.academy-auction-consignment-option')) button.disabled = busy;
}

function submitAuctionConsignmentChoice(source) {
  if (!auctionConsignmentChoiceResolve) return;
  setAuctionConsignmentPickerBusy(true);
  const resolve = auctionConsignmentChoiceResolve;
  auctionConsignmentChoiceResolve = null;
  resolve({ kind: 'submit', source });
}

function skipAuctionConsignmentChoice() {
  if (!auctionConsignmentChoiceResolve) return;
  setAuctionConsignmentPickerBusy(true);
  const resolve = auctionConsignmentChoiceResolve;
  auctionConsignmentChoiceResolve = null;
  resolve({ kind: 'skip' });
}

// After the picker choice: submit lists the asset (POST submit) and runs the consignment lot; skip records the
// terminal skip (POST skip) and goes straight to the house lots. Runs as the session promise (kept in flight so
// the entry re-entrant guard holds through the whole visit).
async function runAuctionConsignmentPhaseAfterPicker() {
  const choice = await awaitAuctionConsignmentChoice();
  if (choice.kind === 'submit') {
    const view = await postJson('/api/auction/consignment/submit', { source: choice.source });
    auctionConsignmentView = view;
    auctionPhase = 'consignment';
    await runAuctionConsignmentLot();
  } else {
    await postJson('/api/auction/consignment/skip', {});
    auctionPhase = 'house';
    showAuctionLive();
    renderAuctionBoardFromState();
    await runAuctionLot(auctionSlotView.current_lot_index);
  }
}

// ----- entry / resume / closed view -----

// Clears every prior-visit view residue before an auction entry decides closed vs live. The auction is
// lot-granular and never persists in-lot progress (spec frontend/auction.md), so a reload / re-entry restarts the
// current lot's bidding from the top — no prior-visit chat, bid history, or board/bid-bar state is ever valid on
// screen. renderStream([]) is required over surface.setHistory([]): setHistory only swaps the model array, leaving
// the prior visit's message rows in the DOM; renderStream repaints the (now empty) stream. renderAuctionHistory
// early-returns while auctionBidState is null, so the bid-history list is cleared here directly.
function resetAuctionScreenView() {
  auctionSlotView = null;
  auctionBidState = null;
  auctionLotGoaded = false;
  auctionMasterUtterances = []; // fresh visit: the 反復回避ハンドオフ accumulates only this visit's 口上
  auctionConsignmentView = null;       // fresh visit: no listed asset carried over
  auctionConsignmentChoiceResolve = null; // drop any dangling picker promise from a prior visit
  auctionPhase = null;
  auctionStage.renderStream([]); // repaint the stream empty (setHistory alone leaves the prior rows in the DOM)
  const historyList = document.querySelector('#academy-auction-history');
  if (historyList) historyList.replaceChildren();
  const optionsList = document.querySelector('#academy-auction-consignment-options');
  if (optionsList) optionsList.replaceChildren(); // clear any prior visit's 出品 options from the picker
  setAuctionConsignmentPickerBusy(false); // clear the picker busy residue: the static skip button stays disabled across visits otherwise (option buttons are rebuilt, but #academy-auction-consignment-skip is the same node)
  setAuctionConsignorBadge(false);
  hideAuctionConsignmentPicker();
  setAuctionBidBarActive(false);
  setAuctionBidNote('');
}

// Called by showScreen('academy-auction'). Resets the view (no prior-visit residue), then GETs the weekly slot
// state: a closed week renders the closed view; a selection (未開催) / in-progress week enters-or-resumes and runs
// the session under an entry loading cover that releases on the first opening 口上 stream (M-2026-07-06-001). The
// auctionFlowInFlight guard makes the trailing showScreen('academy-auction') from the loading interstitial a no-op
// re-entry (so the reset runs once per genuine entry, never mid-session).
async function enterOrResumeAuctionScreen() {
  if (auctionFlowInFlight) return;
  resetAuctionScreenView();
  const state = await getJson('/api/auction/state');
  if (state.phase === 'closed') { renderAuctionClosed(state); return; }
  await runAuctionSession();
}

async function runAuctionSession() {
  auctionFlowInFlight = true;
  showAuctionLive();
  auctionMoney = Number.isInteger(currentInventory?.money) ? currentInventory.money : null;
  try {
    let openingStartedResolve = null;
    let openingStartedResolved = false;
    const openingStarted = new Promise((resolve) => { openingStartedResolve = resolve; });
    const markOpeningStarted = () => {
      if (openingStartedResolved) return;
      openingStartedResolved = true;
      openingStartedResolve?.();
    };
    let sessionPromise = Promise.resolve();
    const readiness = (async () => {
      const view = await postJson('/api/auction/enter', {}); // build the week slot (selection) or resume it (in-progress)
      auctionSlotView = view;
      if (view.status === 'closed') { auctionPhase = 'closed'; markOpeningStarted(); renderAuctionClosed(view); return; }
      // The enter POST completing (past the closed branch) is the first observed boundary of a non-closed visit;
      // advance the constellation here. The closed branch returns above and is deliberately left unwired.
      notifyAcademyLoadingProgress();
      if (auctionConsignmentNeedsPicker(view)) {
        // 出品 window: fetch the consignable assets and reveal the picker. There is no opening stream to wait on
        // here, so the loading cover releases as soon as the picker is on screen (the visit continues on the
        // player's submit / skip choice as the session promise).
        auctionPhase = 'picker';
        const options = await getJson('/api/auction/consignment/options');
        // The consignment picker branch has no opening SSE to advance it; the options GET is its second observed
        // boundary, so advance the constellation before the picker overlay is revealed.
        notifyAcademyLoadingProgress();
        showAuctionConsignmentPicker();
        renderAuctionConsignmentOptions(options);
        markOpeningStarted();
        sessionPromise = runAuctionConsignmentPhaseAfterPicker();
      } else if (view.consignment && view.consignment.status === 'listed') {
        // Resume onto a still-listed consignment lot: re-run it from the top (per-lot restart), then the house lots.
        auctionPhase = 'consignment';
        auctionConsignmentView = view.consignment;
        sessionPromise = runAuctionConsignmentLot({ onOpeningStreamStart: markOpeningStarted });
      } else {
        // Consignment resolved / skipped (or house bidding already underway): go straight to the house lots.
        auctionPhase = 'house';
        sessionPromise = runAuctionLot(view.current_lot_index, { onOpeningStreamStart: markOpeningStarted });
      }
      await Promise.race([openingStarted, sessionPromise]);
    })();
    await showAcademyLoadingScreenUntilReady({
      readiness,
      nextScreen: 'academy-auction',
      refreshBeforeNextScreen: false,
      loadingCopy: { title: '競売場へ移動中', status: '開演の口上を待っています。' }
    });
    if (auctionSlotView?.status !== 'closed') {
      renderAuctionScreenChrome();
      if (auctionPhase === 'consignment') renderAuctionConsignmentBoardFromState();
      else if (auctionPhase === 'house') renderAuctionBoardFromState();
      // 'picker': the 出品 overlay is shown; no board render until submit / skip picks the lot.
    }
    await sessionPromise;
  } catch (error) {
    // Loading-residual defense: a failed auction entry / resume must not strand the player on the loading screen.
    // Auction is routing-only content, so un-strand to the routing hub — the same origin the dungeon direct entry
    // un-strands to — with the cause on the hub status, then re-raise so the caller's reportAuctionScreenError logs
    // it once. A settings-redirect error already left the loader (reportLoadingError → settings), so the guard skips.
    if (isAcademyLoadingScreenActive() && settingsRedirectErrorMessage(error) == null) {
      showScreen('routing-hub');
      routingHubStage.setStatus(errorDisplayMessage(error), { tone: 'error' });
    }
    throw error;
  } finally {
    auctionFlowInFlight = false;
    setAuctionBidBarActive(false);
  }
}

function renderAuctionClosed(state) {
  auctionSlotView = state;
  const live = document.querySelector('#academy-auction-live');
  const closed = document.querySelector('#academy-auction-closed');
  if (live) live.hidden = true;
  if (closed) closed.hidden = false;
  const list = document.querySelector('#academy-auction-closed-results');
  if (list) {
    const bidderName = (id) => state.bidders.find((bidder) => bidder.character_id === id)?.display_name ?? id;
    list.replaceChildren(...state.lots.map((lot, index) => {
      const award = state.awards[index] ?? null;
      const li = document.createElement('li');
      const result = !award
        ? 'pending'
        : award.outcome === 'passed_in'
          ? 'passed_in'
          : award.winner_character_id === AUCTION_PLAYER_WINNER_ID ? 'won_by_player' : 'won_by_other';
      li.dataset.result = result;
      const head = `「${lot.name}」（${lot.band}帯）`;
      li.textContent = result === 'won_by_player'
        ? `${head} … ${award.amount}Gで落札`
        : result === 'won_by_other'
          ? `${head} … ${bidderName(award.winner_character_id)}が${award.amount}Gで落札`
          : result === 'passed_in'
            ? `${head} … 流札`
            : `${head} … 未確定`;
      return li;
    }));
  }
  renderAuctionScreenChrome();
}

// 競売場を出る: routing-only content, so the return is always the routing hub (AUCTION_POST_CONTENT_SCREEN), taken
// through the shared loading-covered content return and guarded by routingContentReturnInFlight.
async function exitAuction() {
  if (routingContentReturnInFlight) { showProcessingToast(); return; }
  routingContentReturnInFlight = true;
  try {
    auctionStage.stopAmbient();
    await returnToRoutingHubFromContent(AUCTION_POST_CONTENT_SCREEN);
  } finally {
    routingContentReturnInFlight = false;
  }
}

document.querySelector('#academy-auction-bid').addEventListener('click', () => submitAuctionPlayerBid().catch(reportAuctionScreenError));
document.querySelector('#academy-auction-drop').addEventListener('click', () => submitAuctionPlayerPass().catch(reportAuctionScreenError));
document.querySelector('#academy-auction-exit').addEventListener('click', () => exitAuction().catch(reportAuctionScreenError));
document.querySelector('#academy-auction-consignment-skip').addEventListener('click', () => skipAuctionConsignmentChoice());
document.querySelector('#academy-auction-bid-input').addEventListener('keydown', (event) => {
  if (event.key === 'Enter') {
    event.preventDefault();
    submitAuctionPlayerBid().catch(reportAuctionScreenError);
  }
});

// ===== 談話室 (lounge) screen =====
// A conversation-day-family content screen: its markup reuses the daytime 黒夜 --cd-* token layer + the shared
// .conversation-day-* presentation (so the taste is the daytime screen's, not a forked token set), and it drives
// itself from the frontend across the lounge per-utterance HTTP surface (spec loungeApi). Unlike the 1:1 daytime
// screen it shows THREE seated NPCs talking in rounds: each assistant bubble carries its OWN speaker identity
// (character_id / character_name / emotion), preserved end-to-end so createMessageRows renders the right face +
// name per message. The group path NEVER re-labels every bubble to one active character (the 1:1
// messagesFromConversation trap) — loungeMessagesFromConversation keeps per-message identity and the clicked-row
// data-character-id resolves WHICH participant a bubble belongs to. A round is NPC1→NPC2→NPC3 (server-shuffled
// order) then the player; the server group record is the authoritative cursor and every request re-validates the
// client-carried cursor. Reaching it is the routing hub dispatch (lounge → academy-lounge); ending it is the
// player's explicit 退出 → aggregate finalization + content-return to the hub.

// Dedicated 「寮の談話室」 stage art for the lounge frame + backdrop. The authored scene TEXT (location_name
// 「寮の談話室」+ the week-seeded visible_situation) is server-authoritative and shown in the stage-detail popup.
const LOUNGE_STAGE_IMAGE_URL = '/canonical/lounge/stage.jpg';

// Lounge session state (frontend-carried; not persisted — the server group record is the truth source).
let loungeConversation = null;     // last authoritative conversation view (enter / utterance result / player-turn)
let loungeFlowInFlight = false;    // guards the re-entrant showScreen during the entry loading transition
let loungeActionInFlight = false;  // single-flight guard for a player round-closing turn submission
let loungePlayerResolve = null;    // resolves the pending player-turn promise when 送信 / 退出 is pressed

// Group-aware conversation → chat-message mapper: keeps each assistant message's OWN speaker identity + emotion
// (the fix for the 1:1 messagesFromConversation re-label). User messages stay right-side bubbles. The server group
// record validates that every assistant message carries both emotion fields, so a missing one is a malformed
// authoritative payload — reject it rather than mask it with a neutral face.
function loungeMessagesFromConversation(conversation) {
  return (conversation?.messages ?? []).filter((message) => message.role === 'user' || message.role === 'assistant').map((message) => {
    if (message.role === 'assistant') {
      if (typeof message.expression !== 'string' || typeof message.face_emotion_variant_id !== 'string') {
        throw new Error(`lounge assistant message is missing emotion fields: ${message.character_id ?? '(no character_id)'}`);
      }
      return {
        role: 'assistant',
        character_id: message.character_id,
        character_name: message.character_name,
        content: message.content ?? '',
        expression: message.expression,
        face_emotion_variant_id: message.face_emotion_variant_id
      };
    }
    return { role: 'user', content: message.content ?? '' };
  });
}

// One assistant bubble carrying its OWN speaker identity + the turn's confirmed emotion (createMessageRows resolves
// the face via sourceSheetImageUrl per message from these fields). Used for the streamed reveal segments; the final
// committed history comes from the server-authoritative conversation view. The emotion is REQUIRED — a reveal
// segment must never be built before the turn's emotion is confirmed, so there is no neutral fallback: a missing
// emotion is a protocol violation (assistant content arrived before assistant_emotion) and fails fast.
function loungeMessage(speaker, content, emotion) {
  if (!emotion || typeof emotion.expression !== 'string' || typeof emotion.face_emotion_variant_id !== 'string') {
    throw new Error('lounge reveal segment requires a confirmed emotion (assistant content before assistant_emotion)');
  }
  return {
    role: 'assistant',
    character_id: speaker.character_id,
    character_name: speaker.character_name,
    content,
    expression: emotion.expression,
    face_emotion_variant_id: emotion.face_emotion_variant_id
  };
}

const loungeStage = createConversationStage({
  screenSelector: '#academy-lounge-screen',
  streamSelector: '#academy-lounge-message-stream',
  statusSelector: '#academy-lounge-status',
  controlSelectors: ['#academy-lounge-input', '#academy-lounge-send', '#academy-lounge-end'],
  weekSelector: '#academy-lounge-week',
  moonSelector: '#academy-lounge-moon-phase',
  respondingClass: 'is-day-responding',
  playerSpokeClass: 'is-day-player-spoke',
  dispatchClimaxClass: 'is-day-dispatch-climax',
  playerSpokeMs: 600,
  dispatchClimaxMs: 900,
  weekTotal: CONVERSATION_DAY_TOTAL_WEEKS,
  moonPhaseCount: 8,
  weekLabel: (week, total) => `第${week}週 / ${total}`,
  moonAriaLabel: (phase, count) => `月相 ${phase + 1} / ${count}`,
  currentWeek: () => conversationStageWeek(currentRuntimeState?.elapsed_weeks),
  // No persona standee: the three participants speak as chat bubbles (each with its own face/name), and the stage
  // frame shows the authored 舞台画像 (set in renderLoungeScreenChrome), so renderScreen's standee/speaker blocks
  // are guarded no-ops (the daytime stage 流儀).
  personaVisual: () => null,
  // Multiple speakers, so there is no single assistant identity; the group mapper keeps each message's identity.
  // This inert value only feeds the shared surface's assistantIdentity seam (unused by the consumer-owned
  // per-utterance reader below).
  assistantIdentity: () => ({ character_id: null, character_name: '' }),
  refresh: () => refresh(),
  ambient: createConversationDayAmbient({ canvasSelector: '#academy-lounge-motes', moteColorRgb: '255, 236, 179', moteCount: 70 }),
  // No info drawer / category rail: these selectors resolve to no nodes, so openInfo/closeInfo are guarded no-ops
  // (the auction 流儀).
  infoPopupSelector: '#academy-lounge-info-popup',
  infoTitleSelector: '#academy-lounge-info-popup-title',
  infoBodySelector: '#academy-lounge-info-popup-body',
  infoIconSelector: '#academy-lounge-info-popup-icon',
  categoryButtonSelector: '.academy-lounge-category-button',
  categoryDataKey: 'loungeCategory',
  categoryTitles: {},
  categoryIconUrl: () => '',
  categoryRenderers: {}
}, {
  displayMessages,
  createMessageRows,
  messagesFromConversation: loungeMessagesFromConversation,
  conversationPopupCooldownMs,
  sleep,
  setActorImageSource
});

function reportLoungeScreenError(error) {
  if (handleRuntimeApiError(error, { allowSettingsRedirect: true })) return;
  loungeStage.setStatus(errorDisplayMessage(error), { tone: 'error' });
  console.error(error);
}

// Consumer-owned SSE reader for one NPC utterance. Frames events exactly like the shared / auction stream helper
// (event:/data: over \n\n blocks) but understands the lounge event列: status → assistant_emotion →
// assistant_delta* → assistant_complete → result ({ speaker, emotion, content, conversation }). The emotion always
// arrives before the first delta so the turn's face is fixed before any bubble reveals. onStreamStart fires once on
// the first token so the entry loading cover can release on the first utterance's first stream.
async function readLoungeUtteranceSse(body, { onDelta, onComplete, onEmotion, onStreamStart = null }) {
  const endpoint = '/api/lounge/utterance/stream';
  const response = await fetch(endpoint, {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify(body)
  });
  if (!response.ok) {
    const text = await response.text();
    throw createApiError({ url: endpoint, status: response.status, payload: parseJsonText(text), fallbackText: text });
  }
  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let buffer = '';
  let finalResult = null;
  let streamStarted = false;
  const notifyStreamStarted = () => {
    if (streamStarted) return;
    streamStarted = true;
    onStreamStart?.();
  };
  const noteLoadingDelta = createLoadingProgressDeltaThrottle();
  const handleBlock = (block) => {
    const event = block.split('\n').find((line) => line.startsWith('event: '))?.slice(7);
    const dataText = block.split('\n').find((line) => line.startsWith('data: '))?.slice(6);
    const data = dataText ? JSON.parse(dataText) : null;
    if (event === 'assistant_delta') { notifyStreamStarted(); noteLoadingDelta(); onDelta(data.delta ?? ''); }
    if (event === 'assistant_emotion') { onEmotion?.({ expression: data.expression, face_emotion_variant_id: data.face_emotion_variant_id }); }
    if (event === 'assistant_complete') { notifyStreamStarted(); notifyAcademyLoadingProgress(); onComplete(data.content ?? ''); }
    if (event === 'result') { finalResult = data; notifyAcademyLoadingProgress(); }
    if (event === 'error') throw createApiError({ url: endpoint, status: 503, payload: data, fallbackText: data?.error ?? '' });
  };
  while (true) {
    const { value, done } = await reader.read();
    buffer += decoder.decode(value ?? new Uint8Array(), { stream: !done });
    const blocks = buffer.split('\n\n');
    buffer = blocks.pop() ?? '';
    for (const block of blocks) if (block.trim()) handleBlock(block);
    if (done) break;
  }
  if (buffer.trim()) handleBlock(buffer);
  if (!finalResult) throw new Error('lounge utterance stream ended without a final result');
  return finalResult;
}

// Streams one NPC utterance, revealing completed 吹き出し単位 through the shared reveal queue as they arrive, then
// adopts the server-authoritative conversation view (each message keeps its own speaker identity + final emotion).
// On failure the reveal is cancelled and the pre-utterance history is restored (no half-revealed bubble left).
async function revealLoungeUtterance({ speaker, id, cursor, onStreamStart = null }) {
  const base = [...loungeStage.surface.getHistory()];
  const reveal = loungeStage.createTurnReveal(base);
  let fullText = '';
  let segCount = 0;
  // The turn's emotion is confirmed once, by the first assistant_emotion event (which the server now sends BEFORE
  // any assistant_delta), and stays immutable for the whole utterance. Every assistant segment — including a
  // 括弧分割 that yields two face rows — is built from this single emotion, so both faces match. Assistant content
  // that arrives before the emotion is confirmed is a protocol violation: fail fast, never revealing a stand-in face.
  let turnEmotion = null;
  const enqueueFrom = (text) => {
    if (!text.trim()) return;
    if (!turnEmotion) throw new Error('lounge utterance stream sent assistant content before assistant_emotion (protocol violation)');
    const segments = displayMessages([loungeMessage(speaker, text, turnEmotion)]).filter((segment) => (segment.content ?? '').trim());
    const fresh = segments.slice(segCount);
    segCount += fresh.length;
    reveal.enqueue(fresh);
  };
  let result = null;
  try {
    result = await readLoungeUtteranceSse(
      { id, round_number: cursor.round_number, next_speaker_index: cursor.next_speaker_index },
      {
        onStreamStart,
        onEmotion: (chosen) => {
          if (turnEmotion) throw new Error('lounge utterance stream sent assistant_emotion more than once (protocol violation)');
          turnEmotion = chosen;
        },
        onDelta: (delta) => { fullText += delta; enqueueFrom(completedAssistantPrefix(fullText)); },
        onComplete: (content) => { fullText = content || fullText; enqueueFrom(fullText); }
      }
    );
    await reveal.drain();
  } catch (error) {
    reveal.cancel();
    loungeStage.surface.setHistory(base);
    loungeStage.renderStream(base);
    throw error;
  }
  // Completion reconcile: adopt the server-authoritative history into BOTH the surface state AND the DOM. setHistory
  // alone leaves the just-revealed rows in the DOM (the same reason resetLoungeScreenView pairs setHistory with
  // renderStream), which would let a stale face linger until the next render. emotion-before-delta is the primary
  // contract; this re-render is the completion backstop against any deferred face变化.
  const authoritative = loungeMessagesFromConversation(result.conversation);
  loungeStage.surface.setHistory(authoritative);
  loungeStage.renderStream(authoritative);
  return result;
}

// The suspended player round-closing turn: opens the input at the round boundary and resolves when 送信
// (submitLoungePlayerTurn → { ended:false, conversation }) or 退出 (exitLounge → { ended:true }) is pressed.
function runLoungePlayerTurn() {
  return new Promise((resolve) => {
    loungePlayerResolve = resolve;
    loungeStage.setControlsDisabled(false);
    const input = document.querySelector('#academy-lounge-input');
    if (input) input.focus();
  });
}

// The round drive: stream each scheduled NPC (server cursor → next_speaker), then open the player's turn. The
// server advances the cursor per request (next_speaker becomes null once all of the round's NPCs have spoken →
// the player's turn; a player turn advances to the next round's first NPC). NPC responses keep the input closed
// (shared setControlsDisabled); the loop returns when the player ends the talk.
async function runLoungeConversation({ onFirstStreamStart = null } = {}) {
  let firstStreamPending = Boolean(onFirstStreamStart);
  while (true) {
    while (loungeConversation.next_speaker) {
      loungeStage.setControlsDisabled(true);
      loungeStage.setResponding(true);
      const onStreamStart = firstStreamPending ? () => { firstStreamPending = false; onFirstStreamStart(); } : null;
      const result = await revealLoungeUtterance({
        speaker: loungeConversation.next_speaker,
        id: loungeConversation.id,
        cursor: loungeConversation.cursor,
        onStreamStart
      });
      loungeConversation = result.conversation;
    }
    loungeStage.setResponding(false);
    const outcome = await runLoungePlayerTurn();
    if (outcome.ended) return;
    loungeConversation = outcome.conversation;
  }
}

// Clears every prior-visit residue before an entry. The lounge never persists in-flight progress (reload/re-entry
// restarts the same week's talk fresh), so no prior chat, cursor, or open popup is ever valid on screen.
function resetLoungeScreenView() {
  loungeConversation = null;
  loungePlayerResolve = null;
  loungeActionInFlight = false;
  loungeStage.surface.setHistory([]);
  loungeStage.renderStream([]); // repaint empty (setHistory alone leaves the prior rows in the DOM)
  loungeStage.setStatus('');
  loungeStage.setControlsDisabled(true); // input stays closed until the first round ends
  closeLoungeStagePopup();
  closeLoungeCharacterPopup();
}

// Paint the week/moon topbar, start the ambient, and set the 暫定 舞台画像 — run AFTER the entry loading cover
// releases and the screen is visible + laid out (the ambient fail-fasts on a zero-size canvas).
function renderLoungeScreenChrome() {
  loungeStage.renderWeekAndMoon();
  loungeStage.startAmbient();
  const stageImage = document.querySelector('#academy-lounge-stage-image');
  if (stageImage) stageImage.style.backgroundImage = `url('${LOUNGE_STAGE_IMAGE_URL}')`;
}

// Called by showScreen('academy-lounge'). Resets the view, then enters + drives the weekly group talk under an
// entry loading cover that releases on the first NPC utterance stream (M-2026-07-06-001). The loungeFlowInFlight
// guard makes the trailing showScreen('academy-lounge') from the loading interstitial a no-op re-entry.
async function enterLoungeScreen() {
  if (loungeFlowInFlight) return;
  resetLoungeScreenView();
  await runLoungeSession();
}

async function runLoungeSession() {
  loungeFlowInFlight = true;
  try {
    let openingStartedResolve = null;
    let openingStartedResolved = false;
    const openingStarted = new Promise((resolve) => { openingStartedResolve = resolve; });
    const markOpeningStarted = () => {
      if (openingStartedResolved) return;
      openingStartedResolved = true;
      openingStartedResolve?.();
    };
    let sessionPromise = Promise.resolve();
    const readiness = (async () => {
      const enter = await postJson('/api/lounge/enter', {}); // fresh week slot (same-week re-entry restarts fresh)
      currentRuntimeState = enter.state ?? currentRuntimeState;
      loungeConversation = enter.conversation;
      // Drive the rounds; the first NPC utterance's first stream token releases the loading cover.
      sessionPromise = runLoungeConversation({ onFirstStreamStart: markOpeningStarted });
      await Promise.race([openingStarted, sessionPromise]);
    })();
    await showAcademyLoadingScreenUntilReady({
      readiness,
      nextScreen: 'academy-lounge',
      refreshBeforeNextScreen: false,
      loadingCopy: { title: '談話室へ移動中', status: '話し声が聞こえてきます。' }
    });
    renderLoungeScreenChrome();
    await sessionPromise;
  } catch (error) {
    // Loading-residual defense: a failed lounge entry / drive must not strand the player on the loading screen.
    // The lounge is routing-only content, so un-strand to the routing hub with the cause on its status, then
    // re-raise so the caller's reportLoungeScreenError logs it once. A settings-redirect error already left the
    // loader (reportLoadingError → settings), so the guard skips.
    if (isAcademyLoadingScreenActive() && settingsRedirectErrorMessage(error) == null) {
      showScreen('routing-hub');
      routingHubStage.setStatus(errorDisplayMessage(error), { tone: 'error' });
    }
    throw error;
  } finally {
    loungeFlowInFlight = false;
  }
}

// 送信: the player's round-closing turn. Appends the utterance server-side (cursor re-validated) and adopts the
// authoritative view (the player bubble + the next round's cursor), then resolves the suspended player turn so the
// round loop continues into the next round.
async function submitLoungePlayerTurn() {
  if (!loungePlayerResolve) return; // not the player's turn (NPCs are still speaking)
  if (loungeActionInFlight) { showProcessingToast(); return; }
  const input = document.querySelector('#academy-lounge-input');
  const content = (input?.value ?? '').trim();
  if (!content) return;
  loungeActionInFlight = true;
  loungeStage.setControlsDisabled(true);
  const historySnapshot = [...loungeStage.surface.getHistory()];
  const inputSnapshot = input ? input.value : '';
  try {
    if (input) input.value = '';
    loungeStage.flashPlayerSpoke();
    const result = await postJson('/api/lounge/player-turn', {
      id: loungeConversation.id,
      round_number: loungeConversation.cursor.round_number,
      next_speaker_index: loungeConversation.cursor.next_speaker_index,
      content
    });
    loungeStage.surface.setHistory(loungeMessagesFromConversation(result.conversation));
    loungeStage.renderStream(loungeStage.surface.getHistory());
    const resolve = loungePlayerResolve;
    loungePlayerResolve = null;
    resolve({ ended: false, conversation: result.conversation });
  } catch (error) {
    // The player turn is still pending (loungePlayerResolve stays set): restore the display + input and re-open
    // the controls so the round can be retried.
    loungeStage.surface.setHistory(historySnapshot);
    loungeStage.renderStream(historySnapshot);
    if (input) input.value = inputSnapshot;
    loungeStage.setControlsDisabled(false);
    reportLoungeScreenError(error);
  } finally {
    loungeActionInFlight = false;
  }
}

// 退出: the player's explicit end (offered only at a round boundary, when the input is open). Runs the aggregate
// finalization + content result server-side, then returns to the routing hub through the shared loading-covered
// content return (guarded by routingContentReturnInFlight).
async function exitLounge() {
  if (!loungePlayerResolve) { showProcessingToast(); return; } // only endable at a round boundary (player turn)
  if (loungeActionInFlight) { showProcessingToast(); return; }
  if (routingContentReturnInFlight) { showProcessingToast(); return; }
  routingContentReturnInFlight = true;
  loungeStage.setControlsDisabled(true);
  try {
    const result = await postJson('/api/lounge/end', { id: loungeConversation.id });
    currentRuntimeState = result.state ?? currentRuntimeState;
    loungeStage.stopAmbient();
    // Release the suspended round loop cleanly; the content return below owns the navigation.
    const resolve = loungePlayerResolve;
    loungePlayerResolve = null;
    if (resolve) resolve({ ended: true });
    await returnToRoutingHubFromContent(result.post_content_screen);
  } catch (error) {
    // A failed end leaves the player on the lounge: re-open the input so the round can be resumed / retried.
    if (loungePlayerResolve) loungeStage.setControlsDisabled(false);
    reportLoungeScreenError(error);
  } finally {
    routingContentReturnInFlight = false;
  }
}

// The clicked speaker's detail popup: the group path keeps each bubble's own data-character-id, so the clicked
// participant (not one active character) resolves to a roster character → standee + parameters. Fail-fast on an
// unresolvable id / missing display_name / missing popup nodes (broken data / wiring — no id fallback).
function openLoungeCharacterPopup(characterId) {
  const character = selectableCharacters.find((item) => item.character_id === characterId);
  if (!character) {
    throw new Error(`lounge participant not found in character roster: ${characterId}`);
  }
  if (typeof character.display_name !== 'string' || character.display_name.trim() === '') {
    throw new Error(`lounge participant ${character.character_id} has no display_name (broken roster data — no id fallback)`);
  }
  const popup = document.querySelector('#academy-lounge-character-popup');
  const title = document.querySelector('#academy-lounge-character-popup-title');
  const standee = document.querySelector('#academy-lounge-character-popup-standee');
  if (!popup || !title || !standee) {
    throw new Error('lounge character popup nodes are missing (broken markup wiring)');
  }
  title.textContent = character.display_name;
  standee.alt = `${character.display_name}の一枚絵`;
  setActorImageSource(standee, characterSceneStandeeUrl(character));
  renderCharacterParametersInto(character, '#academy-lounge-character-popup-parameters');
  popup.hidden = false;
}

function closeLoungeCharacterPopup() {
  const popup = document.querySelector('#academy-lounge-character-popup');
  if (popup) popup.hidden = true;
}

// The 舞台 detail popup: the authored scene (location_name「寮の談話室」 + the week-seeded visible_situation) carried
// on the active conversation view, plus the 暫定 舞台画像. Fail-fast on missing nodes / no active conversation.
function openLoungeStagePopup() {
  if (!loungeConversation) {
    throw new Error('lounge stage popup requires an active conversation (none held)');
  }
  const popup = document.querySelector('#academy-lounge-stage-popup');
  const title = document.querySelector('#academy-lounge-stage-popup-title');
  const text = document.querySelector('#academy-lounge-stage-popup-text');
  const image = document.querySelector('#academy-lounge-stage-popup-image');
  if (!popup || !title || !text || !image) {
    throw new Error('lounge stage popup nodes are missing (broken markup wiring)');
  }
  title.textContent = loungeConversation.location_name;
  text.textContent = loungeConversation.visible_situation;
  image.style.backgroundImage = `url('${LOUNGE_STAGE_IMAGE_URL}')`;
  popup.hidden = false;
}

function closeLoungeStagePopup() {
  const popup = document.querySelector('#academy-lounge-stage-popup');
  if (popup) popup.hidden = true;
}

document.querySelector('#academy-lounge-send').addEventListener('click', () => submitLoungePlayerTurn().catch(reportLoungeScreenError));
document.querySelector('#academy-lounge-end').addEventListener('click', () => exitLounge().catch(reportLoungeScreenError));
const loungeInputElement = document.querySelector('#academy-lounge-input');
loungeInputElement.addEventListener('compositionstart', () => { playerInputIsComposing = true; });
loungeInputElement.addEventListener('compositionend', () => { playerInputIsComposing = false; });
loungeInputElement.addEventListener('keydown', (event) => {
  if (shouldSubmitPlayerInput(event)) {
    event.preventDefault();
    if (loungeActionInFlight) {
      showProcessingToast();
      return;
    }
    submitLoungePlayerTurn().catch(reportLoungeScreenError);
  }
});
// Speaker click → the CLICKED participant's popup, resolved off the clicked row's data-character-id (delegated on
// the stream so it survives re-render). Player (user) rows carry no data-character-id, so they are never clickable.
document.querySelector('#academy-lounge-message-stream').addEventListener('click', (event) => {
  const row = event.target.closest('.chat-message');
  if (!row || !row.dataset.characterId) return;
  try { openLoungeCharacterPopup(row.dataset.characterId); } catch (error) { reportError(error); }
});
document.querySelector('#academy-lounge-stage-image').addEventListener('click', () => {
  try { openLoungeStagePopup(); } catch (error) { reportError(error); }
});
for (const closer of document.querySelectorAll('#academy-lounge-stage-popup [data-lounge-popup-close]')) {
  closer.addEventListener('click', () => closeLoungeStagePopup());
}
for (const closer of document.querySelectorAll('#academy-lounge-character-popup [data-lounge-popup-close]')) {
  closer.addEventListener('click', () => closeLoungeCharacterPopup());
}

// Boot loads persisted state then applies the initial-screen override. Dev calibration (?calibrate=<screen>)
// chains AFTER (so the target screen has its runtime state), and runs whether or not the refresh above
// succeeded because the reportError catch resolves the chain. Its fail-fasts (invalid registry / unknown
// screen / missing target selector / undefined offset custom property) are intentionally NOT caught: a broken
// calibration registration must propagate and abort calibration setup, never be swallowed into a degraded
// dev mode that keeps running.
// Apply the persisted audio settings to the BGM controller once at boot (its own chain so it never gates the
// initial-screen override, and its failure is handled inside initAudioSettings by dropping to silence).
initAudioSettings();

Promise.all([
  refreshSaveSlots(),
  refresh(),
  loadConversationPopupSettings()
]).then(() => applyInitialScreenOverride()).catch(reportError).then(() => applyFrameDecorationCalibrationOverride());
